import {
  Component,
  OnDestroy,
  inject,
  signal,
  computed,
  effect,
  HostListener,
} from '@angular/core';
import { takeUntilDestroyed, toObservable } from '@angular/core/rxjs-interop';
import { debounceTime, filter, map } from 'rxjs';
import { BreakpointObserver } from '@angular/cdk/layout';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { MessageModule } from 'primeng/message';
import { ButtonModule } from 'primeng/button';
import { TooltipModule } from 'primeng/tooltip';
import { SplitterModule } from 'primeng/splitter';
import { ProgressSpinnerModule } from 'primeng/progressspinner';

// Import Analytics Dashboard
import { AnalyticsDashboardComponent } from './dashboard/analytics-dashboard.component';
import { ReportEditingService } from './dashboard/services/report-editing.service';
import { ConflictModalComponent } from './dashboard/edit/conflict-modal.component';
import {
  ConversationHistoryService,
  EditedReportConflictError,
} from '../../../../core/services/conversation-history.service';
import { EditedReportWire } from './dashboard/models/edited-report.interface';

// Import Chat Components
import { ReportingHttpService } from './chat/services/reporting-http.service';
import { ChatSessionService } from './chat/services/chat-session.service';
import { QueryChatComponent } from './chat/components/query-chat/query-chat.component';
import { ConversationSidebarComponent } from './chat/components/conversation-sidebar/conversation-sidebar.component';
import {
  ChatSummaryHeaderComponent,
  SavedParams,
} from './chat/components/chat-summary-header/chat-summary-header.component';
import { ChatFooterPreviewComponent } from './chat/components/chat-footer-preview/chat-footer-preview.component';
import { ConversationReportsListComponent } from './chat/components/conversation-reports-list/conversation-reports-list.component';
import {
  ReportConfigDrawerComponent,
  ReportConfigDrawerResult,
} from './chat/components/report-config-drawer/report-config-drawer.component';
import { ReportConfigSelection } from './chat/components/inline-report-config/inline-report-config.component';
import { GlobalSearchComponent } from './global-search/global-search.component';
import { AnalyticsSnapshotMeta } from '../../../../core/interfaces/conversation.interface';
import { AnalyticalReportReportingService } from './services/analytical-report-reporting.service';
import { AnalyticalReportFacadeService } from './services/analytical-report-facade.service';
import { AnalyticalReviewService } from './services/analytical-review.service';
import { AnalyticalReportLoadingService } from './services/analytical-report-loading.service';
import { AnalyticalReportAssetsStore } from './store/assets.store';
import { AnalyticalReportDateStore } from './store/date.store';
import { AnalyticalReportQueryStore } from './store/query.store';
import { AnalyticalReportUiStore } from './store/ui.store';
import { AnalyticalReportSessionStore } from './store/session.store';
import { ChatSessionStore } from './store/chat-session.store';
import { isDefined } from '../../../../shared/utils';

@Component({
  selector: 'app-analytical-report',
  providers: [
    AnalyticalReportAssetsStore,
    AnalyticalReportDateStore,
    AnalyticalReportQueryStore,
    AnalyticalReportUiStore,
    AnalyticalReportSessionStore,
    ChatSessionStore,
    ReportingHttpService,
    ChatSessionService,
    ReportEditingService,
    AnalyticalReportLoadingService,
    AnalyticalReviewService,
    AnalyticalReportReportingService,
    AnalyticalReportFacadeService,
  ],
  imports: [
    CommonModule,
    FormsModule,
    MessageModule,
    ButtonModule,
    TooltipModule,
    SplitterModule,
    ProgressSpinnerModule,
    AnalyticsDashboardComponent,
    QueryChatComponent,
    ChatSummaryHeaderComponent,
    ChatFooterPreviewComponent,
    ConversationSidebarComponent,
    ConversationReportsListComponent,
    ReportConfigDrawerComponent,
    GlobalSearchComponent,
    ConflictModalComponent,
  ],
  templateUrl: './analytical-report.component.html',
  styleUrl: './analytical-report.component.scss',
})
export class AnalyticalReportComponent implements OnDestroy {
  readonly facade = inject(AnalyticalReportFacadeService);
  private readonly editingService = inject(ReportEditingService);
  private readonly conversationHistory = inject(ConversationHistoryService);
  private readonly breakpointObserver = inject(BreakpointObserver);

  readonly commandPaletteVisible = signal(false);

  /** Stacks the chat/viewer split vertically on narrow screens. */
  readonly isNarrow = signal(false);

  /**
   * On narrow screens the sidebar isn't an in-flow split panel: it sits as a thin
   * strip and expands as an overlay drawer over the workspace. This tracks whether
   * that drawer is open (independent of the persisted wide-screen collapsed state).
   */
  readonly sidebarOverlayOpen = signal(false);

  /** Effective collapsed state for the sidebar: overlay-driven on narrow, persisted on wide. */
  readonly sidebarIsCollapsed = computed(() =>
    this.isNarrow()
      ? !this.sidebarOverlayOpen()
      : this.facade.sidebarCollapsed(),
  );

  /** Variant class for the outer splitter: narrow overlay / thin strip / wide collapsed. */
  readonly outerSplitClass = computed(() => {
    if (this.isNarrow()) {
      return this.sidebarOverlayOpen()
        ? ' sidebar-overlay'
        : ' sidebar-collapsed';
    }
    return this.facade.sidebarCollapsed() ? ' sidebar-collapsed' : '';
  });

  /** Server's current document while a save conflict is being resolved (null = no conflict). */
  readonly conflictDoc = signal<EditedReportWire | null>(null);

  constructor() {
    this.breakpointObserver
      .observe('(max-width: 768px)')
      .pipe(
        map((state) => state.matches),
        takeUntilDestroyed(),
      )
      .subscribe((matches) => this.isNarrow.set(matches));

    // Returning to a wide layout closes any open overlay so the splitter resumes.
    effect(() => {
      if (!this.isNarrow()) this.sidebarOverlayOpen.set(false);
    });

    // Debounced persistence: one PATCH per ~800ms quiet period of edits.
    toObservable(this.editingService.dirty)
      .pipe(
        filter((dirty) => dirty),
        debounceTime(800),
        takeUntilDestroyed(),
      )
      .subscribe(() => void this.persistEdits());
  }

  private async persistEdits(): Promise<void> {
    // The trailing debounce can fire after an AI mutation already synced via the
    // send-message response (markSaved cleared dirty) — don't re-save then.
    if (!this.editingService.dirty()) return;
    const conversationId = this.facade.selectedConversationId();
    if (conversationId === null || conversationId === '') return;
    const wire = this.editingService.toWire(conversationId);
    if (!wire) return;
    try {
      const updatedAt = await this.conversationHistory.saveEditedReport(
        conversationId,
        wire,
      );
      this.editingService.markSaved(updatedAt);
    } catch (err) {
      if (err instanceof EditedReportConflictError) {
        this.conflictDoc.set(err.currentDoc);
      }
      // Other errors leave `dirty` set so the next edit retries the save.
    }
  }

  /** Conflict modal — discard local edits, adopt the server's version. */
  onConflictReload(): void {
    const current = this.conflictDoc();
    this.conflictDoc.set(null);
    if (current) this.editingService.applyServerDoc(current);
  }

  /** Conflict modal — keep local edits, overwrite the server using its updated_at. */
  async onConflictOverwrite(): Promise<void> {
    const current = this.conflictDoc();
    this.conflictDoc.set(null);
    const conversationId = this.facade.selectedConversationId();
    if (conversationId === null || conversationId === '') return;
    const wire = this.editingService.toWire(conversationId);
    if (!wire) return;
    // Rebase onto the server's current updated_at so the overwrite passes.
    wire.updated_at = current?.updated_at ?? wire.updated_at;
    try {
      const updatedAt = await this.conversationHistory.saveEditedReport(
        conversationId,
        wire,
      );
      this.editingService.markSaved(updatedAt);
    } catch (err) {
      if (err instanceof EditedReportConflictError) {
        this.conflictDoc.set(err.currentDoc);
      }
    }
  }

  @HostListener('window:keydown.control.k', ['$event'])
  @HostListener('window:keydown.meta.k', ['$event'])
  handleCommandPalette(event: Event): void {
    event.preventDefault();
    this.commandPaletteVisible.set(!this.commandPaletteVisible());
  }

  // ── Chat event handlers ───────────────────────────────────────────────────

  async onChatGenerateReport(query: string): Promise<void> {
    await this.facade.handleChatGenerateReport(query);
  }

  async onViewAnalyticsSnapshot(snap: AnalyticsSnapshotMeta): Promise<void> {
    await this.facade.handleViewAnalyticsSnapshot(snap);
  }

  onFooterMessageSent(message: string): void {
    this.facade.handleFooterMessageSent(message);
  }

  onHeaderParamsSaved(params: SavedParams): void {
    this.facade.handleHeaderParamsSaved(params);
  }

  // ── UI event handlers ─────────────────────────────────────────────────────

  onOpenConfigDrawer(): void {
    this.facade.openConfigDrawer('now');
  }

  onNewSchedule(): void {
    this.facade.openConfigDrawer('schedule');
  }

  async onDrawerGenerateNow(result: ReportConfigDrawerResult): Promise<void> {
    await this.facade.handleDrawerGenerateNow(result);
  }

  async onFooterGenerateAnalyticalReview(): Promise<void> {
    await this.facade.handleFooterGenerateAnalyticalReview();
  }

  onCollapseViewer(): void {
    this.facade.setViewerCollapsed(true);
  }

  onExpandViewer(): void {
    this.facade.setViewerCollapsed(false);
  }

  onReportConfigSelected(config: ReportConfigSelection): void {
    this.facade.handleReportConfigSelected(config);
  }

  onNewReport(): void {
    this.facade.resetAll();
  }

  // ── Sidebar event handlers ────────────────────────────────────────────────

  onShowReports(): void {
    this.facade.handleShowReports();
  }

  onShowAnalyticalReport(): void {
    void this.facade.showLatestAnalyticalReport();
  }

  onNewConversation(): void {
    this.closeSidebarOverlay();
    this.facade.startNewConversation();
  }

  async onSelectConversation(id: string): Promise<void> {
    // On narrow screens the sidebar is an overlay — close it once a chat is picked.
    this.closeSidebarOverlay();
    this.facade.setPendingScrollTarget(null);
    await this.facade.selectConversation(id);
  }

  /** Close the narrow-screen sidebar overlay (backdrop tap / after selection). */
  closeSidebarOverlay(): void {
    this.sidebarOverlayOpen.set(false);
  }

  async onConversationOpened(event: {
    conversationId: string;
    scrollTargetId?: string;
  }): Promise<void> {
    if (isDefined(event.scrollTargetId)) {
      this.facade.setPendingScrollTarget(event.scrollTargetId);
    }
    if (this.facade.selectedConversationId() === event.conversationId) return;
    await this.facade.selectConversation(event.conversationId);
  }

  onSidebarToggle(collapsed: boolean): void {
    // On narrow screens the chevron opens/closes the overlay drawer; the persisted
    // wide-screen collapsed preference is left untouched. (collapsed === desired
    // collapsed state, so the drawer is open when NOT collapsed.)
    if (this.isNarrow()) {
      this.sidebarOverlayOpen.set(!collapsed);
      return;
    }
    this.facade.setSidebarCollapsed(collapsed);
  }

  // ── Report download ───────────────────────────────────────────────────────

  onDownloadReport(): void {
    this.facade.handleDownloadReport();
  }

  onClearResponse(): void {
    this.facade.handleClearResponse();
  }

  onRecalculate(): void {
    this.facade.handleRecalculate();
  }

  ngOnDestroy(): void {
    this.facade.stop();
  }
}
