import {
  Component,
  computed,
  effect,
  inject,
  input,
  model,
  signal,
  viewChild,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { DrawerModule } from 'primeng/drawer';
import { ButtonModule } from 'primeng/button';

import {
  InlineReportConfigComponent,
  ReportConfigSelection,
} from '../inline-report-config/inline-report-config.component';
import {
  InlineScheduleConfigComponent,
  ScheduleConfigSelection,
} from '../inline-schedule-config/inline-schedule-config.component';
import {
  GeofenceFilterSelection,
  ReportGenerationRequest,
  ReportType,
} from '../../../../../../../core/interfaces/report-generation.interface';
import { isDefined } from '../../../../../../../shared/utils';
import { ReportGenerationService } from '../../../../../../../core/services/report-generation.service';

export interface ReportConfigDrawerResult {
  reportConfig: ReportConfigSelection;
  vehicleIds: string[];
  vehicleNames: Record<string, string>;
  startDate: Date;
  endDate: Date;
  conversationId: string;
  companyId: string;
}

@Component({
  selector: 'app-report-config-drawer',
  imports: [
    CommonModule,
    DrawerModule,
    ButtonModule,
    InlineReportConfigComponent,
    InlineScheduleConfigComponent,
  ],
  templateUrl: './report-config-drawer.component.html',
})
export class ReportConfigDrawerComponent {
  // Inputs
  visible = model<boolean>(false);
  initialReportType = input<ReportType | null>(null);
  initialDeliveryMode = input<'now' | 'schedule'>('now');
  preselectedVehicles = input<{ id: string; name: string }[]>([]);
  preselectedDateRange = input<{ start: Date; end: Date } | null>(null);
  conversationId = input<string>('');
  companyId = input<string>('');

  // Internal state
  deliveryMode = signal<'now' | 'schedule'>('now');

  constructor() {
    effect(
      () => {
        this.deliveryMode.set(this.initialDeliveryMode());
      },
      { allowSignalWrites: true },
    );
  }

  readonly reportGenerationService = inject(ReportGenerationService);

  isReportGenerating = signal<boolean>(false);
  isScheduleCreating = signal<boolean>(false);

  // ViewChild reference to read child signals directly
  readonly reportConfigRef =
    viewChild<InlineReportConfigComponent>('reportConfigRef');

  // Derived from child signals — no event bus needed
  readonly canConfirm = computed(() => {
    return (
      (this.reportConfigRef()?.canConfirm() ?? false) &&
      !this.isReportGenerating()
    );
  });

  readonly currentReportConfig = computed((): ReportConfigSelection | null => {
    const ref = this.reportConfigRef();
    if (!ref) return null;
    const reportType = ref.selectedReportType();
    if (!reportType) return null;
    const columns = Array.from(ref.selectedColumns());
    const allCols = ref.availableColumns();
    const columnCategories = [
      ...new Set(
        allCols.filter((c) => columns.includes(c.key)).map((c) => c.category),
      ),
    ];
    return {
      reportType,
      outputFormat: ref.outputFormat(),
      includeAiAnalysis: false,
      columns,
      columnCategories,
      geofenceFilter:
        reportType === 'geofence' ? ref.geofenceFilter() : undefined,
      eventCategories:
        reportType === 'events'
          ? ref.eventTypeFilter().event_categories
          : undefined,
      alertCategories:
        reportType === 'alerts'
          ? ref.alertTypeFilter().alert_categories
          : undefined,
      speedingFilter:
        reportType === 'speeding' ? ref.speedingFilter() : undefined,
      idlingFilter: reportType === 'idling' ? ref.idlingFilter() : undefined,
      utilisationFilter:
        reportType === 'daily_utilisation'
          ? ref.utilisationFilter()
          : undefined,
      stoppingFilter:
        reportType === 'stopping' ? ref.stoppingFilter() : undefined,
    };
  });

  readonly partialReportRequest = computed(
    (): ReportGenerationRequest | null => {
      const config = this.currentReportConfig();
      const dateRange = this.preselectedDateRange();
      const vehicles = this.preselectedVehicles();
      if (!config || !dateRange || vehicles.length === 0) return null;

      const vehicleNames: Record<string, string> = {};
      for (const v of vehicles) vehicleNames[v.id] = v.name;

      return {
        conversation_id: this.conversationId(),
        company_id: this.companyId(),
        report_type: config.reportType,
        vehicle_ids: vehicles.map((v) => v.id),
        vehicle_names: vehicleNames,
        start_date: dateRange.start.toISOString(),
        end_date: dateRange.end.toISOString(),
        columns: config.columns,
        column_categories: config.columnCategories,
        output_format: config.outputFormat,
        include_ai_analysis: config.includeAiAnalysis,
        ...this.geofenceFilterPayload(config.reportType),
        ...this.eventCategoriesPayload(config.reportType),
        ...this.alertCategoriesPayload(config.reportType),
        ...this.speedingFilterPayload(config.reportType),
        ...this.idlingFilterPayload(config.reportType),
        ...this.utilisationFilterPayload(config.reportType),
        ...this.stoppingFilterPayload(config.reportType),
      };
    },
  );

  /** Returns the three filter fields only when the report is `geofence`. */
  private geofenceFilterPayload(
    reportType: ReportType,
  ): Partial<GeofenceFilterSelection> {
    if (reportType !== 'geofence') return {};
    const f =
      this.currentReportConfig()?.geofenceFilter ??
      this.reportConfigRef()?.geofenceFilter();
    if (!f) return {};
    return {
      geofence_ids: f.geofence_ids,
      geofence_type_ids: f.geofence_type_ids,
      geofence_group_ids: f.geofence_group_ids,
    };
  }

  /** Returns the event-category filter only when the report is `events`. */
  private eventCategoriesPayload(
    reportType: ReportType,
  ): Pick<ReportGenerationRequest, 'event_categories'> {
    if (reportType !== 'events') return {};
    const categories =
      this.currentReportConfig()?.eventCategories ??
      this.reportConfigRef()?.eventTypeFilter().event_categories;
    return categories != null ? { event_categories: categories } : {};
  }

  /** Returns the alert-category filter only when the report is `alerts`. */
  private alertCategoriesPayload(
    reportType: ReportType,
  ): Pick<ReportGenerationRequest, 'alert_categories'> {
    if (reportType !== 'alerts') return {};
    const categories =
      this.currentReportConfig()?.alertCategories ??
      this.reportConfigRef()?.alertTypeFilter().alert_categories;
    return categories != null ? { alert_categories: categories } : {};
  }

  /** Returns the numeric thresholds only when the report is `speeding`. Null
   *  thresholds are omitted so the backend treats them as "show all". */
  private speedingFilterPayload(
    reportType: ReportType,
  ): Pick<ReportGenerationRequest, 'min_distance_km' | 'min_duration_minutes'> {
    if (reportType !== 'speeding') return {};
    const f =
      this.currentReportConfig()?.speedingFilter ??
      this.reportConfigRef()?.speedingFilter();
    if (f == null) return {};
    const out: Pick<
      ReportGenerationRequest,
      'min_distance_km' | 'min_duration_minutes'
    > = {};
    if (f.min_distance_km != null) out.min_distance_km = f.min_distance_km;
    if (f.min_duration_minutes != null) {
      out.min_duration_minutes = f.min_duration_minutes;
    }
    return out;
  }

  /** Returns the duration threshold only when the report is `idling`. A null
   *  threshold is omitted so the backend treats it as "show all". */
  private idlingFilterPayload(
    reportType: ReportType,
  ): Pick<ReportGenerationRequest, 'min_duration_minutes'> {
    if (reportType !== 'idling') return {};
    const f =
      this.currentReportConfig()?.idlingFilter ??
      this.reportConfigRef()?.idlingFilter();
    if (f?.min_duration_minutes == null) return {};
    return { min_duration_minutes: f.min_duration_minutes };
  }

  /** Returns the utilisation settings only when the report is
   *  `daily_utilisation`. The mode is always sent; a null target is omitted so
   *  the backend drops the Target / Distance Utilization % columns. */
  private utilisationFilterPayload(
    reportType: ReportType,
  ): Pick<
    ReportGenerationRequest,
    'utilization_mode' | 'daily_target_distance_km'
  > {
    if (reportType !== 'daily_utilisation') return {};
    const f =
      this.currentReportConfig()?.utilisationFilter ??
      this.reportConfigRef()?.utilisationFilter();
    if (f == null) return {};
    const out: Pick<
      ReportGenerationRequest,
      'utilization_mode' | 'daily_target_distance_km'
    > = { utilization_mode: f.utilization_mode };
    if (f.daily_target_distance_km != null) {
      out.daily_target_distance_km = f.daily_target_distance_km;
    }
    return out;
  }

  /** Returns the stop-type whitelist (and optional duration threshold) only
   *  when the report is `stopping`. An empty/absent list means "all types"; a
   *  null duration is omitted so the backend treats it as "show all". */
  private stoppingFilterPayload(
    reportType: ReportType,
  ): Pick<ReportGenerationRequest, 'stop_types' | 'min_duration_minutes'> {
    if (reportType !== 'stopping') return {};
    const f =
      this.currentReportConfig()?.stoppingFilter ??
      this.reportConfigRef()?.stoppingFilter();
    if (f == null) return {};
    const out: Pick<
      ReportGenerationRequest,
      'stop_types' | 'min_duration_minutes'
    > = {};
    if (f.stop_types?.length) out.stop_types = f.stop_types;
    if (f.min_duration_minutes != null) {
      out.min_duration_minutes = f.min_duration_minutes;
    }
    return out;
  }

  async onConfirmGenerate(): Promise<void> {
    if (!this.canConfirm()) return;
    const config = this.currentReportConfig();
    const dateRange = this.preselectedDateRange();
    const vehicles = this.preselectedVehicles();
    if (!config || !dateRange || vehicles.length === 0) return;

    const vehicleNames: Record<string, string> = {};
    for (const v of vehicles) vehicleNames[v.id] = v.name;

    const result = {
      reportConfig: config,
      vehicleIds: vehicles.map((v) => v.id),
      vehicleNames,
      startDate: dateRange.start,
      endDate: dateRange.end,
      conversationId: this.conversationId(),
      companyId: this.companyId(),
    };
    await this.generateReport(result);
  }

  async generateReport(result: ReportConfigDrawerResult): Promise<void> {
    this.isReportGenerating.set(true);

    const request: ReportGenerationRequest = {
      conversation_id: result.conversationId,
      company_id: result.companyId,
      report_type: result.reportConfig.reportType,
      vehicle_ids: result.vehicleIds,
      vehicle_names: result.vehicleNames,
      start_date: result.startDate.toISOString(),
      end_date: result.endDate.toISOString(),
      columns: result.reportConfig.columns,
      column_categories: result.reportConfig.columnCategories,
      output_format: result.reportConfig.outputFormat,
      include_ai_analysis: result.reportConfig.includeAiAnalysis,
      ...this.geofenceFilterPayload(result.reportConfig.reportType),
      ...this.eventCategoriesPayload(result.reportConfig.reportType),
      ...this.alertCategoriesPayload(result.reportConfig.reportType),
      ...this.speedingFilterPayload(result.reportConfig.reportType),
      ...this.idlingFilterPayload(result.reportConfig.reportType),
      ...this.utilisationFilterPayload(result.reportConfig.reportType),
      ...this.stoppingFilterPayload(result.reportConfig.reportType),
    };

    const response = await this.reportGenerationService.generateReport(request);
    if (isDefined(response)) {
      this.isReportGenerating.set(false);
    }
  }

  async onScheduleCreated(selection: ScheduleConfigSelection): Promise<void> {
    const config = this.currentReportConfig();
    const dateRange = this.preselectedDateRange();
    const vehicles = this.preselectedVehicles();
    if (!config || !dateRange || vehicles.length === 0) return;

    const vehicleNames: Record<string, string> = {};
    for (const v of vehicles) vehicleNames[v.id] = v.name;

    const request: ReportGenerationRequest = {
      conversation_id: this.conversationId(),
      company_id: this.companyId(),
      report_type: config.reportType,
      vehicle_ids: vehicles.map((v) => v.id),
      vehicle_names: vehicleNames,
      start_date: dateRange.start.toISOString(),
      end_date: dateRange.end.toISOString(),
      columns: config.columns,
      column_categories: config.columnCategories,
      output_format: config.outputFormat,
      include_ai_analysis: config.includeAiAnalysis,
      ...this.geofenceFilterPayload(config.reportType),
      ...this.eventCategoriesPayload(config.reportType),
      ...this.alertCategoriesPayload(config.reportType),
      ...this.speedingFilterPayload(config.reportType),
      ...this.idlingFilterPayload(config.reportType),
      ...this.utilisationFilterPayload(config.reportType),
      ...this.stoppingFilterPayload(config.reportType),
    };

    this.isScheduleCreating.set(true);
    const recipients =
      await this.reportGenerationService.resolveRecipientEmails(
        this.companyId(),
        selection.recipients,
      );
    await this.reportGenerationService.createSchedule(
      this.conversationId(),
      request,
      selection.schedule,
      recipients,
    );
    this.isScheduleCreating.set(false);
    this.visible.set(false);
  }
}
