import {
  Component,
  input,
  output,
  computed,
  signal,
  inject,
  ViewChild,
} from '@angular/core';
import { getConfidenceDisplay } from '../../utils/confidence.utils';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ButtonModule } from 'primeng/button';
import { ProgressBarModule } from 'primeng/progressbar';
import { TextareaModule } from 'primeng/textarea';
import { PopoverModule, Popover } from 'primeng/popover';
import { TooltipModule } from 'primeng/tooltip';
import { ChatInputComponent } from '../chat-input/chat-input.component';
import { ReportFileMeta } from '../../models/chat.interface';
import { isDefined } from '../../../../../../../shared/utils';
import { AnalyticalReportQueryStore } from '../../../store/query.store';
import { AnalyticalReportUiStore } from '../../../store/ui.store';
import { ChatSessionService } from '../../services/chat-session.service';

@Component({
  selector: 'app-chat-footer-preview',
  imports: [
    CommonModule,
    FormsModule,
    ButtonModule,
    ProgressBarModule,
    TextareaModule,
    PopoverModule,
    TooltipModule,
    ChatInputComponent,
  ],
  templateUrl: './chat-footer-preview.component.html',
  styleUrl: './chat-footer-preview.component.scss',
})
export class ChatFooterPreviewComponent {
  @ViewChild('reportsPopover') reportsPopover!: Popover;

  private readonly queryStore = inject(AnalyticalReportQueryStore);
  private readonly uiStore = inject(AnalyticalReportUiStore);
  readonly chatSessionService = inject(ChatSessionService);

  // Inputs
  generatingReportsCount = input<number>(0);

  // Read loading state from UI store
  readonly isLoading = computed(() => this.uiStore.isTestingApi());

  // Read state directly from stores/services
  readonly query = computed(() => this.queryStore.currentQuery());
  readonly confidence = computed(() => this.queryStore.currentConfidence());
  readonly isSessionActive = computed(() =>
    this.chatSessionService.isSessionActive(),
  );
  readonly isTyping = computed(() => this.chatSessionService.isTyping());
  readonly conversationPhase = computed(() =>
    this.chatSessionService.conversationPhase(),
  );

  // Derived from chat session messages (ownership moved here from root)
  readonly generatedReports = computed((): ReportFileMeta[] => {
    const msgs = this.chatSessionService.messages();
    const fromGroups = msgs
      .filter((m) => m.metadata?.interactiveType === 'report_file_group')
      .flatMap((m) => m.metadata?.reportFiles ?? []);
    const fromIndividual = msgs
      .filter(
        (m) =>
          m.metadata?.interactiveType === 'report_file' &&
          isDefined(m.metadata.reportFile),
      )
      .map((m) => m.metadata?.reportFile as ReportFileMeta);
    return [...fromGroups, ...fromIndividual];
  });

  readonly isGeneratingReports = computed(
    () => this.generatingReportsCount() > 0,
  );

  // Computed
  readonly isInputDisabled = computed(() => {
    const phase = this.conversationPhase();
    return phase === 'greeting' || phase === 'date_and_vehicle_selection';
  });

  readonly inputPlaceholder = computed(() =>
    this.isInputDisabled()
      ? 'Select a date range and vehicle to start chatting...'
      : 'Type your message or select a suggestion...',
  );

  // Outputs
  openConfigDrawer = output<void>();
  generateAnalyticalReview = output<void>();
  messageSent = output<string>();

  // Local state for editing
  isEditing = signal<boolean>(false);
  editedQuery = signal<string>('');

  // Computed
  readonly hasQuery = computed(() => this.query().length > 0);

  // Generate button is enabled as long as there's a query with sufficient confidence
  // Loading/collecting states don't block the button - user can still click to generate
  readonly canGenerateAnalyticalReview = computed(
    () => this.hasQuery() && this.confidence() >= 50,
  );

  readonly canDownloadReports = computed(() => !this.isInputDisabled());

  readonly confidenceWidthStyle = computed(() => ({
    width: `${this.confidence()}%`,
  }));

  readonly confidenceDisplay = computed(() =>
    getConfidenceDisplay(this.confidence()),
  );

  readonly confidenceLevel = computed(() => this.confidenceDisplay().level);
  readonly confidenceLabel = computed(() => this.confidenceDisplay().label);

  // Show full query when editing, otherwise show preview
  readonly queryPreview = computed(() => {
    const q = this.query();
    if (q.length <= 150) return q;
    return q.substring(0, 147) + '...';
  });

  readonly hasGeneratedReports = computed(
    () => this.generatedReports().length > 0,
  );

  readonly buttonIcon = computed(() =>
    this.hasGeneratedReports() ? 'pi pi-download' : 'pi pi-plus-circle',
  );

  readonly buttonLabel = computed(() => {
    const count = this.generatedReports().length;
    if (count === 0) return 'Generate Reports';
    return `Download Generated Reports (${count})`;
  });

  toggleReportsPanel(event: Event): void {
    this.reportsPopover.toggle(event);
  }

  downloadAll(): void {
    this.generatedReports().forEach((rf) => {
      if (isDefined(rf.downloadUrl)) {
        window.open(rf.downloadUrl, '_blank', 'noopener,noreferrer');
      }
    });
  }

  reportTooltip(rf: ReportFileMeta): string {
    const lines = [
      `File: ${rf.filename}`,
      `Type: ${rf.reportType ?? 'Report'}`,
      `Format: ${rf.outputFormat?.toUpperCase() ?? rf.contentType}`,
      `Size: ${this.formatFileSize(rf.sizeBytes)}`,
    ];
    if (isDefined(rf.generatedAt)) {
      lines.push(`Generated: ${new Date(rf.generatedAt).toLocaleString()}`);
    }
    return lines.join('\n');
  }

  formatFileSize(bytes: number): string {
    if (bytes < 1024) return `${bytes} B`;
    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
    return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
  }

  onGenerateClick(): void {
    this.openConfigDrawer.emit();
  }

  onAnalyticalReviewClick(): void {
    if (this.canGenerateAnalyticalReview()) {
      this.generateAnalyticalReview.emit();
    }
  }

  // Start editing the query
  onQueryClick(): void {
    if (!this.hasQuery()) return;
    this.editedQuery.set(this.query());
    this.isEditing.set(true);
  }

  // Save edited query
  saveEdit(): void {
    const newQuery = this.editedQuery().trim();
    if (newQuery.length > 0) {
      this.queryStore.setCurrentQuery(newQuery);
    }
    this.isEditing.set(false);
  }

  // Cancel editing
  cancelEdit(): void {
    this.isEditing.set(false);
    this.editedQuery.set('');
  }

  // Handle Enter key to save (Shift+Enter for newline)
  onKeyDown(event: KeyboardEvent): void {
    if (event.key === 'Enter' && !event.shiftKey) {
      event.preventDefault();
      this.saveEdit();
    } else if (event.key === 'Escape') {
      this.cancelEdit();
    }
  }
}
