import { Component, effect, inject, input, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { TooltipModule } from 'primeng/tooltip';
import { TranslatePipe } from '@ngx-translate/core';

import { ConversationHistoryService } from '../../../../../../../core/services/conversation-history.service';
import {
  ConversationSummary,
  ReportFile,
} from '../../../../../../../core/interfaces/conversation.interface';

@Component({
  selector: 'app-conversation-reports-list',
  imports: [CommonModule, TooltipModule, TranslatePipe],
  templateUrl: './conversation-reports-list.component.html',
  styleUrl: './conversation-reports-list.component.scss',
})
export class ConversationReportsListComponent {
  private readonly conversationHistoryService = inject(
    ConversationHistoryService,
  );

  conversation = input<ConversationSummary | null>(null);

  reportFiles = signal<ReportFile[]>([]);
  isLoading = signal(false);

  constructor() {
    effect(() => {
      const conv = this.conversation();
      if (!conv) {
        this.reportFiles.set([]);
        return;
      }
      void this.loadReports(conv.id);
    });
  }

  private async loadReports(conversationId: string): Promise<void> {
    this.isLoading.set(true);
    try {
      const detail =
        await this.conversationHistoryService.loadConversation(conversationId);
      this.reportFiles.set(detail.report_files ?? []);
    } catch {
      this.reportFiles.set([]);
    } finally {
      this.isLoading.set(false);
    }
  }
}
