import { Component, Input, input, output, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { CdkDragHandle } from '@angular/cdk/drag-drop';

import { Block } from '../../models/analytics-dashboard.interface';
import { BlockProvenance } from '../../models/edited-report.interface';

import { BlockEditPopoverComponent } from '../block-edit-popover/block-edit-popover.component';
import { SummaryBlockComponent } from '../summary-block/summary-block.component';
import { KpiBlockComponent } from '../kpi-block/kpi-block.component';
import { ChartBlockComponent } from '../chart-block/chart-block.component';
import { AlertBlockComponent } from '../alert-block/alert-block.component';
import { TableBlockComponent } from '../table-block/table-block.component';
import { RecommendationBlockComponent } from '../recommendation-block/recommendation-block.component';
import { TranslatePipe } from '@ngx-translate/core';

/**
 * Thin editing wrapper around an existing block presentational component. Adds a
 * hover toolbar (Remove / Restore / "Ask AI to change"), a CDK drag handle, and a
 * provenance badge — all gated on `editMode`. The six block components it renders
 * are NOT modified; this frame only composes around them.
 *
 * The drag handle uses `cdkDragHandle`, which registers with the `cdkDrag` placed
 * on this frame's host wrapper in the dashboard via DI (CDK_DRAG_PARENT) — so the
 * handle works even though it lives in this child component's template.
 */
@Component({
  selector: 'app-block-edit-frame',
  imports: [
    CommonModule,
    CdkDragHandle,
    BlockEditPopoverComponent,
    SummaryBlockComponent,
    KpiBlockComponent,
    ChartBlockComponent,
    AlertBlockComponent,
    TableBlockComponent,
    RecommendationBlockComponent,
    TranslatePipe,
  ],
  templateUrl: './block-edit-frame.component.html',
  styleUrl: './block-edit-frame.component.scss',
})
export class BlockEditFrameComponent {
  /**
   * Plain `@Input` (not a signal input) so the template type-checker narrows the
   * `Block` discriminated union through `@if (block.block_type === '…')`, exactly
   * as the original dashboard did.
   */
  @Input({ required: true }) block!: Block;

  readonly editMode = input(false);
  readonly hidden = input(false);
  readonly provenance = input<BlockProvenance>('original');

  readonly remove = output<void>();
  readonly restore = output<void>();

  /** Whether the inline "Ask AI to change" popover is open for this block. */
  readonly popoverOpen = signal(false);

  togglePopover(): void {
    this.popoverOpen.update((open) => !open);
  }

  /** Provenance badge only surfaces for blocks that were newly added. */
  get showProvenanceBadge(): boolean {
    const p = this.provenance();
    return p === 'user_added' || p === 'ai_added';
  }

  get provenanceLabel(): string {
    return this.provenance() === 'ai_added' ? 'Added by AI' : 'Added by you';
  }
}
