import {
  Component,
  ElementRef,
  afterNextRender,
  inject,
  input,
  output,
  signal,
  viewChild,
} from '@angular/core';

import { TranslatePipe } from '@ngx-translate/core';

import { Block } from '../../models/analytics-dashboard.interface';
import { ChatSessionService } from '../../../chat/services/chat-session.service';

/**
 * Inline "Ask AI to change" popover anchored to a single block. Keeps the user on
 * the report: it posts the prompt through the SAME chat pipeline
 * (`ChatSessionService.sendMessage`) with the block's id as `targetBlockId`, so
 * the turn still lands in the transcript and the live dashboard updates from the
 * returned mutations. Owns its own input / sending / error state.
 */
@Component({
  selector: 'app-block-edit-popover',
  imports: [TranslatePipe],
  templateUrl: './block-edit-popover.component.html',
  styleUrl: './block-edit-popover.component.scss',
})
export class BlockEditPopoverComponent {
  private readonly chatSession = inject(ChatSessionService);

  readonly block = input.required<Block>();
  readonly closed = output<void>();

  readonly prompt = signal('');
  readonly isSending = signal(false);
  readonly error = signal<string | null>(null);

  private readonly promptInput =
    viewChild<ElementRef<HTMLTextAreaElement>>('promptInput');

  constructor() {
    afterNextRender(() => this.promptInput()?.nativeElement.focus());
  }

  /** Enter sends; Shift+Enter inserts a newline. */
  onEnter(event: Event): void {
    if ((event as KeyboardEvent).shiftKey) return;
    event.preventDefault();
    void this.submit();
  }

  async submit(): Promise<void> {
    const text = this.prompt().trim();
    if (text === '' || this.isSending()) return;
    this.isSending.set(true);
    this.error.set(null);
    try {
      await this.chatSession.sendMessage(text, {
        targetBlockId: this.block().block_id,
      });
      this.prompt.set('');
      this.closed.emit();
    } catch (err) {
      this.error.set(
        err instanceof Error ? err.message : 'Failed to apply the change.',
      );
    } finally {
      this.isSending.set(false);
    }
  }

  cancel(): void {
    this.closed.emit();
  }
}
