import {
  Component,
  Input,
  Output,
  EventEmitter,
  OnDestroy,
  ViewChild,
  ElementRef,
  AfterViewInit,
  inject,
  signal,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { CdkDropList, CdkDrag, CdkDragDrop } from '@angular/cdk/drag-drop';
import {
  AnalyticsResponse,
  Block,
} from './models/analytics-dashboard.interface';
import { DashboardLayoutService } from './services/dashboard-layout.service';
import { ReportEditingService } from './services/report-editing.service';
import { BlockEditFrameComponent } from './blocks/block-edit-frame/block-edit-frame.component';
import { AnalyticalReportDateStore } from '../store/date.store';
import { AnalyticalReportAssetsStore } from '../store/assets.store';
import { isNullOrUndefined } from '../../../../../shared/utils';

@Component({
  selector: 'app-analytics-dashboard',
  imports: [CommonModule, CdkDropList, CdkDrag, BlockEditFrameComponent],
  templateUrl: './analytics-dashboard.component.html',
  styleUrl: './analytics-dashboard.component.scss',
  animations: [
    // Will be added if Angular animations are available
  ],
})
export class AnalyticsDashboardComponent implements OnDestroy, AfterViewInit {
  private readonly layoutService = inject(DashboardLayoutService);
  private readonly dateStore = inject(AnalyticalReportDateStore);
  private readonly assetsStore = inject(AnalyticalReportAssetsStore);
  readonly editingService = inject(ReportEditingService);

  private _response?: AnalyticsResponse;
  /**
   * Seeds the editing store when a *new* report arrives (different request_id),
   * but leaves an in-progress edit session untouched on re-renders of the same
   * report. Clears the store when the response is removed.
   */
  @Input()
  set response(value: AnalyticsResponse | undefined) {
    this._response = value;
    if (value?.response) {
      const current = this.editingService.editedReport();
      if (!current || current.requestId !== value.response.request_id) {
        this.editingService.initFromResponse(value);
      }
    } else {
      this.editingService.clear();
    }
  }
  get response(): AnalyticsResponse | undefined {
    return this._response;
  }

  readonly editMode = signal(false);
  readonly showRegenerateConfirm = signal(false);

  isLoading = false;
  error?: string;
  loadingProgress = 0;
  @Input() userQuery?: string;
  /** Optional conversation title, surfaced only in the print-only header. */
  @Input() conversationTitle?: string | null;
  get dateRange(): string | undefined {
    return this.dateStore.formatDateRange();
  }
  get vehicleNames(): string[] {
    return this.assetsStore.selectedVehicleNamesList();
  }
  @Input() clientTimeZone?: string;
  @Input() clientLanguage?: string;
  /** Selected client's display name, shown in the report title. */
  @Input() clientName?: string | null;

  showAllVehicles = false;

  @Output() recalculate = new EventEmitter<void>();

  @ViewChild('dashboardContainer') dashboardContainer?: ElementRef;

  isRecalculating = false;

  ngAfterViewInit(): void {
    if (
      this.response?.response?.layout &&
      typeof this.response.response.layout === 'object' &&
      this.dashboardContainer
    ) {
      setTimeout(() => this.applyLayout(), 100);
    }
  }

  ngOnDestroy(): void {
    this.layoutService.destroy();
  }

  trackByBlock(index: number, block: Block): string {
    return block.block_id;
  }

  applyLayout(): void {
    const layout = this.response?.response?.layout;
    const blocks = this.response?.response?.blocks;
    if (
      layout &&
      typeof layout === 'object' &&
      blocks &&
      this.dashboardContainer
    ) {
      this.layoutService.applyLayout(this.dashboardContainer, layout, blocks, {
        enableAnimations: true,
        gapSizePx: 16,
        minBlockHeight: 200,
      });
    }
  }

  getBlockClasses(block: Block): string[] {
    const classes = [`block-${block.block_type}`, `priority-${block.priority}`];

    if (block.visual?.theme) {
      classes.push(`theme-${block.visual.theme}`);
    }

    if (
      block.visual?.elevation !== undefined &&
      block.visual.elevation !== null
    ) {
      classes.push(`elevation-${block.visual.elevation}`);
    }

    return classes;
  }

  formatTimestamp(timestamp: string): string {
    try {
      const locale =
        this.clientLanguage != null && this.clientLanguage === 'af'
          ? 'af-ZA'
          : 'en-ZA';
      const options: Intl.DateTimeFormatOptions = {
        year: 'numeric',
        month: 'short',
        day: 'numeric',
        hour: '2-digit',
        minute: '2-digit',
        timeZone: this.clientTimeZone ?? 'Africa/Johannesburg',
      };
      return new Date(timestamp).toLocaleString(locale, options);
    } catch {
      return timestamp;
    }
  }

  getAlertCount(): number {
    return (
      this.response?.response?.blocks?.filter((b) => b.block_type === 'alert')
        .length ?? 0
    );
  }

  getVehicleDisplayText(): string {
    if (
      isNullOrUndefined(this.vehicleNames) ||
      this.vehicleNames.length === 0
    ) {
      return 'No vehicles selected';
    }
    if (this.vehicleNames.length <= 2) {
      return this.vehicleNames.join(', ');
    }
    return `${this.vehicleNames.slice(0, 2).join(', ')} +${this.vehicleNames.length - 2} more`;
  }

  onRecalculate(): void {
    this.isRecalculating = true;
    this.recalculate.emit();
  }

  /** Called by parent when recalculation is complete */
  resetRecalculatingState(): void {
    this.isRecalculating = false;
  }

  onPrint(): void {
    globalThis.print();
  }

  // ── Editing ─────────────────────────────────────────────────────────────────

  toggleEditMode(): void {
    this.editMode.update((on) => !on);
  }

  onDrop(event: CdkDragDrop<unknown>): void {
    this.editingService.reorder(event.previousIndex, event.currentIndex);
  }

  onRemoveBlock(blockId: string): void {
    this.editingService.remove(blockId);
  }

  onRestoreBlock(blockId: string): void {
    this.editingService.restore(blockId);
  }

  onResetToOriginal(): void {
    this.editingService.resetToOriginal();
  }

  /**
   * Regenerate guard: if the report has unsaved edits, confirm before discarding;
   * otherwise regenerate straight away.
   */
  onRegenerateClick(): void {
    if (this.editingService.isEdited()) {
      this.showRegenerateConfirm.set(true);
    } else {
      this.onRecalculate();
    }
  }

  confirmRegenerate(): void {
    this.showRegenerateConfirm.set(false);
    this.onRecalculate();
  }

  cancelRegenerate(): void {
    this.showRegenerateConfirm.set(false);
  }

  onRetry(): void {
    // Emit retry event - parent component should handle
    this.error = undefined;
  }

  onDismissError(): void {
    this.error = undefined;
  }
}
