import { Injectable, computed, signal } from '@angular/core';
import { DropdownOption } from '../models/analytical-report.types';
import { SelectableGroup } from '../chat/models/chat.interface';
import { safeStringify } from '../../../../../shared/utils';

export interface HeaderVehicleOption {
  id: string;
  name: string;
  selected: boolean;
}

export interface ChatVehicleOption {
  id: string;
  name: string;
}

@Injectable()
export class AnalyticalReportAssetsStore {
  private readonly _assets = signal<DropdownOption[]>([]);
  private readonly _filteredAssets = signal<DropdownOption[]>([]);
  private readonly _selectedAssetIds = signal<string[]>([]);
  private readonly _availableCostCenters = signal<SelectableGroup[]>([]);
  private readonly _selectedGroups = signal<SelectableGroup[]>([]);
  private readonly _availableAssetGroups = signal<SelectableGroup[]>([]);
  private readonly _loadingAssets = signal<boolean>(false);
  private readonly _contextVehicleNames = signal<Record<string, string>>({});

  readonly assets = this._assets.asReadonly();
  readonly filteredAssets = this._filteredAssets.asReadonly();
  readonly selectedAssetIds = this._selectedAssetIds.asReadonly();
  readonly availableCostCenters = this._availableCostCenters.asReadonly();
  readonly selectedGroups = this._selectedGroups.asReadonly();
  readonly availableAssetGroups = this._availableAssetGroups.asReadonly();
  readonly loadingAssets = this._loadingAssets.asReadonly();
  readonly contextVehicleNames = this._contextVehicleNames.asReadonly();

  readonly selectedAssetNames = computed(() => {
    const assetIds = this._selectedAssetIds();
    const allAssets = this._assets();

    if (!Array.isArray(allAssets) || !Array.isArray(assetIds)) {
      return 'Loading...';
    }

    const selectedAssets = allAssets.filter(
      (asset) => asset?.value != null && assetIds.includes(asset.value),
    );

    if (selectedAssets.length === 0) {
      return 'No vehicles selected';
    }

    return selectedAssets
      .map((asset) =>
        safeStringify(asset.label || asset.value || 'Unknown Vehicle'),
      )
      .join(', ');
  });

  readonly isMultipleVehiclesSelected = computed(
    () => this._selectedAssetIds().length > 1,
  );
  readonly canAnalyzePerVehicle = computed(
    () => this._selectedAssetIds().length > 1,
  );

  readonly selectedVehicleNames = computed((): Record<string, string> => {
    const assetIds = this._selectedAssetIds();
    const allAssets = this._assets();
    if (!Array.isArray(allAssets) || !Array.isArray(assetIds)) return {};
    return Object.fromEntries(
      allAssets
        .filter(
          (asset) => asset?.value != null && assetIds.includes(asset.value),
        )
        .map((asset) => [
          asset.value,
          asset.label || asset.value || 'Unknown Vehicle',
        ]),
    );
  });

  readonly selectedVehicleNamesList = computed((): string[] =>
    Object.values(this.selectedVehicleNames()),
  );

  readonly chatSelectedVehicles = computed((): ChatVehicleOption[] => {
    const assetIds = this._selectedAssetIds();
    const allAssets = this._assets();
    return assetIds
      .map((id) => {
        const asset = allAssets.find((a) => a.value === id);
        return asset ? { id: asset.value, name: asset.label } : null;
      })
      .filter((v): v is ChatVehicleOption => v !== null);
  });

  readonly availableVehiclesForChat = computed((): ChatVehicleOption[] => {
    return this._assets().map((asset) => ({
      id: asset.value,
      name: asset.label,
    }));
  });

  readonly headerAvailableVehicles = computed((): HeaderVehicleOption[] => {
    const allAssets = this._assets();
    const selectedIds = this._selectedAssetIds();
    const contextNames = this._contextVehicleNames();
    const assetIdSet = new Set(allAssets.map((a) => a.value));

    const fromAssets = allAssets.map((asset) => ({
      id: asset.value,
      name: asset.label,
      selected: selectedIds.includes(asset.value),
    }));

    const fromContext = selectedIds
      .filter((id) => !assetIdSet.has(id))
      .map((id) => ({ id, name: contextNames[id] ?? id, selected: true }));

    return [...fromAssets, ...fromContext];
  });

  readonly headerSelectedVehicleIds = computed(() => this._selectedAssetIds());

  setAssets(assets: DropdownOption[]): void {
    this._assets.set(assets);
  }

  setFilteredAssets(assets: DropdownOption[]): void {
    this._filteredAssets.set(assets);
  }

  setSelectedAssetIds(ids: string[]): void {
    this._selectedAssetIds.set(ids ?? []);
  }

  setAvailableCostCenters(groups: SelectableGroup[]): void {
    this._availableCostCenters.set(groups);
  }

  setSelectedGroups(groups: SelectableGroup[]): void {
    this._selectedGroups.set(groups);
  }

  setAvailableAssetGroups(groups: SelectableGroup[]): void {
    this._availableAssetGroups.set(groups);
  }

  setLoadingAssets(loading: boolean): void {
    this._loadingAssets.set(loading);
  }

  setContextVehicleNames(names: Record<string, string>): void {
    this._contextVehicleNames.set(names);
  }

  reset(): void {
    this._selectedAssetIds.set([]);
    this._contextVehicleNames.set({});
    this._selectedGroups.set([]);
  }
}
