import { Component, effect, output, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';

import { TranslatePipe } from '@ngx-translate/core';

import { IdlingFilterSelection } from '../../../../../../../core/interfaces/report-generation.interface';

/**
 * Numeric filter for the Excessive Idling report. One optional threshold —
 * Duration (minutes) — applied as a strictly greater-than filter on an idling
 * incident. A blank input emits `null`, which the backend treats as
 * "show all".
 */
@Component({
  selector: 'app-inline-idling-filter',
  imports: [CommonModule, FormsModule, TranslatePipe],
  templateUrl: './inline-idling-filter.component.html',
})
export class InlineIdlingFilterComponent {
  filterChanged = output<IdlingFilterSelection>();

  readonly minDurationMinutes = signal<number | null>(null);

  constructor() {
    effect(
      () => {
        this.filterChanged.emit({
          min_duration_minutes: this.minDurationMinutes(),
        });
      },
      { allowSignalWrites: true },
    );
  }

  setDuration(value: string): void {
    this.minDurationMinutes.set(value === '' ? null : Number(value));
  }
}
