import { Component, effect, output, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';

import { TranslatePipe } from '@ngx-translate/core';

import { SpeedingFilterSelection } from '../../../../../../../core/interfaces/report-generation.interface';

/**
 * Numeric filters for the Over Speeding report. Two optional thresholds —
 * Distance (km) and Duration (minutes) — each applied as a strictly
 * greater-than filter on an overspeed incident. A blank input emits `null`,
 * which the backend treats as "show all".
 */
@Component({
  selector: 'app-inline-speeding-filter',
  imports: [CommonModule, FormsModule, TranslatePipe],
  templateUrl: './inline-speeding-filter.component.html',
})
export class InlineSpeedingFilterComponent {
  filterChanged = output<SpeedingFilterSelection>();

  readonly minDistanceKm = signal<number | null>(null);
  readonly minDurationMinutes = signal<number | null>(null);

  constructor() {
    effect(
      () => {
        this.filterChanged.emit({
          min_distance_km: this.minDistanceKm(),
          min_duration_minutes: this.minDurationMinutes(),
        });
      },
      { allowSignalWrites: true },
    );
  }

  setDistance(value: string): void {
    this.minDistanceKm.set(value === '' ? null : Number(value));
  }

  setDuration(value: string): void {
    this.minDurationMinutes.set(value === '' ? null : Number(value));
  }
}
