import { DestroyRef, Injectable, inject, signal } from '@angular/core';

@Injectable()
export class AnalyticalReportLoadingService {
  private readonly destroyRef = inject(DestroyRef);
  private loadingInterval: ReturnType<typeof setInterval> | null = null;
  private readonly _loadingMessage = signal<string>(
    'Preparing report generation...',
  );
  readonly loadingMessage = this._loadingMessage.asReadonly();

  constructor() {
    this.destroyRef.onDestroy(() => this.stop());
  }

  start(dataTypes: string[], vehicleCount: number): void {
    if (this.loadingInterval !== null) return;
    const vehicleText =
      vehicleCount === 1
        ? 'selected vehicle'
        : `${vehicleCount} selected vehicles`;

    const messages = [
      'Connecting to AI analysis engine...',
      `Gathering ${dataTypes.join(', ')} data for ${vehicleText}...`,
      'Processing telemetry information...',
      'Analyzing fleet patterns and behaviors...',
      'Identifying potential issues and insights...',
      'Generating intelligent recommendations...',
      'Finalizing comprehensive report...',
      'Almost ready, applying finishing touches...',
    ];

    let messageIndex = 0;
    this._loadingMessage.set(messages[messageIndex]);

    this.loadingInterval = setInterval(() => {
      messageIndex = (messageIndex + 1) % messages.length;
      this._loadingMessage.set(messages[messageIndex]);
    }, 3000);
  }

  stop(): void {
    if (this.loadingInterval !== null) {
      clearInterval(this.loadingInterval);
      this.loadingInterval = null;
    }
  }
}
