import {
  Component,
  computed,
  effect,
  inject,
  input,
  output,
  signal,
  viewChild,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ButtonModule } from 'primeng/button';
import { ChipModule } from 'primeng/chip';
import { SelectModule } from 'primeng/select';
import { PopoverModule, Popover } from 'primeng/popover';
import { combineLatest } from 'rxjs';

import { AccountsService } from '../../../../../../../api';
import { ScheduleRecipient } from '../../../../../../../core/interfaces/report-generation.interface';

interface RecipientOption {
  label: string;
  value: string;
  email?: string;
}

const MAX_RECIPIENTS = 1000;

@Component({
  selector: 'app-report-recipients-picker',
  imports: [
    CommonModule,
    FormsModule,
    ButtonModule,
    ChipModule,
    SelectModule,
    PopoverModule,
  ],
  templateUrl: './report-recipients-picker.component.html',
})
export class ReportRecipientsPickerComponent {
  private readonly accountsService = inject(AccountsService);

  // Inputs / Outputs
  ownerId = input<string>('');
  recipientsChange = output<ScheduleRecipient[]>();

  // Popover reference
  private readonly addPopover = viewChild<Popover>('addPopover');

  // Constant exposed to template
  readonly maxRecipients = MAX_RECIPIENTS;

  // State
  readonly recipients = signal<ScheduleRecipient[]>([]);
  readonly category = signal<'user' | 'role'>('user');
  readonly selectedId = signal<string | null>(null);

  private readonly userOptions = signal<RecipientOption[]>([]);
  private readonly roleOptions = signal<RecipientOption[]>([]);
  readonly optionsLoading = signal<boolean>(false);

  // Options for the currently selected category, excluding already-added items
  readonly currentOptions = computed<RecipientOption[]>(() => {
    const isUser = this.category() === 'user';
    const source = isUser ? this.userOptions() : this.roleOptions();
    const chosen = new Set(
      this.recipients()
        .filter((r) => r.type === this.category())
        .map((r) => r.id),
    );
    return source.filter((o) => !chosen.has(o.value));
  });

  readonly atLimit = computed(() => this.recipients().length >= MAX_RECIPIENTS);

  constructor() {
    // Reload the user/role lists whenever the owner changes.
    effect(() => {
      const owner = this.ownerId();
      if (owner) {
        this.loadOptions(owner);
      } else {
        this.userOptions.set([]);
        this.roleOptions.set([]);
      }
    });
  }

  private loadOptions(ownerId: string): void {
    this.optionsLoading.set(true);
    combineLatest([
      this.accountsService.listUsers(ownerId, 0, 100, 'name', 'state=active'),
      this.accountsService.listUserRoles(ownerId, 0, 100, 'name'),
    ]).subscribe({
      next: ([users, roles]) => {
        this.userOptions.set(
          (users.items ?? []).map((u) => ({
            label: u.name ?? u.emailAddress ?? '',
            value: u.id,
            email: u.emailAddress ?? undefined,
          })),
        );
        this.roleOptions.set(
          (roles.items ?? []).map((r) => ({
            label: r.name ?? '',
            value: r.id,
          })),
        );
        this.optionsLoading.set(false);
      },
      error: () => {
        this.userOptions.set([]);
        this.roleOptions.set([]);
        this.optionsLoading.set(false);
      },
    });
  }

  onCategoryChange(value: 'user' | 'role'): void {
    this.category.set(value);
    this.selectedId.set(null);
  }

  onAdd(): void {
    const id = this.selectedId();
    if (id == null || this.atLimit()) return;

    const type = this.category();
    const option = (
      type === 'user' ? this.userOptions() : this.roleOptions()
    ).find((o) => o.value === id);
    if (!option) return;

    const recipient: ScheduleRecipient = {
      id: option.value,
      name: option.label,
      type,
      email: option.email,
    };
    this.recipients.update((list) => [...list, recipient]);
    this.recipientsChange.emit(this.recipients());

    this.selectedId.set(null);
    this.addPopover()?.hide();
  }

  remove(recipient: ScheduleRecipient): void {
    this.recipients.update((list) =>
      list.filter((r) => !(r.id === recipient.id && r.type === recipient.type)),
    );
    this.recipientsChange.emit(this.recipients());
  }

  toggleAdd(event: Event): void {
    this.addPopover()?.toggle(event);
  }
}
