import { Injectable, computed, signal } from '@angular/core';
import {
  AnalyticsResponse,
  Block,
} from '../models/analytics-dashboard.interface';
import {
  BlockProvenance,
  EditedBlock,
  EditedBlockWire,
  EditedReport,
  EditedReportWire,
} from '../models/edited-report.interface';
import {
  ReportMutation,
  ReportPatchEdit,
} from '../models/report-mutation.interface';

// ============================================================================
// Trust boundary — pure type guards and helpers
//
// Everything below the class is a module-scope pure function. The reducer never
// trusts an incoming mutation: `applyMutation` accepts `unknown` and narrows it
// through `isReportMutation` before committing anything to the store.
// ============================================================================

/** The six block types the backend can emit through mutation tools. */
const MUTATABLE_BLOCK_TYPES: readonly string[] = [
  'summary',
  'kpi',
  'chart',
  'alert',
  'table',
  'recommendation',
];

/** The five mutation kinds the backend can emit. */
const MUTATION_KINDS: readonly string[] = [
  'add',
  'replace',
  'patch',
  'remove',
  'reorder',
];

/** True when `value` is a non-null, non-array object we can index by string key. */
function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === 'object' && value !== null && !Array.isArray(value);
}

/** True when `value` is an array whose every element is a string. */
function isStringArray(value: unknown): value is string[] {
  return Array.isArray(value) && value.every((v) => typeof v === 'string');
}

/**
 * Validate that `value` is a structurally-sound block envelope: a string
 * `block_id`, a `block_type` that is one of the six mutatable kinds, and a
 * `content` object. Deep per-content-field validation is intentionally NOT done
 * here — block components render defensively and content-shape drift is out of
 * scope for this trust boundary.
 */
function isBlock(value: unknown): value is Block {
  if (!isRecord(value)) return false;
  if (typeof value['block_id'] !== 'string') return false;
  if (
    typeof value['block_type'] !== 'string' ||
    !MUTATABLE_BLOCK_TYPES.includes(value['block_type'])
  ) {
    return false;
  }
  return isRecord(value['content']);
}

/** True when `value` is a non-empty array of `{ path: "/…", value }` edits. */
function isPatchEdits(value: unknown): value is ReportPatchEdit[] {
  return (
    Array.isArray(value) &&
    value.length > 0 &&
    value.every(
      (e) =>
        isRecord(e) &&
        typeof e['path'] === 'string' &&
        e['path'].startsWith('/') &&
        'value' in e,
    )
  );
}

/**
 * The trust boundary. Narrow one untrusted value (a single element of
 * `metadata.report_mutations`) to a `ReportMutation`, validating only the fields
 * its `kind` requires. Returns false for unknown kinds or missing/mistyped
 * required fields.
 */
function isReportMutation(value: unknown): value is ReportMutation {
  if (!isRecord(value)) return false;
  const kind = value['kind'];
  if (typeof kind !== 'string' || !MUTATION_KINDS.includes(kind)) return false;

  switch (kind) {
    case 'add':
      return (
        isBlock(value['block']) &&
        (value['at_index'] === undefined ||
          typeof value['at_index'] === 'number')
      );
    case 'replace':
      return typeof value['block_id'] === 'string' && isBlock(value['block']);
    case 'patch':
      return (
        typeof value['block_id'] === 'string' && isPatchEdits(value['edits'])
      );
    case 'remove':
      return typeof value['block_id'] === 'string';
    case 'reorder':
      return isStringArray(value['order']) && value['order'].length > 0;
    default:
      return false;
  }
}

/**
 * Apply one RFC 6901 JSON Pointer edit to a block, returning a NEW block with
 * the value at `path` set (the input is never mutated). Used by `applyMutation`
 * for the `patch` kind. Returns null on an invalid or non-resolvable pointer so
 * the reducer can reject the whole patch atomically.
 */
function setByPointer(
  block: Block,
  path: string,
  value: unknown,
): Block | null {
  if (!path.startsWith('/')) return null;
  const tokens = path
    .split('/')
    .slice(1)
    .map((t) => t.replace(/~1/g, '/').replace(/~0/g, '~'));
  if (tokens.length === 0) return null;

  const clone = structuredClone(block);
  let parent: unknown = clone;
  for (let i = 0; i < tokens.length - 1; i++) {
    if (isRecord(parent)) {
      parent = parent[tokens[i]];
    } else if (Array.isArray(parent)) {
      parent = parent[Number(tokens[i])];
    } else {
      return null;
    }
  }

  const last = tokens[tokens.length - 1];
  if (Array.isArray(parent)) {
    const index = Number(last);
    if (!Number.isInteger(index) || index < 0 || index >= parent.length) {
      return null;
    }
    parent[index] = value;
  } else if (isRecord(parent)) {
    parent[last] = value;
  } else {
    return null;
  }
  return clone;
}

/**
 * Deep-merge `partial` into `base`, returning a new object. Nested objects merge
 * recursively; arrays and primitives replace wholesale (so e.g. patching a
 * chart's `data` array swaps it rather than merging by index).
 */
function deepMergeContent(
  base: Record<string, unknown>,
  partial: Record<string, unknown>,
): Record<string, unknown> {
  const out: Record<string, unknown> = { ...base };
  for (const [key, value] of Object.entries(partial)) {
    const existing = out[key];
    out[key] =
      isRecord(existing) && isRecord(value)
        ? deepMergeContent(existing, value)
        : value;
  }
  return out;
}

// ============================================================================
// Result type
// ============================================================================

/** Outcome of `applyMutation`, used by the chat layer for the transparency log. */
export interface MutationResult {
  applied: boolean;
  mutation?: ReportMutation;
  error?: string;
}

// ============================================================================
// Service
// ============================================================================

/**
 * Signal store + pure reducer for the editable report. Holds the immutable
 * AnalyticsResponse baseline alongside the working `EditedReport` so
 * "Reset to original" can always rebuild. Component-scoped (provided on
 * AnalyticalReportComponent) so the dashboard and chat layer share one instance.
 */
@Injectable()
export class ReportEditingService {
  private readonly baseline = signal<AnalyticsResponse | null>(null);
  private readonly edited = signal<EditedReport | null>(null);

  /**
   * True when the in-memory report has unsaved local changes. Flips on every
   * mutating op (all of which funnel through `update`) and clears on `markSaved`.
   * The persistence layer debounces on this to PATCH the edited report.
   */
  private readonly _dirty = signal(false);
  readonly dirty = this._dirty.asReadonly();

  /**
   * The `updated_at` of the last server-persisted edited_report (from GET
   * hydration or a successful PATCH). Sent back as `expected_updated_at` for
   * optimistic concurrency; null when nothing has been persisted yet.
   */
  private readonly _serverUpdatedAt = signal<string | null>(null);
  readonly serverUpdatedAt = this._serverUpdatedAt.asReadonly();

  /**
   * Persisted edited_report stashed at conversation-open time, consumed by the
   * next `initFromResponse` whose baseline matches. Lets the conversation-load
   * flow (which has the saved doc) and the dashboard-render flow (which has the
   * baseline AnalyticsResponse) rendezvous without threading an extra input.
   */
  private readonly _pendingPersisted = signal<EditedReportWire | null>(null);

  /** Stash the conversation's persisted edited_report for the next init. */
  setPendingPersisted(wire: EditedReportWire | null): void {
    this._pendingPersisted.set(wire);
  }

  /** The current edited report (null until `initFromResponse`). */
  readonly editedReport = this.edited.asReadonly();

  /** All blocks in render order, including hidden ones (the template filters). */
  readonly orderedBlocks = computed<EditedBlock[]>(() => {
    const report = this.edited();
    if (!report) return [];
    return report.blockOrder
      .map((id) => report.blocks[id])
      .filter((b): b is EditedBlock => b !== undefined);
  });

  /** Visible blocks only, in order — used for read-only render and print. */
  readonly visibleBlocks = computed<EditedBlock[]>(() =>
    this.orderedBlocks().filter((b) => !b.hidden),
  );

  /** True once a report has been loaded. */
  readonly hasReport = computed(() => this.edited() !== null);

  /** True when the user/AI has changed order, hidden a block, or edited content. */
  readonly isEdited = computed(() => {
    const report = this.edited();
    const base = this.baseline();
    if (!report || !base) return false;

    const baseOrder = base.response.blocks.map((b) => b.block_id);
    if (report.blockOrder.length !== baseOrder.length) return true;
    if (report.blockOrder.some((id, i) => id !== baseOrder[i])) return true;
    return Object.values(report.blocks).some(
      (b) => b.hidden || b.provenance !== 'original',
    );
  });

  /**
   * Seed the store from a fresh AnalyticsResponse, recording it as baseline.
   *
   * When `persisted` is supplied (the conversation's saved edited_report from
   * GET) and its `report_id` matches this response, the working report is
   * hydrated from it instead of the baseline — so reopening a conversation
   * restores the user's edits. A mismatched/absent `persisted` falls back to the
   * baseline. Hydration is NOT a local edit, so `dirty` stays false; the
   * server's `updated_at` is tracked for the next PATCH.
   */
  initFromResponse(
    response: AnalyticsResponse,
    persisted?: EditedReportWire | null,
  ): void {
    this.baseline.set(response);
    const saved = persisted ?? this._pendingPersisted();
    // Match on report_id, but also accept an empty report_id: that means the doc
    // predates report_id stamping (or the FE didn't send it), and a conversation
    // has at most one edited_report, so it's safe to treat as this report's edit.
    if (
      saved != null &&
      saved.blocks != null &&
      (saved.report_id === '' ||
        saved.report_id === response.response.request_id)
    ) {
      this._pendingPersisted.set(null); // consumed by a matching report
      // Stamp the baseline's real request_id (not the wire's, which may be empty
      // for legacy docs) so the dashboard's "same report" guard holds and the
      // next save heals the persisted report_id.
      const hydrated = this.fromWire(saved);
      hydrated.requestId = response.response.request_id;
      this.edited.set(hydrated);
      this._serverUpdatedAt.set(saved.updated_at ?? null);
    } else {
      // No match — keep any stashed doc for a later matching report rather than
      // discarding it, and start from the baseline for this one.
      this.edited.set(this.buildFromResponse(response));
      this._serverUpdatedAt.set(null);
    }
    this._dirty.set(false);
  }

  /** Rebuild the working report from the stored baseline, discarding edits. */
  resetToOriginal(): void {
    const base = this.baseline();
    if (!base) return;
    this.edited.set(this.buildFromResponse(base));
    this._dirty.set(true); // reverting to baseline is itself a change to persist
  }

  /** Drop all state (e.g. when navigating away or starting a new report). */
  clear(): void {
    this.baseline.set(null);
    this.edited.set(null);
    this._dirty.set(false);
    this._serverUpdatedAt.set(null);
  }

  /**
   * Mark the current state as persisted: clears `dirty` and records the server's
   * new `updated_at` (for the next PATCH's optimistic-concurrency token).
   */
  markSaved(updatedAt: string): void {
    this._serverUpdatedAt.set(updatedAt);
    this._dirty.set(false);
  }

  /**
   * Replace the working report with a server document (the conflict modal's
   * "reload" action) — discards local edits and adopts the server's updated_at.
   */
  applyServerDoc(wire: EditedReportWire): void {
    this.edited.set(this.fromWire(wire));
    this._serverUpdatedAt.set(wire.updated_at ?? null);
    this._dirty.set(false);
  }

  /**
   * Serialise the current edited report to its persisted (snake_case) wire form
   * for PATCH. `removed_ids` is derived from hidden blocks; `expected_updated_at`
   * is left to the caller to attach from `serverUpdatedAt()`.
   */
  toWire(conversationId: string): EditedReportWire | null {
    const report = this.edited();
    if (!report) return null;
    const blocks: Record<string, EditedBlockWire> = {};
    for (const [id, eb] of Object.entries(report.blocks)) {
      blocks[id] = {
        block: eb.block,
        provenance: eb.provenance,
        hidden: eb.hidden,
      };
    }
    return {
      report_id: report.requestId,
      conversation_id: conversationId,
      blocks,
      block_order: [...report.blockOrder],
      removed_ids: report.blockOrder.filter((id) => report.blocks[id]?.hidden),
      schema_version: 1,
      updated_at: this._serverUpdatedAt() ?? '',
    };
  }

  /** Move a block from one render position to another (drag-and-drop). */
  reorder(previousIndex: number, currentIndex: number): void {
    this.update((report) => {
      const order = [...report.blockOrder];
      if (previousIndex < 0 || previousIndex >= order.length) return report;
      if (currentIndex < 0 || currentIndex >= order.length) return report;
      const [moved] = order.splice(previousIndex, 1);
      order.splice(currentIndex, 0, moved);
      return { ...report, blockOrder: order };
    });
  }

  /** Soft-remove a block (keeps its slot in `blockOrder`). */
  remove(blockId: string): void {
    this.setHidden(blockId, true);
  }

  /** Un-hide a previously soft-removed block. */
  restore(blockId: string): void {
    this.setHidden(blockId, false);
  }

  /** Insert a new block at `atIndex` (or the end). No-op on id collision. */
  addBlock(
    block: Block,
    atIndex?: number,
    provenance: BlockProvenance = 'user_added',
  ): void {
    this.update((report) => {
      if (block.block_id in report.blocks) return report;
      const blocks: Record<string, EditedBlock> = {
        ...report.blocks,
        [block.block_id]: { block, provenance, hidden: false },
      };
      const order = [...report.blockOrder];
      const at =
        atIndex === undefined
          ? order.length
          : Math.max(0, Math.min(atIndex, order.length));
      order.splice(at, 0, block.block_id);
      return { ...report, blocks, blockOrder: order };
    });
  }

  /** Replace a block wholesale, preserving its id and slot. No-op if unknown. */
  replaceBlock(
    blockId: string,
    block: Block,
    provenance: BlockProvenance = 'user_edit',
  ): void {
    this.update((report) => {
      const existing: EditedBlock | undefined = report.blocks[blockId];
      if (existing === undefined) return report;
      const normalized: Block = { ...block, block_id: blockId };
      return {
        ...report,
        blocks: {
          ...report.blocks,
          [blockId]: { ...existing, block: normalized, provenance },
        },
      };
    });
  }

  /** Deep-merge a partial content object into a block. No-op if unknown. */
  patchBlockContent(
    blockId: string,
    partialContent: Record<string, unknown>,
    provenance: BlockProvenance = 'user_edit',
  ): void {
    this.update((report) => {
      const existing: EditedBlock | undefined = report.blocks[blockId];
      if (existing === undefined) return report;
      const mergedContent = deepMergeContent(
        existing.block.content,
        partialContent,
      );
      const block = {
        ...existing.block,
        content: mergedContent,
      } as Block;
      return {
        ...report,
        blocks: {
          ...report.blocks,
          [blockId]: { ...existing, block, provenance },
        },
      };
    });
  }

  /**
   * Validate and apply one chat-driven mutation. This is the only entry point
   * that accepts untrusted input — it narrows through `isReportMutation` and
   * verifies block references before committing. Returns a result the chat layer
   * uses to append a transparency message (or surface a rejection).
   */
  applyMutation(raw: unknown): MutationResult {
    if (!isReportMutation(raw)) {
      return { applied: false, error: 'Malformed mutation payload' };
    }

    const report = this.edited();
    if (!report) {
      return { applied: false, mutation: raw, error: 'No report loaded' };
    }

    switch (raw.kind) {
      case 'add':
        if (raw.block.block_id in report.blocks) {
          return {
            applied: false,
            mutation: raw,
            error: `Block ${raw.block.block_id} already exists`,
          };
        }
        this.addBlock(raw.block, raw.at_index, 'ai_added');
        return { applied: true, mutation: raw };

      case 'replace':
        if (!(raw.block_id in report.blocks)) {
          return {
            applied: false,
            mutation: raw,
            error: `Unknown block ${raw.block_id}`,
          };
        }
        this.replaceBlock(raw.block_id, raw.block, 'ai_edit');
        return { applied: true, mutation: raw };

      case 'patch': {
        const existing: EditedBlock | undefined = report.blocks[raw.block_id];
        if (existing === undefined) {
          return {
            applied: false,
            mutation: raw,
            error: `Unknown block ${raw.block_id}`,
          };
        }
        let next: Block | null = existing.block;
        for (const edit of raw.edits) {
          next = setByPointer(next, edit.path, edit.value);
          if (next === null) {
            return {
              applied: false,
              mutation: raw,
              error: `Invalid patch path ${edit.path}`,
            };
          }
        }
        const patched = next;
        this.update((r) => {
          const e: EditedBlock | undefined = r.blocks[raw.block_id];
          if (e === undefined) return r;
          return {
            ...r,
            blocks: {
              ...r.blocks,
              [raw.block_id]: { ...e, block: patched, provenance: 'ai_edit' },
            },
          };
        });
        return { applied: true, mutation: raw };
      }

      case 'remove':
        if (!(raw.block_id in report.blocks)) {
          return {
            applied: false,
            mutation: raw,
            error: `Unknown block ${raw.block_id}`,
          };
        }
        this.remove(raw.block_id);
        return { applied: true, mutation: raw };

      case 'reorder':
        this.applyReorderByIds(raw.order);
        return { applied: true, mutation: raw };

      default:
        return { applied: false, error: 'Unsupported mutation kind' };
    }
  }

  // ── private ────────────────────────────────────────────────────────────────

  private buildFromResponse(response: AnalyticsResponse): EditedReport {
    const blocks: Record<string, EditedBlock> = {};
    const blockOrder: string[] = [];
    for (const block of response.response.blocks) {
      blocks[block.block_id] = {
        block: structuredClone(block),
        provenance: 'original',
        hidden: false,
      };
      blockOrder.push(block.block_id);
    }
    return {
      requestId: response.response.request_id,
      blocks,
      blockOrder,
    };
  }

  private setHidden(blockId: string, hidden: boolean): void {
    this.update((report) => {
      const existing: EditedBlock | undefined = report.blocks[blockId];
      if (existing === undefined || existing.hidden === hidden) return report;
      return {
        ...report,
        blocks: { ...report.blocks, [blockId]: { ...existing, hidden } },
      };
    });
  }

  /**
   * Reorder by an explicit id list (chat `reorder` kind). Unknown/duplicate ids
   * are dropped; any block_ids omitted from `order` are appended in their
   * existing relative order.
   */
  private applyReorderByIds(order: string[]): void {
    this.update((report) => {
      const known: string[] = [];
      const seen = new Set<string>();
      for (const id of order) {
        if (id in report.blocks && !seen.has(id)) {
          known.push(id);
          seen.add(id);
        }
      }
      const leftovers = report.blockOrder.filter((id) => !seen.has(id));
      return { ...report, blockOrder: [...known, ...leftovers] };
    });
  }

  private update(fn: (report: EditedReport) => EditedReport): void {
    const current = this.edited();
    if (!current) return;
    const next = fn(current);
    this.edited.set(next);
    if (next !== current) {
      this._dirty.set(true);
    }
  }

  /** Build the in-memory (camelCase) report from a persisted wire document. */
  private fromWire(wire: EditedReportWire): EditedReport {
    const blocks: Record<string, EditedBlock> = {};
    for (const [id, eb] of Object.entries(wire.blocks ?? {})) {
      blocks[id] = {
        block: eb.block,
        provenance: eb.provenance ?? 'original',
        hidden: Boolean(eb.hidden),
      };
    }
    return {
      requestId: wire.report_id,
      blocks,
      blockOrder: [...(wire.block_order ?? [])],
    };
  }
}
