import {
  Component,
  computed,
  inject,
  input,
  output,
  signal,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { ButtonModule } from 'primeng/button';

import { ReportGenerationService } from '../../../../../../../core/services/report-generation.service';
import {
  AlertTypeFilterSelection,
  CustomFieldColumn,
  EMPTY_GEOFENCE_FILTER,
  EMPTY_IDLING_FILTER,
  EMPTY_SPEEDING_FILTER,
  EMPTY_STOPPING_FILTER,
  EMPTY_UTILISATION_FILTER,
  EventTypeFilterSelection,
  GeofenceFilterSelection,
  IdlingFilterSelection,
  ReportType,
  SpeedingFilterSelection,
  StoppingFilterSelection,
  UtilisationFilterSelection,
} from '../../../../../../../core/interfaces/report-generation.interface';
import { InlineGeofenceFilterComponent } from '../inline-geofence-filter/inline-geofence-filter.component';
import { InlineEventTypeFilterComponent } from '../inline-event-type-filter/inline-event-type-filter.component';
import { InlineAlertTypeFilterComponent } from '../inline-alert-type-filter/inline-alert-type-filter.component';
import { InlineSpeedingFilterComponent } from '../inline-speeding-filter/inline-speeding-filter.component';
import { InlineIdlingFilterComponent } from '../inline-idling-filter/inline-idling-filter.component';
import { InlineUtilisationFilterComponent } from '../inline-utilisation-filter/inline-utilisation-filter.component';
import { InlineStoppingFilterComponent } from '../inline-stopping-filter/inline-stopping-filter.component';
import {
  AdditionalColumnsSelection,
  InlineAdditionalColumnsComponent,
} from '../inline-additional-columns/inline-additional-columns.component';

export interface ReportTypesConfirmation {
  types: ReportType[];
  /** Present only when `'geofence'` is among the selected types. */
  geofenceFilter?: GeofenceFilterSelection;
  /** Selected event-class keys. Present only when `'events'` is selected. */
  eventCategories?: string[];
  /** Selected alert-class keys. Present only when `'alerts'` is selected. */
  alertCategories?: string[];
  /** Numeric thresholds. Present only when `'speeding'` is selected. */
  speedingFilter?: SpeedingFilterSelection;
  /** Duration threshold. Present only when `'idling'` is selected. */
  idlingFilter?: IdlingFilterSelection;
  /** Mode & target. Present only when `'daily_utilisation'` is selected. */
  utilisationFilter?: UtilisationFilterSelection;
  /** Stop types & duration. Present only when `'stopping'` is selected. */
  stoppingFilter?: StoppingFilterSelection;
  /**
   * Extra catalog columns chosen in the "Add Additional Columns" picker.
   * Currently surfaced for `'trip_history_daily_summary'` only; other report
   * types will opt in later.
   */
  additionalColumns?: string[];
  /**
   * Asset custom-field columns chosen in the picker. Currently surfaced for
   * `'trip_history_daily_summary'` only; other report types will opt in later.
   */
  customColumns?: CustomFieldColumn[];
  /** IoType columns to show the first-trip value for (Trip Summary only). */
  initialColumns?: CustomFieldColumn[];
  /** IoType columns to show the last-trip value for (Trip Summary only). */
  finalColumns?: CustomFieldColumn[];
}

@Component({
  selector: 'app-inline-report-type-selector',
  imports: [
    CommonModule,
    ButtonModule,
    InlineGeofenceFilterComponent,
    InlineEventTypeFilterComponent,
    InlineAlertTypeFilterComponent,
    InlineSpeedingFilterComponent,
    InlineIdlingFilterComponent,
    InlineUtilisationFilterComponent,
    InlineStoppingFilterComponent,
    InlineAdditionalColumnsComponent,
  ],
  templateUrl: './inline-report-type-selector.component.html',
  styleUrl: './inline-report-type-selector.component.scss',
})
export class InlineReportTypeSelectorComponent {
  private readonly reportGenerationService = inject(ReportGenerationService);

  // Inputs
  /** Client/owner id used by the geofence filter to load zones & groups. */
  ownerId = input<string>('');

  // Output
  reportTypesConfirmed = output<ReportTypesConfirmation>();

  // All available report types from service
  readonly reportTypes = this.reportGenerationService.getReportTypes();

  // Local state
  selectedIds = signal<Set<ReportType>>(new Set());
  geofenceFilter = signal<GeofenceFilterSelection>({
    ...EMPTY_GEOFENCE_FILTER,
  });
  eventTypeFilter = signal<EventTypeFilterSelection>({ event_categories: [] });
  alertTypeFilter = signal<AlertTypeFilterSelection>({ alert_categories: [] });
  speedingFilter = signal<SpeedingFilterSelection>({
    ...EMPTY_SPEEDING_FILTER,
  });
  idlingFilter = signal<IdlingFilterSelection>({ ...EMPTY_IDLING_FILTER });
  utilisationFilter = signal<UtilisationFilterSelection>({
    ...EMPTY_UTILISATION_FILTER,
  });
  stoppingFilter = signal<StoppingFilterSelection>({
    ...EMPTY_STOPPING_FILTER,
  });
  additionalColumns = signal<AdditionalColumnsSelection>({
    additionalColumns: [],
    customFields: [],
    initialColumns: [],
    finalColumns: [],
  });

  // Computed
  readonly selectedCount = computed(() => this.selectedIds().size);
  readonly canConfirm = computed(() => this.selectedCount() > 0);
  readonly allSelected = computed(
    () =>
      this.reportTypes.length > 0 &&
      this.reportTypes.every((t) => this.selectedIds().has(t.report_type)),
  );
  readonly isGeofenceSelected = computed(() =>
    this.selectedIds().has('geofence'),
  );
  readonly isEventsSelected = computed(() => this.selectedIds().has('events'));
  readonly isAlertsSelected = computed(() => this.selectedIds().has('alerts'));
  readonly isSpeedingSelected = computed(() =>
    this.selectedIds().has('speeding'),
  );
  readonly isIdlingSelected = computed(() => this.selectedIds().has('idling'));
  readonly isDailyUtilisationSelected = computed(() =>
    this.selectedIds().has('daily_utilisation'),
  );
  readonly isStoppingSelected = computed(() =>
    this.selectedIds().has('stopping'),
  );
  readonly isDailySummarySelected = computed(() =>
    this.selectedIds().has('trip_history_daily_summary'),
  );

  isSelected(id: ReportType): boolean {
    return this.selectedIds().has(id);
  }

  toggleType(id: ReportType): void {
    const current = new Set(this.selectedIds());
    if (current.has(id)) {
      current.delete(id);
    } else {
      current.add(id);
    }
    this.selectedIds.set(current);
  }

  selectAll(): void {
    this.selectedIds.set(new Set(this.reportTypes.map((t) => t.report_type)));
  }

  clearAll(): void {
    this.selectedIds.set(new Set());
  }

  onConfirm(): void {
    const selected = Array.from(this.selectedIds());
    if (selected.length === 0) return;
    this.reportTypesConfirmed.emit({
      types: selected,
      geofenceFilter: selected.includes('geofence')
        ? this.geofenceFilter()
        : undefined,
      eventCategories: selected.includes('events')
        ? this.eventTypeFilter().event_categories
        : undefined,
      alertCategories: selected.includes('alerts')
        ? this.alertTypeFilter().alert_categories
        : undefined,
      speedingFilter: selected.includes('speeding')
        ? this.speedingFilter()
        : undefined,
      idlingFilter: selected.includes('idling')
        ? this.idlingFilter()
        : undefined,
      utilisationFilter: selected.includes('daily_utilisation')
        ? this.utilisationFilter()
        : undefined,
      stoppingFilter: selected.includes('stopping')
        ? this.stoppingFilter()
        : undefined,
      additionalColumns: selected.includes('trip_history_daily_summary')
        ? this.additionalColumns().additionalColumns
        : undefined,
      customColumns: selected.includes('trip_history_daily_summary')
        ? this.additionalColumns().customFields
        : undefined,
      initialColumns: selected.includes('trip_history_daily_summary')
        ? this.additionalColumns().initialColumns
        : undefined,
      finalColumns: selected.includes('trip_history_daily_summary')
        ? this.additionalColumns().finalColumns
        : undefined,
    });
  }
}
