import { Component, computed, effect, output, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';

import { SelectModule } from 'primeng/select';
import { MultiSelectModule } from 'primeng/multiselect';
import { TranslatePipe } from '@ngx-translate/core';

import { eventCategoryMapping } from '../../../../../../../shared/models/event-types.model';
import { AlertTypeFilterSelection } from '../../../../../../../core/interfaces/report-generation.interface';

export type AlertTypeFilterMode = 'all' | 'specific';

interface ModeOption {
  label: string;
  value: AlertTypeFilterMode;
}

interface CategoryOption {
  label: string;
  value: string;
}

// Alert categories the user can pick from, built from the shared event-type
// model. `value` is the eventClass key the backend filters on (alerts are
// events that raised a notification, identified by the same eventClass keys).
const CATEGORY_OPTIONS: CategoryOption[] = Object.entries(eventCategoryMapping)
  .map(([value, label]) => ({ label, value }))
  .sort((a, b) => a.label.localeCompare(b.label));

/**
 * Alert-Type filter for the Alerts report. Mirrors the event-type filter: an
 * "All Alerts" / "Specific Alerts" mode plus a category multi-select. Emits an
 * empty array for "All" (the backend treats it as a wildcard).
 */
@Component({
  selector: 'app-inline-alert-type-filter',
  imports: [
    CommonModule,
    FormsModule,
    SelectModule,
    MultiSelectModule,
    TranslatePipe,
  ],
  templateUrl: './inline-alert-type-filter.component.html',
})
export class InlineAlertTypeFilterComponent {
  filterChanged = output<AlertTypeFilterSelection>();

  readonly mode = signal<AlertTypeFilterMode>('all');
  readonly selectedCategories = signal<string[]>([]);

  readonly categoryOptions = CATEGORY_OPTIONS;
  readonly modeOptions: ModeOption[] = [
    { label: 'All Alerts', value: 'all' },
    { label: 'Specific Alerts', value: 'specific' },
  ];

  readonly showCategoryMulti = computed(() => this.mode() === 'specific');

  constructor() {
    effect(
      () => {
        this.filterChanged.emit(this.buildSelection());
      },
      { allowSignalWrites: true },
    );
  }

  private buildSelection(): AlertTypeFilterSelection {
    if (this.mode() === 'specific') {
      return { alert_categories: [...this.selectedCategories()] };
    }
    return { alert_categories: [] };
  }
}
