import { Component, output } from '@angular/core';
import { TranslatePipe } from '@ngx-translate/core';

/**
 * Shown when saving the edited report returns a 409 (the conversation's edited
 * report was changed elsewhere — e.g. another tab). Offers the two safe
 * resolutions: take the server's version, or overwrite it with the local edits.
 * Presentational only — the host owns the conflict state and performs the work.
 */
@Component({
  selector: 'app-conflict-modal',
  imports: [TranslatePipe],
  templateUrl: './conflict-modal.component.html',
  styleUrl: './conflict-modal.component.scss',
})
export class ConflictModalComponent {
  /** Discard local edits and load the server's current version. */
  readonly reload = output<void>();
  /** Keep local edits and overwrite the server's version. */
  readonly overwrite = output<void>();
}
