import {
  Component,
  Input,
  OnInit,
  OnChanges,
  OnDestroy,
  SimpleChanges,
  ViewChild,
  ElementRef,
  AfterViewInit,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { ChartBlock } from '../../models/analytics-dashboard.interface';
import { Chart, ChartConfiguration, ChartType } from 'chart.js';
import { isDefined } from '../../../../../../../shared/utils';
import { registerChartJs } from '../../../../../../../shared/utils/register-chart-js';

@Component({
  selector: 'app-chart-block',
  imports: [CommonModule],
  templateUrl: './chart-block.component.html',
  styleUrls: ['./chart-block.component.scss'],
})
export class ChartBlockComponent
  implements OnInit, OnChanges, OnDestroy, AfterViewInit
{
  @Input() block!: ChartBlock;
  @ViewChild('chartCanvas', { static: true })
  chartCanvas!: ElementRef<HTMLCanvasElement>;
  @ViewChild('chartContainer') chartContainer!: ElementRef;

  private chart?: Chart;
  isLoading = true;
  showCustomLegend = false;
  legendItems: { label: string; color: string; value: string }[] = [];

  private readonly colorPalette = [
    '#3b82f6',
    '#ef4444',
    '#22c55e',
    '#f59e0b',
    '#8b5cf6',
    '#06b6d4',
    '#f97316',
    '#84cc16',
    '#ec4899',
    '#6b7280',
    '#14b8a6',
    '#f43f5e',
  ];

  ngOnInit() {
    this.prepareLegendData();
  }

  ngOnChanges(changes: SimpleChanges) {
    // Rebuild the chart when the block content changes (e.g. an AI/user edit
    // patches the data, axis, type, or title). The title is a plain template
    // binding, but the bars/axis live inside the Chart.js config, so without
    // this the canvas keeps rendering the original dataset.
    if ('block' in changes && !changes['block'].firstChange) {
      this.prepareLegendData();
      this.createChart(); // self-destroys any existing chart
    }
  }

  ngAfterViewInit() {
    registerChartJs();
    // Small delay to ensure DOM is ready
    setTimeout(() => {
      this.createChart();
    }, 100);
  }

  ngOnDestroy() {
    if (this.chart) {
      this.chart.destroy();
    }
  }

  getBlockClasses(): string[] {
    const classes = ['chart-block'];

    if (this.block.visual?.theme) {
      classes.push(`theme-${this.block.visual.theme}`);
    }

    return classes;
  }

  private createChart() {
    const ctx = this.chartCanvas.nativeElement.getContext('2d');
    if (!ctx) return;

    // Idempotent: tear down a prior chart so re-renders (and the init timeout)
    // never double-instantiate on the same canvas.
    if (this.chart !== undefined) {
      this.chart.destroy();
      this.chart = undefined;
    }

    const config = this.getChartConfig();

    try {
      this.chart = new Chart(ctx, config);
      this.isLoading = false;
    } catch (error) {
      console.error('Error creating chart:', error);
      this.isLoading = false;
    }
  }

  private getChartConfig(): ChartConfiguration {
    const baseConfig: ChartConfiguration = {
      type: this.getChartType(),
      data: this.getChartData(),
      options: {
        responsive: true,
        maintainAspectRatio: false,
        interaction: {
          intersect: false,
          mode: 'index',
        },
        plugins: {
          legend: {
            display: !this.showCustomLegend,
            position: 'bottom',
            labels: {
              padding: 20,
              usePointStyle: true,
              color:
                getComputedStyle(document.documentElement).getPropertyValue(
                  '--text-color',
                ) || '#374151',
            },
          },
          tooltip: {
            mode: 'index',
            intersect: false,
            backgroundColor: 'rgba(0, 0, 0, 0.8)',
            titleColor: '#fff',
            bodyColor: '#fff',
            borderColor: 'rgba(255, 255, 255, 0.1)',
            borderWidth: 1,
            cornerRadius: 8,
            displayColors: true,
            callbacks: {
              label: (context) => {
                let label = context.dataset.label ?? '';
                if (label) {
                  label += ': ';
                }
                label += this.formatTooltipValue(
                  context.parsed.y ?? context.parsed,
                );
                return label;
              },
            },
          },
        },
        scales: this.getScalesConfig(),
        animation: {
          duration: 1000,
          easing: 'easeOutQuart',
        },
      },
    };

    // Add specific configurations for different chart types
    if (
      this.block.content.chart_type === 'line' ||
      this.block.content.chart_type === 'area'
    ) {
      if (baseConfig.options) {
        baseConfig.options.elements = {
          line: {
            tension: 0.4,
          },
          point: {
            radius: 4,
            hoverRadius: 8,
            borderWidth: 2,
          },
        };
      }
    }

    return baseConfig;
  }

  private getChartType(): ChartType {
    const typeMapping: Record<string, ChartType> = {
      line: 'line',
      bar: 'bar',
      pie: 'pie',
      area: 'line',
      scatter: 'scatter',
      donut: 'doughnut',
    };

    return typeMapping[this.block.content.chart_type] || 'bar';
  }

  private getChartData() {
    const data = this.block.content.data;

    if (['pie', 'donut'].includes(this.block.content.chart_type)) {
      return {
        labels: data.map((d) => d.label),
        datasets: [
          {
            data: data.map((d) => d.value),
            backgroundColor: data.map(
              (d, i) =>
                d.color ?? this.colorPalette[i % this.colorPalette.length],
            ),
            borderWidth: 3,
            borderColor: '#fff',
            hoverBorderWidth: 5,
            hoverOffset: 10,
          },
        ],
      };
    }

    const isArea = this.block.content.chart_type === 'area';
    const baseColor = this.colorPalette[0];

    return {
      labels: data.map((d) => d.label),
      datasets: [
        {
          label: this.block.content.y_axis ?? 'Value',
          data: data.map((d) => d.value),
          backgroundColor:
            this.block.content.chart_type === 'line' || isArea
              ? isArea
                ? this.hexToRgba(baseColor, 0.2)
                : this.hexToRgba(baseColor, 0.1)
              : data.map(
                  (d, i) =>
                    d.color ?? this.colorPalette[i % this.colorPalette.length],
                ),
          borderColor: baseColor,
          borderWidth: 3,
          fill: isArea,
          pointBackgroundColor: baseColor,
          pointBorderColor: '#fff',
          pointBorderWidth: 2,
          pointHoverBackgroundColor: '#fff',
          pointHoverBorderColor: baseColor,
          pointHoverBorderWidth: 3,
        },
      ],
    };
  }

  private getScalesConfig() {
    if (['pie', 'donut'].includes(this.block.content.chart_type)) {
      return {};
    }

    const textColor =
      getComputedStyle(document.documentElement).getPropertyValue(
        '--text-color-secondary',
      ) || '#6b7280';
    const gridColor =
      getComputedStyle(document.documentElement).getPropertyValue(
        '--surface-200',
      ) || '#e5e7eb';

    return {
      x: {
        display: true,
        title: {
          display:
            isDefined(this.block.content.x_axis) &&
            this.block.content.x_axis !== '',
          text: this.block.content.x_axis,
          color: textColor,
        },
        ticks: {
          color: textColor,
        },
        grid: {
          color: gridColor,
        },
      },
      y: {
        display: true,
        title: {
          display:
            isDefined(this.block.content.y_axis) &&
            this.block.content.y_axis !== '',
          text: this.block.content.y_axis,
          color: textColor,
        },
        ticks: {
          color: textColor,
          callback: (value: number | string) => {
            return this.formatAxisValue(value as number);
          },
        },
        grid: {
          color: gridColor,
        },
      },
    };
  }

  private prepareLegendData() {
    if (['pie', 'donut'].includes(this.block.content.chart_type)) {
      this.showCustomLegend = true;
      this.legendItems = this.block.content.data.map((item, index) => ({
        label: item.label,
        color:
          item.color ?? this.colorPalette[index % this.colorPalette.length],
        value: this.formatTooltipValue(item.value),
      }));
    } else {
      // Reset so a type change away from pie/donut drops the custom legend.
      this.showCustomLegend = false;
      this.legendItems = [];
    }
  }

  private formatTooltipValue(value: number): string {
    return new Intl.NumberFormat('en-ZA').format(value);
  }

  private formatAxisValue(value: number): string {
    if (value >= 1000000) {
      return (value / 1000000).toFixed(1) + 'M';
    } else if (value >= 1000) {
      return (value / 1000).toFixed(1) + 'K';
    }
    return value.toString();
  }

  private hexToRgba(hex: string, alpha: number): string {
    const r = Number.parseInt(hex.slice(1, 3), 16);
    const g = Number.parseInt(hex.slice(3, 5), 16);
    const b = Number.parseInt(hex.slice(5, 7), 16);
    return `rgba(${r}, ${g}, ${b}, ${alpha})`;
  }

  downloadChart() {
    if (this.chart) {
      const url = this.chart.toBase64Image('image/png', 1);
      const link = document.createElement('a');
      link.download = `${this.block.content.title ?? 'chart'}.png`;
      link.href = url;
      link.click();
    }
  }
}
