import { Component, Input } from '@angular/core';
import { CommonModule } from '@angular/common';
import {
  KPIBlock,
  KPIMetric,
  MetricComparison,
} from '../../models/analytics-dashboard.interface';

@Component({
  selector: 'app-kpi-block',
  imports: [CommonModule],
  templateUrl: './kpi-block.component.html',
  styleUrls: ['./kpi-block.component.scss'],
})
export class KpiBlockComponent {
  @Input() block!: KPIBlock;

  trackByMetric(index: number, metric: KPIMetric): string {
    return metric.label;
  }

  getBlockClasses(): string[] {
    const classes = ['kpi-block'];

    if (this.block.visual?.theme) {
      classes.push(`theme-${this.block.visual.theme}`);
    }

    return classes;
  }

  getOrientationClass(): string {
    return `orientation-${this.block.content.orientation}`;
  }

  getMetricClasses(metric: KPIMetric): string[] {
    const classes: string[] = [];

    if (metric.comparison) {
      classes.push('has-comparison');
    }

    return classes;
  }

  formatValue(value: number, format: string): string {
    switch (format) {
      case 'currency':
        return new Intl.NumberFormat('en-ZA', {
          style: 'currency',
          currency: 'ZAR',
          minimumFractionDigits: 0,
          maximumFractionDigits: 0,
        }).format(value);

      case 'percentage':
        return value.toFixed(1);

      case 'duration': {
        const hours = Math.floor(value / 60);
        const minutes = value % 60;
        if (hours > 0) {
          return `${hours}h ${minutes}m`;
        }
        return `${minutes}m`;
      }

      case 'number':
      default:
        return new Intl.NumberFormat('en-ZA').format(value);
    }
  }

  formatPercentage(value: number): string {
    const formatted = Math.abs(value).toFixed(1);
    return `${formatted}%`;
  }

  getComparisonClass(comparison: MetricComparison): string {
    return comparison.is_improvement ? 'improvement' : 'decline';
  }

  getTrendIcon(trend: string): string {
    switch (trend) {
      case 'up':
        return 'trend-up';
      case 'down':
        return 'trend-down';
      case 'stable':
        return 'trend-stable';
      default:
        return '';
    }
  }
}
