import { VehicleSelectionResult } from '../inline-vehicle-selector/inline-vehicle-selector.component';
import { ReportConfigSelection } from '../inline-report-config/inline-report-config.component';
import { ReportTypesConfirmation } from '../inline-report-type-selector/inline-report-type-selector.component';
import { ScheduleConfigSelection } from '../inline-schedule-config/inline-schedule-config.component';
import { DateAndVehicleSelection } from '../inline-date-vehicle-selector/inline-date-vehicle-selector.component';
import { AnalyticalReportAssetsStore } from '../../../store/assets.store';
import { AnalyticalReportDateStore } from '../../../store/date.store';
import { AnalyticalReportQueryStore } from '../../../store/query.store';

@Component({
  selector: 'app-query-chat',
  imports: [
    CommonModule,
    ButtonModule,
    CardModule,
    ProgressBarModule,
    SkeletonModule,
    ChatMessageComponent,
    QueryPreviewComponent,
  ],
  templateUrl: './query-chat.component.html',
  styleUrl: './query-chat.component.scss',
})
export class QueryChatComponent implements OnDestroy, AfterViewInit {
  // Injected services
  readonly chatSessionService = inject(ChatSessionService);
  private readonly soundService = inject(ChatSoundService);
  private readonly reportGenerationService = inject(ReportGenerationService);
  private readonly toastService = inject(ToastService);
  private readonly assetsStore = inject(AnalyticalReportAssetsStore);
  private readonly dateStore = inject(AnalyticalReportDateStore);
  private readonly queryStore = inject(AnalyticalReportQueryStore);

  // Inputs
  clientInfo = input<ClientInfo | null>(null);
  readonly fullWidthMode = signal(true);
  readonly guidedMode = signal(true);
  /** When set to a non-null string, the component sends the message and resets the input. */
  messageToSend = input<string | null>(null);
  /** When set to a non-null value, the component loads the snapshot and resets its loading state. */
  snapshotToLoad = input<AnalyticsSnapshotMeta | null>(null);
  /** When set to a non-null string, the component scrolls to and highlights the matching message. */
  scrollTargetId = input<string | null>(null);

  // Store-derived signals for template use
  readonly availableAssetGroups = computed(() =>
    this.assetsStore.availableAssetGroups(),
  );
  readonly availableCostCenters = computed(() =>
    this.assetsStore.availableCostCenters(),
  );

  // Outputs
  generateReport = output<string>();
  viewAnalyticsSnapshot = output<AnalyticsSnapshotMeta>();
  /** Emitted after the component processes a messageToSend so the parent can reset the signal. */
  messageSendComplete = output<void>();
  /** Emitted whenever the count of in-progress report generations changes. */
  generatingReportsCountChange = output<number>();
  // Guided flow outputs
  reportConfigSelected = output<ReportConfigSelection>();
  /** Emitted after the component scrolls to a target so the parent can clear the pending scroll. */
  scrollTargetCleared = output<void>();

  // Report generation counter (exposed so parent can pass to footer)
  readonly generatingReportsCount = signal(0);

  // View children
  @ViewChild('scrollAnchor')
  scrollAnchor!: ElementRef<HTMLDivElement>;
  // Computed signals from service
  readonly messages = this.chatSessionService.messages;
  readonly isTyping = this.chatSessionService.isTyping;
  readonly isConnecting = this.chatSessionService.isConnecting;
  readonly currentQuery = this.chatSessionService.currentQuery;
  readonly queryConfidence = this.chatSessionService.queryConfidence;
  readonly error = this.chatSessionService.error;
  readonly lastFailedOperation = this.chatSessionService.lastFailedOperation;
  readonly session = this.chatSessionService.session;
  readonly dataCollectionStatus = this.chatSessionService.dataCollectionStatus;

  // Form state signals from service (for guided mode)
  readonly formDateRange = this.chatSessionService.formDateRange;
  readonly formSelectedVehicles = this.chatSessionService.formSelectedVehicles;
  readonly formSelectedDataTypes =
    this.chatSessionService.formSelectedDataTypes;
  readonly conversationPhase = this.chatSessionService.conversationPhase;

  // Local computed
  readonly canStartSession = computed(() => {
    const range = this.dateStore.chatDateRange();
    const vehicles = this.assetsStore.chatSelectedVehicles();
    const client = this.clientInfo();
    return range !== null && vehicles.length > 0 && client !== null;
  });

  // For guided mode, we only need a client to start
  readonly canStartGuidedSession = computed(() => {
    const client = this.clientInfo();
    return client !== null;
  });

  readonly isSessionActive = this.chatSessionService.isSessionActive;
  readonly hasSession = this.chatSessionService.hasSession;

  readonly canGenerateReport = computed(
    () => this.currentQuery().length > 0 && this.queryConfidence() >= 50,
  );

  readonly queryChanges = computed(() => {
    // Get the last message with query changes
    const msgs = this.messages();
    for (let i = msgs.length - 1; i >= 0; i--) {
      const changes = msgs[i].metadata?.queryUpdate?.changes;
      if (changes && changes.length > 0) {
        return changes;
      }
    }
    return [];
  });

  readonly collectedDataSummary = computed(() => {
    return this.dataCollectionStatus().collectedData;
  });

  readonly completedVehiclesCount = computed(() => {
    const progress = this.dataCollectionStatus().vehicleProgress;
    if (!progress) return 0;
    return progress.filter((v) => v.status === 'complete').length;
  });

  // Prompt starters for empty chat state
  readonly promptStarters = [
    {
      icon: 'pi-shield',
      text: 'Analyze driver safety scores',
      description: 'Review speeding, harsh braking, and acceleration events',
    },
    {
      icon: 'pi-chart-line',
      text: 'Show fuel efficiency trends',
      description: 'Compare consumption patterns across vehicles',
    },
    {
      icon: 'pi-car',
      text: 'Compare vehicle utilization',
      description: 'Identify underused or overworked assets',
    },
    {
      icon: 'pi-exclamation-triangle',
      text: 'Highlight maintenance alerts',
      description: 'Find vehicles needing attention',
    },
  ];

  readonly showPromptStarters = computed(
    () =>
      this.isSessionActive() &&
      this.messages().length === 0 &&
      !this.isTyping(),
  );

  // The id of the last message that is NOT a report_file_group.
  // Used to keep interactive selectors unlocked even after report files are appended.
  readonly lastNonReportFileMessageId = computed(() => {
    const msgs = this.messages();
    for (let i = msgs.length - 1; i >= 0; i--) {
      if (msgs[i].metadata?.interactiveType !== 'report_file_group') {
        return msgs[i].id;
      }
    }
    return null;
  });

  // Interleaves date separator entries between messages when the date changes
  readonly messagesWithDateSeparators = computed(() => {
    const msgs = this.messages();
    const result: {
      type: 'message' | 'date';
      message?: (typeof msgs)[0];
      label?: string;
    }[] = [];
    let lastDateKey = '';

    for (const msg of msgs) {
      const dateKey = msg.timestamp.toDateString();
      if (dateKey !== lastDateKey) {
        result.push({
          type: 'date',
          label: this.formatDateLabel(msg.timestamp),
        });
        lastDateKey = dateKey;
      }
      result.push({ type: 'message', message: msg });
    }
    return result;
  });

  private formatDateLabel(date: Date): string {
    const today = new Date();
    const yesterday = new Date(today);
    yesterday.setDate(today.getDate() - 1);

    if (date.toDateString() === today.toDateString()) return 'Today';
    if (date.toDateString() === yesterday.toDateString()) return 'Yesterday';
    return date.toLocaleDateString('en-US', {
      weekday: 'long',
      month: 'long',
      day: 'numeric',
      year: 'numeric',
    });
  }

  // Tracks which snapshot is currently loading (by snapshot_id), null if none
  readonly loadingSnapshotId = signal<string | null>(null);

  constructor() {
    // Auto-scroll to bottom when new messages arrive or typing indicator changes.
    // Suppressed when a scroll target is pending (it will scroll to the target instead).
    effect(() => {
      const messageCount = this.messages().length;
      const typing = this.isTyping();
      const collecting = this.dataCollectionStatus().isCollecting;
      const hasScrollTarget = isDefined(untracked(() => this.scrollTargetId()));

      if (!hasScrollTarget && (messageCount > 0 || typing || collecting)) {
        requestAnimationFrame(() => this.scrollToBottom());
      }
    });
    // Auto-start guided session when conditions are met
    effect(() => {
      const isGuided = this.guidedMode();
      const canStart = this.canStartGuidedSession();
      const sessionActive = this.isSessionActive();
      const isConnecting = this.isConnecting();
      const hasSession = this.hasSession();

      // Auto-start guided session if:
      // 1. We're in guided mode
      // 2. We can start a guided session (client is selected)
      // 3. Session is not already active
      // 4. Not currently connecting
      // 5. Haven't already started a session
      // 6. No existing session loaded (e.g. completed/expired conversation)
      if (
        isGuided &&
        canStart &&
        !sessionActive &&
        !isConnecting &&
        !hasSession
      ) {
        void this.startGuidedSession();
      }
    });

    // Keep available vehicles in sync with the service
    // This ensures vehicles are available when the vehicle selection phase is reached,
    // even if they were loaded after the guided session started
    effect(() => {
      const availableVehicles = this.assetsStore.availableVehiclesForChat();
      if (availableVehicles.length > 0) {
        this.chatSessionService.setAvailableVehicles(
          availableVehicles.map((v) => ({ id: v.id, name: v.name })),
        );
      }
    });

    // Reset session when client changes
    let previousClientId: string | null = null;
    effect(() => {
      const clientId = this.clientInfo()?.id ?? null;
      if (previousClientId !== null && clientId !== previousClientId) {
        this.clearSession();
      }
      previousClientId = clientId;
    });

    // Write query and confidence directly to store
    effect(() => {
      const query = this.currentQuery();
      if (query) {
        this.queryStore.setCurrentQuery(query);
      }
    });

    effect(() => {
      const confidence = this.queryConfidence();
      this.queryStore.setCurrentConfidence(confidence);
    });

    // Sound: assistant starts typing
    effect(() => {
      if (this.isTyping()) {
        this.soundService.playAssistantTypingSound();
      }
    });

    // Sound: new assistant message arrived (track count to detect additions only)
    let previousMessageCount = 0;
    effect(() => {
      const msgs = this.messages();
      const lastMsg = msgs.at(-1);
      if (
        msgs.length > previousMessageCount &&
        lastMsg?.sender === 'assistant'
      ) {
        this.soundService.playNewMessageSound();
      }
      previousMessageCount = msgs.length;
    });

    // Sound: session becomes active (false → true transition)
    let previousSessionActive = false;
    effect(() => {
      const active = this.isSessionActive();
      if (active && !previousSessionActive) {
        this.soundService.playSessionStartSound();
      }
      previousSessionActive = active;
    });

    // Sound: error occurred
    let previousError: string | null = null;
    effect(() => {
      const err = this.error();
      if (isDefined(err) && err !== previousError) {
        this.soundService.playErrorSound();
      }
      previousError = err;
    });

    // Emit generatingReportsCount whenever it changes so parent can track it without @ViewChild
    effect(() => {
      this.generatingReportsCountChange.emit(this.generatingReportsCount());
    });

    // React to messageToSend signal input: send when non-null
    let previousMessage: string | null = null;
    effect(() => {
      const msg = this.messageToSend();
      if (isDefined(msg) && msg !== null && msg !== previousMessage) {
        previousMessage = msg;
        void this.onSendMessage(msg).then(() => {
          this.messageSendComplete.emit();
        });
      }
    });

    // React to snapshotToLoad signal input: when parent resets it to null after handling,
    // reset the local loading state (replaces parent calling resetSnapshotLoading() directly)
    let wasNonNull = false;
    effect(() => {
      const snap = this.snapshotToLoad();
      if (isDefined(snap) && snap !== null) {
        wasNonNull = true;
      } else if (wasNonNull) {
        // Transitioned from non-null → null: parent finished handling, reset our state
        wasNonNull = false;
        this.resetSnapshotLoading();
      }
    });

    // Scroll to a specific message when scrollTargetId is set and messages are loaded
    effect(() => {
      const targetId = this.scrollTargetId();
      if (isNullOrUndefined(targetId)) return;

      // Mark untracked to prevent it from scrolling at every message change
      const messages = this.messages();
      if (isNullOrUndefined(targetId) || messages.length === 0) return;
      setTimeout(() => this.scrollToMessage(targetId));
    });
  }

  ngAfterViewInit(): void {
    if (this.messages().length > 0) {
      this.scrollToBottom('instant');
    }
  }

  ngOnDestroy(): void {
    void this.chatSessionService.endSession();
  }

  async retryLastOperation(): Promise<void> {
    await this.lastFailedOperation()?.();
  }

  async startSession(): Promise<void> {
    const range = this.dateStore.chatDateRange();
    const vehicles = this.assetsStore.chatSelectedVehicles();
    const client = this.clientInfo();

    if (!range || vehicles.length === 0 || !client) {
      return;
    }

    const context: ChatContext = {
      clientId: client.id,
      clientName: client.name,
      dateRange: {
        startDate: range.start.toISOString(),
        endDate: range.end.toISOString(),
      },
      vehicleIds: vehicles.map((v) => v.id),
      vehicleNames: Object.fromEntries(vehicles.map((v) => [v.id, v.name])),
    };

    try {
      await this.chatSessionService.startSession(context);
    } catch (err) {
      console.error('Failed to start chat session:', err);
    }
  }

  async onSendMessage(
    content: string,
    options?: {
      selectedActionId?: string;
      selectedActionIds?: string[];
      selectedActions?: SuggestedAction[];
    },
  ): Promise<void> {
    try {
      await this.chatSessionService.sendMessage(content, options);
    } catch (err) {
      console.error('Failed to send message:', err);
    }
  }

  async onActionSelected(action: SuggestedAction): Promise<void> {
    // Handle special actions
    if (action.value === 'generate' || action.value === 'generate_report') {
      this.onGenerateReport();
      return;
    }

    // Send action as a message with its ID for backend tracking
    await this.onSendMessage(action.label, {
      selectedActionId: action.id,
      selectedActions: [action],
    });
  }

  async onMultiActionsSelected(actions: SuggestedAction[]): Promise<void> {
    if (actions.length === 0) return;

    // Check if any selected action is a generate action
    if (
      actions.some(
        (a) => a.value === 'generate' || a.value === 'generate_report',
      )
    ) {
      this.onGenerateReport();
      return;
    }

    // Extract data types from selected actions
    const dataTypes = actions
      .map((a) => a.value.toLowerCase())
      .filter((v): v is DataType =>
        ['trips', 'events', 'telemetry', 'alerts'].includes(v),
      );

    // Get non-data-type actions
    const otherActions = actions.filter(
      (a) =>
        !['trips', 'events', 'telemetry', 'alerts'].includes(
          a.value.toLowerCase(),
        ),
    );

    // Collect all action IDs for backend tracking
    const actionIds = actions.map((a) => a.id);

    // Build message with all selected options
    const selectedLabels = actions.map((a) => a.label).join(', ');

    // Send message to chat about the selections
    if (dataTypes.length > 0 && otherActions.length === 0) {
      // Only data types selected
      await this.onSendMessage(`I'd like to include: ${selectedLabels}`, {
        selectedActionIds: actionIds,
        selectedActions: actions,
      });
    } else if (dataTypes.length === 0 && otherActions.length > 0) {
      // Only non-data-type actions selected
      await this.onSendMessage(`I want to: ${selectedLabels}`, {
        selectedActionIds: actionIds,
        selectedActions: actions,
      });
    } else {
      // Mixed selection
      await this.onSendMessage(`Selected options: ${selectedLabels}`, {
        selectedActionIds: actionIds,
        selectedActions: actions,
      });
    }
  }

  async onPromptStarterClick(prompt: { text: string }): Promise<void> {
    await this.onSendMessage(prompt.text);
  }

  onGenerateReport(): void {
    const query = this.currentQuery();
    if (query) {
      this.soundService.playGenerateReportSound();
      this.generateReport.emit(query);
    }
  }

  // Called by parent when data collection completes
  async submitDataContext(summarizedData: SummarizedData): Promise<void> {
    try {
      // Calculate summary for display
      let trips = 0;
      let events = 0;
      let telemetry = 0;
      let alerts = 0;

      for (const vehicle of Object.values(summarizedData.vehicles)) {
        trips += vehicle.data_summary.trip_count;
        events += vehicle.data_summary.event_count;
        telemetry += vehicle.data_summary.telemetry_count;
        alerts += vehicle.data_summary.alert_count;
      }

      const summary: CollectedDataSummary = {
        trips,
        events,
        telemetry,
        alerts,
      };
      this.chatSessionService.setDataCollectionComplete(summary);

      // Send to backend
      await this.chatSessionService.submitDataContext(summarizedData);
    } catch (err) {
      console.error('Failed to submit data context:', err);
    }
  }

  // Called by parent to update collection progress
  updateCollectionProgress(progress: number): void {
    this.chatSessionService.updateDataCollectionProgress(progress);
  }

  // Called by parent to start collection
  startDataCollection(dataTypes: DataType[]): void {
    const vehicles = this.assetsStore.chatSelectedVehicles().map((v) => ({
      id: v.id,
      name: v.name,
    }));
    this.chatSessionService.setDataCollectionStarted(dataTypes, vehicles);
  }

  private scrollToBottom(behavior: ScrollBehavior = 'smooth'): void {
    this.scrollAnchor?.nativeElement.scrollIntoView({ behavior, block: 'end' });
  }

  private scrollToMessage(targetId: string): void {
    const msgs = this.messages();
    const target = msgs.find(
      (m) =>
        m.metadata?.reportFile?.reportId === targetId ||
        isDefined(
          m.metadata?.reportFiles?.some((f) => f.reportId === targetId),
        ) ||
        m.metadata?.analyticsSnapshot?.snapshot_id === targetId,
    );

    if (isNullOrUndefined(target)) return;

    const element = document.getElementById('msg-' + target.id);
    if (isNullOrUndefined(element)) return;

    element.scrollIntoView({ behavior: 'smooth', block: 'center' });
    element.classList.add('message-highlight');
    setTimeout(() => {
      element.classList.remove('message-highlight');
    }, 3500);

    this.scrollTargetCleared.emit();
  }

  onViewAnalyticsSnapshot(snap: AnalyticsSnapshotMeta): void {
    this.loadingSnapshotId.set(snap.snapshot_id);
    this.viewAnalyticsSnapshot.emit(snap);
  }

  resetSnapshotLoading(): void {
    this.loadingSnapshotId.set(null);
    this.soundService.playAnalyticsCompleteSound();
  }

  // Called by parent to clear session and start fresh
  clearSession(): void {
    // Reset service state so hasSession() becomes false and the auto-start effect re-triggers
    this.chatSessionService.reset();
  }

  // Guided conversation flow handlers
  async startGuidedSession(): Promise<void> {
    const client = this.clientInfo();
    if (!client) {
      return;
    }

    try {
      // Pass available vehicles to the service before starting
      const availableVehicles = this.assetsStore.availableVehiclesForChat();
      if (availableVehicles.length > 0) {
        this.chatSessionService.setAvailableVehicles(
          availableVehicles.map((v) => ({ id: v.id, name: v.name })),
        );
      }

      await this.chatSessionService.startGuidedSession(client.id, client.name);
    } catch (err) {
      console.error('Failed to start guided session:', err);
    }
  }

  // Handler for inline date picker selection
  onDateRangeSelected(dateRange: DateRangeSelection): void {
    // Update service state
    this.chatSessionService.setDateRange(dateRange.start, dateRange.end);
    // Write directly to store
    this.dateStore.setDateRange(dateRange.start, dateRange.end);
  }

  // Handler for combined date + vehicle selector
  onDateAndVehicleSelected(selection: DateAndVehicleSelection): void {
    this.chatSessionService.setDateRangeAndVehicles(
      selection.dateRange.start,
      selection.dateRange.end,
      selection.vehicles.map((v) => ({ id: v.id, name: v.name })),
    );
    // Write directly to stores
    this.dateStore.setDateRange(
      selection.dateRange.start,
      selection.dateRange.end,
    );
    const vehicleIds = selection.vehicles.map((v) => v.id);
    this.assetsStore.setSelectedAssetIds(vehicleIds);
    this.assetsStore.setSelectedGroups(selection.groups);
  }

  // Handler for inline vehicle selector
  onVehiclesSelected(result: VehicleSelectionResult): void {
    // Update service state
    this.chatSessionService.setSelectedVehicles(result.vehicles);
    // Write directly to store
    const vehicleIds = result.vehicles.map((v) => v.id);
    this.assetsStore.setSelectedAssetIds(vehicleIds);
    this.assetsStore.setSelectedGroups(result.groups);
  }

  onReportConfigSelected(config: ReportConfigSelection): void {
    this.reportConfigSelected.emit(config);
  }

  // Handler for inline schedule config — resolves recipients to emails and
  // creates the schedule against the reporting backend.
  async onScheduleConfigSelected(
    selection: ScheduleConfigSelection,
  ): Promise<void> {
    const session = this.chatSessionService.session();
    const ownerId = session?.context?.clientId ?? this.clientInfo()?.id ?? '';
    const conversationId =
      session?.id ?? selection.reportConfig.conversation_id;
    const recipients =
      await this.reportGenerationService.resolveRecipientEmails(
        ownerId,
        selection.recipients,
      );
    await this.reportGenerationService.createSchedule(
      conversationId,
      selection.reportConfig,
      selection.schedule,
      recipients,
    );

    const error = this.reportGenerationService.error();
    if (error != null && error.length > 0) {
      this.toastService.showError('Schedule not created', error);
      return;
    }
    const detail =
      recipients.length > 0
        ? `The report will be e-mailed to ${recipients.length} recipient(s) each run.`
        : 'Your report schedule was created.';
    this.toastService.showSuccess('Schedule created', detail);
  }

  // Handler for inline data type selector
  onDataTypesSelected(dataTypes: string[]): void {
    // Update service state
    const typedDataTypes = dataTypes.filter((t): t is DataType =>
      ['trips', 'events', 'telemetry', 'alerts'].includes(t),
    );
    this.chatSessionService.setSelectedDataTypes(typedDataTypes);
    // Write directly to store
    this.queryStore.setSelectedDataTypesList(dataTypes);
    this.queryStore.updateDataTypeOptions((options) =>
      options.map((opt) => ({
        ...opt,
        selected: dataTypes.includes(opt.value),
      })),
    );
  }

  // Handler for report type selector — locks selector, reveals pending message,
  // fires parallel generateReport() calls, decrements counter as each resolves.
  async onReportTypesConfirmed(
    payload: ReportTypesConfirmation,
  ): Promise<void> {
    const reportTypes = payload.types;
    const geofenceFilter = payload.geofenceFilter;
    const eventCategories = payload.eventCategories;
    const alertCategories = payload.alertCategories;
    const speedingFilter = payload.speedingFilter;
    const idlingFilter = payload.idlingFilter;
    const utilisationFilter = payload.utilisationFilter;
    const stoppingFilter = payload.stoppingFilter;
    const additionalColumns = new Set(payload.additionalColumns ?? []);
    const customColumns = payload.customColumns ?? [];
    const initialColumns = payload.initialColumns ?? [];
    const finalColumns = payload.finalColumns ?? [];

    // 1. Lock selector and reveal the held-back backend message
    this.chatSessionService.revealPendingMessage(reportTypes);

    // 2. Set counter
    this.generatingReportsCount.set(reportTypes.length);

    // 3. Get session context
    const session = this.chatSessionService.session();
    const context = session?.context;
    if (!session || !context) return;

    // 4. Fire parallel generateReport() calls — one per type. Most types send
    // all catalog columns (idling sends only its defaults). Trip Summary honours
    // the "Add Additional Columns" picker: defaults ∪ the user's chosen extras,
    // plus any asset custom-field columns.
    // Columns the Trip Summary picker's Standard group manages — governed by the
    // picker selection; every other default column stays always-on.
    const dailySummaryStandardKeys = new Set(
      this.reportGenerationService
        .getAdditionalStandardColumns('trip_history_daily_summary')
        .map((c) => c.key),
    );
    const requests = reportTypes.map((reportType) => {
      const isDailySummary = reportType === 'trip_history_daily_summary';
      const columnDefs = this.reportGenerationService
        .getAvailableColumns(reportType)
        .filter((c) => {
          if (reportType === 'idling') return c.default;
          if (isDailySummary) {
            return dailySummaryStandardKeys.has(c.key)
              ? additionalColumns.has(c.key)
              : c.default;
          }
          return true;
        });
      const allColumns = columnDefs.map((c) => c.key);
      const extraCategories: ColumnCategory[] = [];
      if (isDailySummary) {
        if (customColumns.length) extraCategories.push('custom_fields');
        if (initialColumns.length) extraCategories.push('initial');
        if (finalColumns.length) extraCategories.push('final');
      }
      const allCategories = [
        ...new Set([...columnDefs.map((c) => c.category), ...extraCategories]),
      ];

      return this.reportGenerationService
        .generateReport({
          conversation_id: session.id,
          company_id: context.clientId,
          report_type: reportType,
          vehicle_ids: context.vehicleIds,
          vehicle_names: context.vehicleNames,
          start_date: context.dateRange.startDate,
          end_date: context.dateRange.endDate,
          columns: allColumns,
          column_categories: allCategories,
          output_format: 'xlsx',
          include_ai_analysis: false,
          ...(isDailySummary && customColumns.length
            ? { custom_columns: customColumns }
            : {}),
          ...(isDailySummary && initialColumns.length
            ? { initial_columns: initialColumns }
            : {}),
          ...(isDailySummary && finalColumns.length
            ? { final_columns: finalColumns }
            : {}),
          ...(reportType === 'geofence' && geofenceFilter
            ? {
                geofence_ids: geofenceFilter.geofence_ids,
                geofence_type_ids: geofenceFilter.geofence_type_ids,
                geofence_group_ids: geofenceFilter.geofence_group_ids,
              }
            : {}),
          ...(reportType === 'events' && eventCategories
            ? { event_categories: eventCategories }
            : {}),
          ...(reportType === 'alerts' && alertCategories
            ? { alert_categories: alertCategories }
            : {}),
          ...(reportType === 'speeding' && speedingFilter
            ? {
                ...(speedingFilter.min_distance_km != null
                  ? { min_distance_km: speedingFilter.min_distance_km }
                  : {}),
                ...(speedingFilter.min_duration_minutes != null
                  ? {
                      min_duration_minutes: speedingFilter.min_duration_minutes,
                    }
                  : {}),
              }
            : {}),
          ...(reportType === 'idling' &&
          idlingFilter &&
          idlingFilter.min_duration_minutes != null
            ? { min_duration_minutes: idlingFilter.min_duration_minutes }
            : {}),
          ...(reportType === 'daily_utilisation' && utilisationFilter
            ? {
                utilization_mode: utilisationFilter.utilization_mode,
                ...(utilisationFilter.daily_target_distance_km != null
                  ? {
                      daily_target_distance_km:
                        utilisationFilter.daily_target_distance_km,
                    }
                  : {}),
              }
            : {}),
          ...(reportType === 'stopping' && stoppingFilter
            ? {
                ...(stoppingFilter.stop_types?.length
                  ? { stop_types: stoppingFilter.stop_types }
                  : {}),
                ...(stoppingFilter.min_duration_minutes != null
                  ? {
                      min_duration_minutes: stoppingFilter.min_duration_minutes,
                    }
                  : {}),
              }
            : {}),
        })
        .then((response) => ({ reportType, response }));
    });

    // 5. As each resolves, decrement counter and add a report_file message
    for (const promise of requests) {
      promise
        .then(({ reportType, response }) => {
          this.generatingReportsCount.update((n) => n - 1);
          if (response) {
            this.chatSessionService.appendReportFileToGroupedMessage(
              reportType,
              response,
            );
            this.soundService.playGenerateReportSound();
          }
        })
        .catch(() => {
          // Decrement even on failure so the banner doesn't get stuck
          this.generatingReportsCount.update((n) => n - 1);
        });
    }
  }
}
