import { Injectable, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { firstValueFrom } from 'rxjs';

import { AuthTokenManagerService } from '../../../../../core/services/auth-token-manager.service';
import { ApiUrlService } from '../../../../../core/services/api-url.service';
import {
  AnalyticsAPIRequest,
  VehicleInfo,
} from '../../../../../core/interfaces/analytics-api-request.interface';
import { ClientResponse } from '../../../../../api/model/clientResponse';
// ClientDataService returns Partial<ClientResponse> — we accept that here
import { ErrorResponse } from '../models/analytical-report.types';
import { AnalyticsResponse } from '../dashboard/models/analytics-dashboard.interface';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { AnalyticalReportAssetsStore } from '../store/assets.store';
import { AnalyticalReportDateStore } from '../store/date.store';
import { AnalyticalReportQueryStore } from '../store/query.store';
import { AnalyticalReportUiStore } from '../store/ui.store';
import { AnalyticalReportLoadingService } from './analytical-report-loading.service';
import { ClientDataService } from '../../../../clients/services/client-data.service';
import { ConversationHistoryService } from '../../../../../core/services/conversation-history.service';

@Injectable()
export class AnalyticalReviewService {
  private readonly http = inject(HttpClient);
  private readonly authTokenManagerService = inject(AuthTokenManagerService);
  private readonly apiUrlService = inject(ApiUrlService);
  private readonly assetsStore = inject(AnalyticalReportAssetsStore);
  private readonly dateStore = inject(AnalyticalReportDateStore);
  private readonly queryStore = inject(AnalyticalReportQueryStore);
  private readonly uiStore = inject(AnalyticalReportUiStore);
  private readonly loadingService = inject(AnalyticalReportLoadingService);
  private readonly clientDataService = inject(ClientDataService);
  private readonly conversationHistoryService = inject(
    ConversationHistoryService,
  );

  clearResponse(): void {
    this.uiStore.setApiResponse(null);
  }

  setApiResponse(
    response: Parameters<typeof this.uiStore.setApiResponse>[0],
  ): void {
    this.uiStore.setApiResponse(response);
  }

  setLastReportQuery(query: string): void {
    this.queryStore.setLastReportQuery(query);
  }

  buildRequest(
    query: string,
    client: Partial<ClientResponse> | null,
    analysisBreakdownText: string,
    selectedVehicles: VehicleInfo[],
    startDate: Date,
    endDate: Date,
    dataTypes: string[],
    conversationId?: string | null,
  ): AnalyticsAPIRequest {
    if (isNullOrUndefined(conversationId))
      throw new Error('Please select a conversation.');
    return {
      key_auth_token: this.authTokenManagerService.getAccessToken() ?? '',
      key_base_url: this.apiUrlService.getCurrentApiUrl(),
      report_query: query + analysisBreakdownText,
      client_id: client?.id ?? '',
      user_role: 'fleet_manager',
      analysis_type: 'fleet_overview',
      vehicle_ids: selectedVehicles,
      date_range: {
        start: startDate.toISOString(),
        end: endDate.toISOString(),
      },
      data_types:
        dataTypes.length > 0 ? dataTypes : ['trips', 'events', 'telemetry'],
      conversation_id: conversationId,
    };
  }

  async submitReview(
    request: AnalyticsAPIRequest,
  ): Promise<AnalyticsResponse | ErrorResponse | null> {
    this.uiStore.setIsSubmitting(true);

    const apiBaseUrl = `${this.apiUrlService.getCurrentApiUrl()}/analytical-review`;

    try {
      const response = await firstValueFrom(
        this.http.post<AnalyticsResponse | ErrorResponse>(apiBaseUrl, request),
      );
      return response;
    } catch (error) {
      console.error(error);
      return null;
    } finally {
      this.uiStore.setIsSubmitting(false);
    }
  }

  async runAnalyticalReview(
    query: string,
  ): Promise<{ errorMessage: string | null; successMessage: string | null }> {
    const assetIds = this.assetsStore.selectedAssetIds();
    if (assetIds.length === 0) {
      return { errorMessage: null, successMessage: null };
    }

    this.uiStore.setIsTestingApi(true);
    this.uiStore.setApiResponse(null);

    this.loadingService.start(
      this.queryStore.selectedDataTypes(),
      assetIds.length,
    );

    const startDate = this.dateStore.startDate();
    const endDate = this.dateStore.endDate();

    if (isNullOrUndefined(startDate) || isNullOrUndefined(endDate)) {
      this.uiStore.setIsTestingApi(false);
      this.loadingService.stop();
      return {
        errorMessage: 'Please select a date range.',
        successMessage: null,
      };
    }

    const conversationId =
      this.conversationHistoryService.selectedConversationId();
    const client = this.clientDataService.getSelectedClientSignal()();

    const requestBody = this.buildRequest(
      query,
      client ?? null,
      this.queryStore.analysisBreakdownText(),
      this.assetsStore
        .chatSelectedVehicles()
        .map((v): VehicleInfo => ({ id: v.id, name: v.name })),
      startDate,
      endDate,
      this.queryStore.selectedDataTypes(),
      conversationId,
    );

    try {
      const response = await this.submitReview(requestBody);
      this.loadingService.stop();

      if (response === null) {
        this.uiStore.setApiResponse({
          success: false,
          error: 'Analysis failed',
        });
        return { errorMessage: 'Analysis failed', successMessage: null };
      }

      const errorResponse = response as ErrorResponse;
      const isError = isDefined(errorResponse.error);
      this.uiStore.setApiResponse({
        success: !isError,
        data: response,
        error: isError
          ? (errorResponse.message ?? errorResponse.error)
          : undefined,
        statusCode: 200,
      });

      if (isError) {
        return {
          errorMessage: `Analysis failed: ${errorResponse.message ?? errorResponse.error}`,
          successMessage: null,
        };
      }

      this.queryStore.setLastReportQuery(requestBody.report_query);
      this.uiStore.setViewerMode('dashboard');
      return {
        errorMessage: null,
        successMessage: 'Report generated successfully!',
      };
    } catch (err) {
      this.loadingService.stop();
      const message = err instanceof Error ? err.message : 'Analysis failed';
      this.uiStore.setApiResponse({ success: false, error: message });
      return {
        errorMessage: `Analysis failed: ${message}`,
        successMessage: null,
      };
    } finally {
      this.uiStore.setIsTestingApi(false);
    }
  }
}
