import { Injectable, computed, inject, signal } from '@angular/core';
import { LocalStorageService } from '../../../../../shared/services/local-storage.service';
import {
  LOCAL_STORAGE_ANALYTICAL_VIEWER_COLLAPSED_KEY,
  LOCAL_STORAGE_CONVERSATION_SIDEBAR_KEY,
} from '../../../../../core/models';
import { ReportConfigSelection } from '../chat/components/inline-report-config/inline-report-config.component';
import { AnalyticsSnapshotMeta } from '../../../../../core/interfaces/conversation.interface';
import { ReportGenerationResponse } from '../../../../../core/interfaces/report-generation.interface';
import {
  ApiResponse,
  buildLegacyAnalyticsResponse,
} from '../models/analytical-report.types';
import { AnalyticsResponse } from '../dashboard/models/analytics-dashboard.interface';
import {
  isDefined,
  isNullOrUndefined,
  safeStringify,
} from '../../../../../shared/utils';
import { AnalyticalReportAssetsStore } from './assets.store';
import { AnalyticalReportDateStore } from './date.store';

/** Which inline viewer occupies the right split pane ('null' = chat only). */
export type ViewerMode = 'dashboard' | 'reports' | null;

@Injectable()
export class AnalyticalReportUiStore {
  private readonly localStorageService = inject(LocalStorageService);
  private readonly assetsStore = inject(AnalyticalReportAssetsStore);
  private readonly dateStore = inject(AnalyticalReportDateStore);

  private readonly _viewerMode = signal<ViewerMode>(null);
  private readonly _viewerCollapsed = signal<boolean>(
    this.localStorageService.getItem<boolean>(
      LOCAL_STORAGE_ANALYTICAL_VIEWER_COLLAPSED_KEY,
    ) ?? false,
  );
  private readonly _sidebarCollapsed = signal<boolean>(
    this.localStorageService.getItem<boolean>(
      LOCAL_STORAGE_CONVERSATION_SIDEBAR_KEY,
    ) ?? false,
  );
  private readonly _pendingReportConfig = signal<ReportConfigSelection | null>(
    null,
  );
  private readonly _isGeneratingFile = signal<boolean>(false);
  private readonly _configDrawerVisible = signal<boolean>(false);
  private readonly _configDrawerInitialDeliveryMode = signal<
    'now' | 'schedule'
  >('now');

  // State migrated from AnalyticalReviewService
  private readonly _isSubmitting = signal<boolean>(false);
  private readonly _isTestingApi = signal<boolean>(false);
  private readonly _errorMessage = signal<string | null>(null);
  private readonly _successMessage = signal<string | null>(null);
  private readonly _apiResponse = signal<ApiResponse | null>(null);

  // State migrated from facade
  private readonly _generatedReport = signal<ReportGenerationResponse | null>(
    null,
  );
  private readonly _pendingMessage = signal<string | null>(null);
  private readonly _pendingSnapshot = signal<AnalyticsSnapshotMeta | null>(
    null,
  );
  private readonly _generatingReportsCount = signal<number>(0);
  private readonly _pendingScrollTarget = signal<string | null>(null);

  readonly viewerMode = this._viewerMode.asReadonly();
  readonly viewerCollapsed = this._viewerCollapsed.asReadonly();
  readonly sidebarCollapsed = this._sidebarCollapsed.asReadonly();
  readonly pendingReportConfig = this._pendingReportConfig.asReadonly();
  readonly isGeneratingFile = this._isGeneratingFile.asReadonly();
  readonly configDrawerVisible = this._configDrawerVisible.asReadonly();
  readonly configDrawerInitialDeliveryMode =
    this._configDrawerInitialDeliveryMode.asReadonly();
  readonly isSubmitting = this._isSubmitting.asReadonly();
  readonly isTestingApi = this._isTestingApi.asReadonly();
  readonly errorMessage = this._errorMessage.asReadonly();
  readonly successMessage = this._successMessage.asReadonly();
  readonly apiResponse = this._apiResponse.asReadonly();
  readonly generatedReport = this._generatedReport.asReadonly();
  readonly pendingMessage = this._pendingMessage.asReadonly();
  readonly pendingSnapshot = this._pendingSnapshot.asReadonly();
  readonly generatingReportsCount = this._generatingReportsCount.asReadonly();
  readonly pendingScrollTarget = this._pendingScrollTarget.asReadonly();

  // Computed signals derived from _apiResponse
  readonly reportSummary = computed(() => {
    const response = this._apiResponse();
    const analyticsData = response?.data as AnalyticsResponse | undefined;
    const summary = analyticsData?.response?.summary;
    return safeStringify(summary) ?? 'Report generated successfully.';
  });

  readonly dashboardResponse = computed((): AnalyticsResponse | undefined => {
    const response = this._apiResponse();
    if (response?.success !== true || isNullOrUndefined(response?.data)) {
      return undefined;
    }

    const analyticsData = response.data as AnalyticsResponse | undefined;
    if (isNullOrUndefined(analyticsData?.response)) {
      return undefined;
    }

    if (isDefined(analyticsData.response.blocks)) {
      return analyticsData;
    }

    return buildLegacyAnalyticsResponse(
      response.data,
      this.assetsStore.selectedAssetIds().length,
      this.dateStore.formatDateRange(),
    );
  });

  // Writable references needed for [(visible)] two-way model bindings in template
  readonly configDrawerVisibleWritable = this._configDrawerVisible;

  setViewerMode(mode: ViewerMode): void {
    this._viewerMode.set(mode);
    // Opening a viewer always brings it back into view.
    if (mode !== null) {
      this.setViewerCollapsed(false);
    }
  }

  setViewerCollapsed(collapsed: boolean): void {
    this._viewerCollapsed.set(collapsed);
    this.localStorageService.setItem(
      LOCAL_STORAGE_ANALYTICAL_VIEWER_COLLAPSED_KEY,
      collapsed,
    );
  }

  setSidebarCollapsed(collapsed: boolean): void {
    this._sidebarCollapsed.set(collapsed);
    this.localStorageService.setItem(
      LOCAL_STORAGE_CONVERSATION_SIDEBAR_KEY,
      collapsed,
    );
  }

  setPendingReportConfig(config: ReportConfigSelection | null): void {
    this._pendingReportConfig.set(config);
  }

  setIsGeneratingFile(generating: boolean): void {
    this._isGeneratingFile.set(generating);
  }

  setConfigDrawerVisible(visible: boolean, mode?: 'now' | 'schedule'): void {
    this._configDrawerVisible.set(visible);
    if (mode != null) {
      this._configDrawerInitialDeliveryMode.set(mode);
    }
  }

  setIsSubmitting(submitting: boolean): void {
    this._isSubmitting.set(submitting);
  }

  setIsTestingApi(testing: boolean): void {
    this._isTestingApi.set(testing);
  }

  setErrorMessage(message: string | null): void {
    this._errorMessage.set(message);
  }

  setSuccessMessage(message: string | null): void {
    this._successMessage.set(message);
  }

  setApiResponse(response: ApiResponse | null): void {
    this._apiResponse.set(response);
  }

  setGeneratedReport(report: ReportGenerationResponse | null): void {
    this._generatedReport.set(report);
  }

  setPendingMessage(message: string | null): void {
    this._pendingMessage.set(message);
  }

  setPendingSnapshot(snapshot: AnalyticsSnapshotMeta | null): void {
    this._pendingSnapshot.set(snapshot);
  }

  setGeneratingReportsCount(count: number): void {
    this._generatingReportsCount.set(count);
  }

  setPendingScrollTarget(id: string | null): void {
    this._pendingScrollTarget.set(id);
  }

  reset(): void {
    this._viewerMode.set(null);
    this.setViewerCollapsed(false);
    this._pendingReportConfig.set(null);
    this._isGeneratingFile.set(false);
    this._isSubmitting.set(false);
    this._isTestingApi.set(false);
    this._errorMessage.set(null);
    this._successMessage.set(null);
    this._apiResponse.set(null);
    this._generatedReport.set(null);
    this._pendingMessage.set(null);
    this._pendingSnapshot.set(null);
    this._generatingReportsCount.set(0);
    this._pendingScrollTarget.set(null);
  }
}
