import {
  Component,
  computed,
  effect,
  inject,
  input,
  output,
  signal,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { firstValueFrom } from 'rxjs';

import { ButtonModule } from 'primeng/button';
import { SelectModule } from 'primeng/select';
import { MultiSelectModule } from 'primeng/multiselect';

import { ZonesService, ZoneGroupsService } from '../../../../../../../api';
import { GeofenceFilterSelection } from '../../../../../../../core/interfaces/report-generation.interface';

/**
 * Six modes from the Geofence Report spec. All-variants collapse to "no
 * restriction" on the corresponding dimension when emitted to the backend.
 */
export type GeofenceFilterMode =
  | 'all_types'
  | 'specific_type'
  | 'all_groups'
  | 'specific_group'
  | 'all_in_type'
  | 'specific_geofence';

interface ModeOption {
  label: string;
  value: GeofenceFilterMode;
}

interface IdNameOption {
  label: string;
  value: string;
}

// Zone types from the Fleet API (see ZoneResponse.ZoneTypeEnum). Treated as
// "type ids" by the backend — it accepts whatever string identifies a type.
const ZONE_TYPE_OPTIONS: IdNameOption[] = [
  { label: 'Location', value: 'location' },
  { label: 'Keep-In', value: 'keepin' },
  { label: 'No-Go', value: 'nogo' },
  { label: 'Route', value: 'route' },
];

@Component({
  selector: 'app-inline-geofence-filter',
  imports: [
    CommonModule,
    FormsModule,
    ButtonModule,
    SelectModule,
    MultiSelectModule,
  ],
  templateUrl: './inline-geofence-filter.component.html',
})
export class InlineGeofenceFilterComponent {
  private readonly zonesService = inject(ZonesService);
  private readonly zoneGroupsService = inject(ZoneGroupsService);

  // ── Inputs / Outputs ───────────────────────────────────────────────────
  ownerId = input<string>('');
  filterChanged = output<GeofenceFilterSelection>();

  // ── State ──────────────────────────────────────────────────────────────
  readonly mode = signal<GeofenceFilterMode>('all_types');

  // User selections per dimension.
  readonly selectedTypes = signal<string[]>([]);
  readonly selectedTypeForAllIn = signal<string | null>(null);
  readonly selectedGroups = signal<string[]>([]);
  readonly selectedZones = signal<string[]>([]);

  // Lookup data.
  readonly zoneTypeOptions = ZONE_TYPE_OPTIONS;
  readonly zoneGroupOptions = signal<IdNameOption[]>([]);
  readonly zoneOptions = signal<IdNameOption[]>([]);
  readonly isLoadingGroups = signal<boolean>(false);
  readonly isLoadingZones = signal<boolean>(false);

  private readonly loadedGroupsForOwner = signal<string | null>(null);
  private readonly loadedZonesForOwner = signal<string | null>(null);

  readonly modeOptions: ModeOption[] = [
    { label: 'All Geofence Types', value: 'all_types' },
    { label: 'Specific Geofence Type', value: 'specific_type' },
    { label: 'All Geofence Groups', value: 'all_groups' },
    { label: 'Specific Geofence Group', value: 'specific_group' },
    { label: 'All Geofences in Type', value: 'all_in_type' },
    { label: 'Specific Geofence', value: 'specific_geofence' },
  ];

  // ── Derived visibility helpers (for the template) ──────────────────────
  readonly showTypeMulti = computed(() => this.mode() === 'specific_type');
  readonly showGroupMulti = computed(() => this.mode() === 'specific_group');
  readonly showTypeSingle = computed(() => this.mode() === 'all_in_type');
  readonly showZoneMulti = computed(() => this.mode() === 'specific_geofence');

  constructor() {
    // Lazy-load groups/zones when the owner becomes available, so we don't
    // hit the API for the dimensions the user isn't currently filtering on.
    // The `loadedXForOwner` guards mean we only attempt each load once per
    // owner — successful or not — so a 500 from the API can't trigger a
    // retry storm.
    effect(
      () => {
        const owner = this.ownerId();
        const m = this.mode();
        if (!owner) return;
        if (
          m === 'specific_group' &&
          this.loadedGroupsForOwner() !== owner &&
          !this.isLoadingGroups()
        ) {
          void this.loadZoneGroups(owner);
        }
        if (
          m === 'specific_geofence' &&
          this.loadedZonesForOwner() !== owner &&
          !this.isLoadingZones()
        ) {
          void this.loadZones(owner);
        }
      },
      { allowSignalWrites: true },
    );

    // Emit a selection whenever inputs change. Empty arrays for every
    // dimension = "Select all" (backend treats missing/empty as wildcard).
    effect(
      () => {
        this.filterChanged.emit(this.buildSelection());
      },
      { allowSignalWrites: true },
    );
  }

  private buildSelection(): GeofenceFilterSelection {
    const m = this.mode();
    const empty: GeofenceFilterSelection = {
      geofence_ids: [],
      geofence_type_ids: [],
      geofence_group_ids: [],
    };

    switch (m) {
      case 'all_types':
      case 'all_groups':
        return empty;
      case 'specific_type':
        return { ...empty, geofence_type_ids: [...this.selectedTypes()] };
      case 'specific_group':
        return { ...empty, geofence_group_ids: [...this.selectedGroups()] };
      case 'all_in_type': {
        const t = this.selectedTypeForAllIn();
        return {
          ...empty,
          geofence_type_ids: t !== null && t.length > 0 ? [t] : [],
        };
      }
      case 'specific_geofence':
        return { ...empty, geofence_ids: [...this.selectedZones()] };
    }
  }

  private async loadZoneGroups(owner: string): Promise<void> {
    this.isLoadingGroups.set(true);
    try {
      // Pull a generous page; geofence group counts in practice are small.
      const response = await firstValueFrom(
        this.zoneGroupsService.listZoneGroups(owner, 0, 500, 'name'),
      );
      const items = (response.items ?? []) as {
        id: string;
        name?: string | null;
      }[];
      this.zoneGroupOptions.set(
        items.map((g) => ({ label: g.name ?? g.id, value: g.id })),
      );
    } catch {
      this.zoneGroupOptions.set([]);
    } finally {
      // Mark attempted regardless of outcome so the lazy-load effect won't
      // re-fire and spam the API on failure.
      this.loadedGroupsForOwner.set(owner);
      this.isLoadingGroups.set(false);
    }
  }

  private async loadZones(owner: string): Promise<void> {
    this.isLoadingZones.set(true);
    try {
      const response = await firstValueFrom(
        this.zonesService.listZones(owner, 0, 1000, 'name'),
      );
      const items = (response.items ?? []) as {
        id: string;
        name?: string | null;
      }[];
      this.zoneOptions.set(
        items.map((z) => ({ label: z.name ?? z.id, value: z.id })),
      );
    } catch {
      this.zoneOptions.set([]);
    } finally {
      this.loadedZonesForOwner.set(owner);
      this.isLoadingZones.set(false);
    }
  }
}
