import {
  Component,
  computed,
  effect,
  inject,
  input,
  output,
  signal,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { TranslatePipe } from '@ngx-translate/core';
import { toObservable, toSignal } from '@angular/core/rxjs-interop';
import { catchError, forkJoin, map, of, switchMap } from 'rxjs';

import {
  AccountsService,
  ClientResponse,
  IoTypeListItem,
  IoTypesService,
} from '../../../../../../../api';
import { ReportGenerationService } from '../../../../../../../core/services/report-generation.service';
import {
  ColumnDefinition,
  CustomFieldColumn,
  ReportType,
} from '../../../../../../../core/interfaces/report-generation.interface';

/**
 * Selection emitted by the "Add Additional Columns" picker.
 * `additionalColumns` are catalog column keys (the non-default Standard extras);
 * the rest are asset custom-field / IoType columns keyed by their id + title.
 */
export interface AdditionalColumnsSelection {
  additionalColumns: string[];
  customFields: CustomFieldColumn[];
  initialColumns: CustomFieldColumn[];
  finalColumns: CustomFieldColumn[];
}

/** A vendor/client-split set of selectable items. */
interface OwnerGroups {
  vendor: CustomFieldColumn[];
  client: CustomFieldColumn[];
}

const EMPTY_GROUPS: OwnerGroups = { vendor: [], client: [] };

/**
 * Custom-field buckets that are not asset attributes — excluded from the picker.
 * (The `customFields` map is keyed by entity type and by asset-type GUIDs; the
 * GUID buckets hold the asset custom fields we want.)
 */
const NON_ASSET_FIELD_BUCKETS = new Set([
  'device',
  'simcard',
  'assettag',
  'event',
]);

/** Owner-split picker groups (each renders Vendor + Client sub-dropdowns). */
type OwnerSectionId = 'custom' | 'initial' | 'final';

interface OwnerSection {
  id: OwnerSectionId;
  /** Translation key for the section header. */
  label: string;
  groups: OwnerGroups;
}

const ADDITIONAL_COLUMNS_I18N =
  'DEVELOPMENT.ANALYTICAL_REPORT.FILTERS.ADDITIONAL_COLUMNS';

/**
 * "Add Additional Columns" picker for the Trip Summary report. Renders four
 * collapsible groups — Standard, Custom Fields, Initial, Final — where Custom
 * Fields / Initial / Final expand into Vendor and Client sub-groups of clickable
 * chips (selected chips fill with the primary color). Custom fields come from the
 * Client document's `customFields`; Initial/Final options are the active IoTypes
 * owned by the client and its parent vendor.
 */
@Component({
  selector: 'app-inline-additional-columns',
  imports: [CommonModule, TranslatePipe],
  templateUrl: './inline-additional-columns.component.html',
})
export class InlineAdditionalColumnsComponent {
  private readonly reportGenerationService = inject(ReportGenerationService);
  private readonly accountsService = inject(AccountsService);
  private readonly ioTypesService = inject(IoTypesService);

  // Inputs
  reportType = input.required<ReportType>();
  /** Client id used to load custom-field definitions and IoTypes. */
  ownerId = input<string>('');
  /**
   * Whether to show the Standard group. Off when the host already has its own
   * standard-column picker (e.g. the Configure Report panel), so this component
   * only contributes Custom Fields / Initial / Final.
   */
  showStandard = input<boolean>(true);

  // Output
  selectionChanged = output<AdditionalColumnsSelection>();

  // Selection state. Keys are namespaced by group: `${group}::${itemKey}`
  // (group ∈ standard | custom | initial | final).
  private readonly selected = signal<Set<string>>(new Set());
  // Which collapsible sections are open (keyed by section / sub-group id).
  // Standard is open by default so its pre-selected columns are visible.
  private readonly expanded = signal<Set<string>>(new Set(['standard']));

  /** Standard columns offered in the picker (some default-on, e.g. Trips). */
  readonly standardColumns = computed<ColumnDefinition[]>(() =>
    this.reportGenerationService.getAdditionalStandardColumns(this.reportType()),
  );

  /** Display name of the current report, shown beside the picker title so
   * multiple report pickers can be told apart once others opt in. */
  readonly reportLabel = computed(
    () =>
      this.reportGenerationService
        .getReportTypes()
        .find((r) => r.report_type === this.reportType())?.display_name ?? '',
  );

  /**
   * Loads the Client document (for custom fields + the parent vendor id) and the
   * active IoTypes for both the client and vendor, grouped by owner.
   */
  private readonly loadedData = toSignal(
    toObservable(this.ownerId).pipe(
      switchMap((id) => {
        if (!id) {
          return of({ customFields: EMPTY_GROUPS, ioTypes: EMPTY_GROUPS });
        }
        return this.accountsService.getClient(id).pipe(
          switchMap((client) => {
            const vendorId = client?.owner?.id;
            const ioCalls = [this.listActiveIoTypes(id)];
            if (vendorId && vendorId !== id) {
              ioCalls.push(this.listActiveIoTypes(vendorId));
            }
            return forkJoin(ioCalls).pipe(
              map((ioLists) => ({
                customFields: this.buildCustomFieldGroups(client),
                ioTypes: this.buildIoTypeGroups(ioLists.flat()),
              })),
            );
          }),
          catchError(() =>
            of({ customFields: EMPTY_GROUPS, ioTypes: EMPTY_GROUPS }),
          ),
        );
      }),
    ),
    { initialValue: { customFields: EMPTY_GROUPS, ioTypes: EMPTY_GROUPS } },
  );

  private readonly customFieldGroups = computed(
    () => this.loadedData().customFields,
  );
  private readonly ioTypeGroups = computed(() => this.loadedData().ioTypes);

  /** The three owner-split sections (Custom Fields / Initial / Final). */
  readonly ownerSections = computed<OwnerSection[]>(() => [
    {
      id: 'custom',
      label: `${ADDITIONAL_COLUMNS_I18N}.CUSTOM_FIELDS`,
      groups: this.customFieldGroups(),
    },
    {
      id: 'initial',
      label: `${ADDITIONAL_COLUMNS_I18N}.INITIAL`,
      groups: this.ioTypeGroups(),
    },
    {
      id: 'final',
      label: `${ADDITIONAL_COLUMNS_I18N}.FINAL`,
      groups: this.ioTypeGroups(),
    },
  ]);

  readonly hasStandard = computed(() => this.standardColumns().length > 0);

  constructor() {
    // Reset selections whenever the report type changes, pre-selecting the
    // default-on Standard columns (Trips, Drive Time, Stop Time, Parked Time)
    // so they show highlighted.
    effect(
      () => {
        const defaults = this.showStandard()
          ? this.standardColumns()
              .filter((c) => c.default)
              .map((c) => `standard::${c.key}`)
          : [];
        this.selected.set(new Set(defaults));
      },
      { allowSignalWrites: true },
    );

    // Emit the current selection to the parent selector.
    effect(() => {
      this.selectionChanged.emit(this.buildSelection());
    });
  }

  // ---- Expand / collapse -------------------------------------------------

  isExpanded(id: string): boolean {
    return this.expanded().has(id);
  }

  toggleExpand(id: string): void {
    this.expanded.update((current) => {
      const next = new Set(current);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  }

  // ---- Chip selection ----------------------------------------------------

  isSelected(group: string, key: string): boolean {
    return this.selected().has(`${group}::${key}`);
  }

  toggle(group: string, key: string): void {
    const composite = `${group}::${key}`;
    this.selected.update((current) => {
      const next = new Set(current);
      if (next.has(composite)) next.delete(composite);
      else next.add(composite);
      return next;
    });
  }

  /** Number of selected items within a section (for the header badge). */
  selectedCount(group: string): number {
    const prefix = `${group}::`;
    let count = 0;
    for (const key of this.selected()) if (key.startsWith(prefix)) count++;
    return count;
  }

  // ---- Selection assembly ------------------------------------------------

  private buildSelection(): AdditionalColumnsSelection {
    const selected = this.selected();
    const io = this.ioTypeGroups();
    const cf = this.customFieldGroups();

    const pick = (group: string, pool: CustomFieldColumn[]): CustomFieldColumn[] =>
      pool.filter((item) => selected.has(`${group}::${item.key}`));

    return {
      additionalColumns: this.standardColumns()
        .filter((c) => selected.has(`standard::${c.key}`))
        .map((c) => c.key),
      customFields: pick('custom', [...cf.vendor, ...cf.client]),
      initialColumns: pick('initial', [...io.vendor, ...io.client]),
      finalColumns: pick('final', [...io.vendor, ...io.client]),
    };
  }

  // ---- Data loading helpers ---------------------------------------------

  private listActiveIoTypes(ownerId: string) {
    return this.ioTypesService
      .listIoTypes(ownerId, undefined, 0, 1000)
      .pipe(
        map((res) => res.items ?? []),
        catchError(() => of([] as IoTypeListItem[])),
      );
  }

  private buildCustomFieldGroups(client: ClientResponse | null): OwnerGroups {
    const vendor = new Map<string, CustomFieldColumn>();
    const clientOwned = new Map<string, CustomFieldColumn>();

    const customFields = client?.customFields ?? {};
    for (const [bucket, fields] of Object.entries(customFields)) {
      if (NON_ASSET_FIELD_BUCKETS.has(bucket)) continue;
      for (const field of fields ?? []) {
        if (!field?.id) continue;
        const target = field.owner === 'client' ? clientOwned : vendor;
        // Dedupe by id — the same field can appear under multiple asset types.
        if (!target.has(field.id)) {
          target.set(field.id, { key: field.id, title: field.title });
        }
      }
    }
    return this.toSortedGroups(vendor, clientOwned);
  }

  private buildIoTypeGroups(items: IoTypeListItem[]): OwnerGroups {
    const vendor = new Map<string, CustomFieldColumn>();
    const clientOwned = new Map<string, CustomFieldColumn>();

    for (const item of items) {
      if (!item?.id || item.state !== 'active') continue;
      const target = item.owner?.type === 'client' ? clientOwned : vendor;
      if (!target.has(item.id)) {
        // Carry the IoType unit so the backend can render "122 355 Km".
        target.set(item.id, { key: item.id, title: item.name ?? item.id, unit: item.unit ?? null });
      }
    }
    return this.toSortedGroups(vendor, clientOwned);
  }

  private toSortedGroups(
    vendor: Map<string, CustomFieldColumn>,
    clientOwned: Map<string, CustomFieldColumn>,
  ): OwnerGroups {
    const byTitle = (a: CustomFieldColumn, b: CustomFieldColumn): number =>
      a.title.localeCompare(b.title);
    return {
      vendor: [...vendor.values()].sort(byTitle),
      client: [...clientOwned.values()].sort(byTitle),
    };
  }
}
