import {
  Component,
  computed,
  effect,
  inject,
  input,
  output,
  signal,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ButtonModule } from 'primeng/button';

import { ReportGenerationService } from '../../../../../../../core/services/report-generation.service';
import { isDefined } from '../../../../../../../shared/utils';
import {
  ColumnCategory,
  AlertTypeFilterSelection,
  ColumnDefinition,
  CustomFieldColumn,
  EMPTY_GEOFENCE_FILTER,
  EMPTY_IDLING_FILTER,
  EMPTY_SPEEDING_FILTER,
  EMPTY_STOPPING_FILTER,
  EMPTY_UTILISATION_FILTER,
  EventTypeFilterSelection,
  GeofenceFilterSelection,
  IdlingFilterSelection,
  ReportType,
  SpeedingFilterSelection,
  StoppingFilterSelection,
  UtilisationFilterSelection,
} from '../../../../../../../core/interfaces/report-generation.interface';
import { InlineGeofenceFilterComponent } from '../inline-geofence-filter/inline-geofence-filter.component';
import { InlineEventTypeFilterComponent } from '../inline-event-type-filter/inline-event-type-filter.component';
import { InlineAlertTypeFilterComponent } from '../inline-alert-type-filter/inline-alert-type-filter.component';
import { InlineSpeedingFilterComponent } from '../inline-speeding-filter/inline-speeding-filter.component';
import { InlineIdlingFilterComponent } from '../inline-idling-filter/inline-idling-filter.component';
import { InlineUtilisationFilterComponent } from '../inline-utilisation-filter/inline-utilisation-filter.component';
import { InlineStoppingFilterComponent } from '../inline-stopping-filter/inline-stopping-filter.component';
import {
  AdditionalColumnsSelection,
  InlineAdditionalColumnsComponent,
} from '../inline-additional-columns/inline-additional-columns.component';

export interface ReportConfigSelection {
  reportType: ReportType;
  outputFormat: 'csv' | 'xlsx';
  includeAiAnalysis: boolean;
  columns: string[];
  columnCategories: ColumnCategory[];
  /** Only meaningful when `reportType === 'geofence'`; ignored otherwise. */
  geofenceFilter?: GeofenceFilterSelection;
  /** Selected event-class keys. Only meaningful when `reportType === 'events'`. */
  eventCategories?: string[];
  /** Numeric thresholds. Only meaningful when `reportType === 'speeding'`. */
  speedingFilter?: SpeedingFilterSelection;
  /** Duration threshold. Only meaningful when `reportType === 'idling'`. */
  idlingFilter?: IdlingFilterSelection;
  /** Mode & target. Only meaningful when `reportType === 'daily_utilisation'`. */
  utilisationFilter?: UtilisationFilterSelection;
  /** Stop types & duration. Only meaningful when `reportType === 'stopping'`. */
  stoppingFilter?: StoppingFilterSelection;
  /** Selected alert-class keys. Only meaningful when `reportType === 'alerts'`. */
  alertCategories?: string[];
  /** Asset custom-field columns (Trip Summary "Add Additional Columns"). */
  customColumns?: CustomFieldColumn[];
  /** First-trip IoType columns (Trip Summary "Add Additional Columns"). */
  initialColumns?: CustomFieldColumn[];
  /** Last-trip IoType columns (Trip Summary "Add Additional Columns"). */
  finalColumns?: CustomFieldColumn[];
}

const OUTPUT_FORMAT_OPTIONS = [
  { label: 'CSV', value: 'csv' as const },
  { label: 'XLSX', value: 'xlsx' as const },
];

@Component({
  selector: 'app-inline-report-config',
  imports: [
    CommonModule,
    FormsModule,
    ButtonModule,
    InlineGeofenceFilterComponent,
    InlineEventTypeFilterComponent,
    InlineAlertTypeFilterComponent,
    InlineSpeedingFilterComponent,
    InlineIdlingFilterComponent,
    InlineUtilisationFilterComponent,
    InlineStoppingFilterComponent,
    InlineAdditionalColumnsComponent,
  ],
  templateUrl: './inline-report-config.component.html',
  styleUrl: './inline-report-config.component.scss',
})
export class InlineReportConfigComponent {
  private readonly reportGenerationService = inject(ReportGenerationService);

  // Inputs
  initialReportType = input<ReportType | null>(null);
  hideConfirmButton = input(false);
  /** Client/owner id used by the geofence filter to load zones & groups. */
  ownerId = input<string>('');

  // Output
  reportConfigSelected = output<ReportConfigSelection>();

  // Constants exposed to template
  readonly reportTypes = this.reportGenerationService.getReportTypes();
  readonly outputFormatOptions = OUTPUT_FORMAT_OPTIONS;

  // State
  selectedReportType = signal<ReportType | null>(null);
  geofenceFilter = signal<GeofenceFilterSelection>({
    ...EMPTY_GEOFENCE_FILTER,
  });
  eventTypeFilter = signal<EventTypeFilterSelection>({ event_categories: [] });
  alertTypeFilter = signal<AlertTypeFilterSelection>({ alert_categories: [] });
  speedingFilter = signal<SpeedingFilterSelection>({
    ...EMPTY_SPEEDING_FILTER,
  });
  idlingFilter = signal<IdlingFilterSelection>({ ...EMPTY_IDLING_FILTER });
  utilisationFilter = signal<UtilisationFilterSelection>({
    ...EMPTY_UTILISATION_FILTER,
  });
  stoppingFilter = signal<StoppingFilterSelection>({
    ...EMPTY_STOPPING_FILTER,
  });
  additionalColumns = signal<AdditionalColumnsSelection>({
    additionalColumns: [],
    customFields: [],
    initialColumns: [],
    finalColumns: [],
  });

  readonly isDailySummaryReport = computed(
    () => this.selectedReportType() === 'trip_history_daily_summary',
  );

  readonly isGeofenceReport = computed(
    () => this.selectedReportType() === 'geofence',
  );

  readonly isEventsReport = computed(
    () => this.selectedReportType() === 'events',
  );

  readonly isAlertsReport = computed(
    () => this.selectedReportType() === 'alerts',
  );

  readonly isSpeedingReport = computed(
    () => this.selectedReportType() === 'speeding',
  );

  readonly isIdlingReport = computed(
    () => this.selectedReportType() === 'idling',
  );

  readonly isDailyUtilisationReport = computed(
    () => this.selectedReportType() === 'daily_utilisation',
  );

  readonly isStoppingReport = computed(
    () => this.selectedReportType() === 'stopping',
  );

  constructor() {
    effect(
      () => {
        const initial = this.initialReportType();
        if (initial) this.selectReportType(initial);
      },
      { allowSignalWrites: true },
    );
  }
  outputFormat = signal<'csv' | 'xlsx'>('xlsx');
  selectedColumns = signal<Set<string>>(new Set());

  // Computed
  readonly availableColumns = computed(() => {
    const type = this.selectedReportType();
    return type ? this.reportGenerationService.getAvailableColumns(type) : [];
  });

  readonly columnsByCategory = computed(() => {
    const cols = this.availableColumns();
    const map = new Map<ColumnCategory, ColumnDefinition[]>();
    for (const col of cols) {
      if (!map.has(col.category)) map.set(col.category, []);
      const entry = map.get(col.category);
      if (isDefined(entry)) entry.push(col);
    }
    return map;
  });

  readonly categoryKeys = computed(() =>
    Array.from(this.columnsByCategory().keys()),
  );

  readonly selectedColumnCount = computed(() => this.selectedColumns().size);

  readonly canConfirm = computed(
    () => this.selectedReportType() !== null && this.selectedColumns().size > 0,
  );

  readonly allColumnsSelected = computed(
    () => this.selectedColumns().size === this.availableColumns().length,
  );

  readonly formattedSummary = computed(() => {
    const type = this.reportTypes.find(
      (r) => r.report_type === this.selectedReportType(),
    );
    const count = this.selectedColumnCount();
    const fmt = this.outputFormat().toUpperCase();
    return `${type?.display_name ?? ''} — ${count} columns — ${fmt}`;
  });

  // Methods
  selectReportType(type: ReportType): void {
    this.selectedReportType.set(type);
    const defaults = this.reportGenerationService.getDefaultColumns(type);
    this.selectedColumns.set(new Set(defaults));
  }

  toggleColumn(key: string): void {
    this.selectedColumns.update((current) => {
      const next = new Set(current);
      if (next.has(key)) next.delete(key);
      else next.add(key);
      return next;
    });
  }

  isColumnSelected(key: string): boolean {
    return this.selectedColumns().has(key);
  }

  selectAllColumns(): void {
    this.selectedColumns.set(
      new Set(this.availableColumns().map((c) => c.key)),
    );
  }

  clearColumns(): void {
    this.selectedColumns.set(new Set());
  }

  onConfirm(): void {
    if (!this.canConfirm()) return;
    const type = this.selectedReportType();
    if (!isDefined(type)) return;
    const cols = Array.from(this.selectedColumns());
    const allCols = this.availableColumns();
    const isDailySummary = type === 'trip_history_daily_summary';
    const extra = this.additionalColumns();
    const customColumns = isDailySummary ? extra.customFields : [];
    const initialColumns = isDailySummary ? extra.initialColumns : [];
    const finalColumns = isDailySummary ? extra.finalColumns : [];
    const categories = [
      ...new Set<ColumnCategory>([
        ...allCols
          .filter((c) => cols.includes(c.key))
          .map((c) => c.category),
        ...(customColumns.length ? (['custom_fields'] as const) : []),
        ...(initialColumns.length ? (['initial'] as const) : []),
        ...(finalColumns.length ? (['final'] as const) : []),
      ]),
    ];
    this.reportConfigSelected.emit({
      reportType: type,
      outputFormat: this.outputFormat(),
      includeAiAnalysis: false,
      columns: cols,
      columnCategories: categories,
      customColumns: customColumns.length ? customColumns : undefined,
      initialColumns: initialColumns.length ? initialColumns : undefined,
      finalColumns: finalColumns.length ? finalColumns : undefined,
      geofenceFilter: type === 'geofence' ? this.geofenceFilter() : undefined,
      eventCategories:
        type === 'events' ? this.eventTypeFilter().event_categories : undefined,
      alertCategories:
        type === 'alerts' ? this.alertTypeFilter().alert_categories : undefined,
      speedingFilter: type === 'speeding' ? this.speedingFilter() : undefined,
      idlingFilter: type === 'idling' ? this.idlingFilter() : undefined,
      utilisationFilter:
        type === 'daily_utilisation' ? this.utilisationFilter() : undefined,
      stoppingFilter: type === 'stopping' ? this.stoppingFilter() : undefined,
    });
  }
}
