import { ReportMutation } from '../models/report-mutation.interface';

/**
 * Build the text for the synthetic "Applied: …" system message appended to the
 * chat after a mutation commits (transparency log). Prefers the assistant's
 * `rationale`; otherwise derives a concise per-kind summary.
 *
 * @param mutation A mutation that has ALREADY passed the reducer's guards.
 * @returns A single line, e.g. "Applied: removed block kpi-1" or "Applied: <rationale>".
 */
export function describeMutation(mutation: ReportMutation): string {
  const rationale = mutation.rationale?.trim();
  const body =
    rationale !== undefined && rationale.length > 0
      ? rationale
      : defaultDescription(mutation);
  return `Applied: ${body}`;
}

/** Fallback description when the mutation carries no rationale. */
function defaultDescription(mutation: ReportMutation): string {
  switch (mutation.kind) {
    case 'add': {
      const where =
        mutation.at_index === undefined
          ? 'at the end'
          : `at position ${mutation.at_index + 1}`;
      return `added a ${mutation.block.block_type} block ${where}`;
    }
    case 'replace':
      return `replaced block ${mutation.block_id}`;
    case 'patch':
      return `updated block ${mutation.block_id}`;
    case 'remove':
      return `removed block ${mutation.block_id}`;
    case 'reorder':
      return `reordered ${mutation.order.length} blocks`;
  }
}
