import { MultiSelectModule } from 'primeng/multiselect';
import { SelectModule } from 'primeng/select';
import { ToggleButtonModule } from 'primeng/togglebutton';

import { ReportGenerationService } from '../../../../../core/services/report-generation.service';
import { ConversationHistoryService } from '../../../../../core/services/conversation-history.service';
import {
  ConversationSummary,
  ReportFile,
  AnalyticsSnapshotMeta,
  ConversationVisibility,
} from '../../../../../core/interfaces/conversation.interface';
import {
  ReportType,
  ReportTypeConfig,
  ScheduleItem,
} from '../../../../../core/interfaces/report-generation.interface';
import {
  cronToHuman,
  getReportTypeLabel,
} from '../../../../../core/utils/schedule.utils';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { SessionStatus } from '../chat/models/chat.interface';

export interface ReportFileResult {
  conversationId: string;
  conversationTitle: string;
  file: ReportFile;
}

export interface AnalyticsSnapshotResult {
  conversationId: string;
  conversationTitle: string;
  snapshot: AnalyticsSnapshotMeta;
}

export interface DateGroup<T> {
  label: string;
  items: T[];
}

export interface ActiveFilterChip {
  label: string;
  group: string;
  clear: () => void;
}

function groupByDate<T>(
  items: T[],
  getDate: (item: T) => string,
): DateGroup<T>[] {
  const now = new Date();
  const startOfToday = new Date(
    now.getFullYear(),
    now.getMonth(),
    now.getDate(),
  );
  const startOfYesterday = new Date(startOfToday.getTime() - 86_400_000);
  const startOfWeek = new Date(
    startOfToday.getTime() - (now.getDay() || 7) * 86_400_000,
  );
  const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);

  const buckets: Record<string, T[]> = {
    Today: [],
    Yesterday: [],
    'This Week': [],
    'This Month': [],
    Older: [],
  };

  for (const item of items) {
    const d = new Date(getDate(item));
    if (d >= startOfToday) buckets['Today'].push(item);
    else if (d >= startOfYesterday) buckets['Yesterday'].push(item);
    else if (d >= startOfWeek) buckets['This Week'].push(item);
    else if (d >= startOfMonth) buckets['This Month'].push(item);
    else buckets['Older'].push(item);
  }

  return Object.entries(buckets)
    .filter(([, group]) => group.length > 0)
    .map(([label, group]) => ({ label, items: group }));
}

@Component({
  selector: 'app-global-search',
  imports: [
    CommonModule,
    FormsModule,
    DialogModule,
    InputTextModule,
    InputGroupModule,
    TabsModule,
    ListboxModule,
    MenuModule,
    DividerModule,
    ProgressSpinnerModule,
    IconFieldModule,
    InputIconModule,
    ChipModule,
    TagModule,
    MultiSelectModule,
    SelectModule,
    ToggleButtonModule,
  ],
  templateUrl: './global-search.component.html',
  styleUrls: ['./global-search.component.scss'],
})
export class GlobalSearchComponent {
  @ViewChild('searchInput') searchInput!: ElementRef<HTMLInputElement>;

  private readonly conversationHistoryService = inject(
    ConversationHistoryService,
  );
  private readonly reportGenerationService = inject(ReportGenerationService);
  private readonly destroyRef = inject(DestroyRef);

  readonly visible = model<boolean>(false);
  readonly conversationOpened = output<{
    conversationId: string;
    scrollTargetId?: string;
  }>();

  readonly searchQuery = signal('');
  readonly isLoading = signal(false);
  readonly hasError = signal(false);
  activeTabIndex = signal<number>(0);

  private readonly conversations = signal<ConversationSummary[]>([]);
  private readonly schedules = signal<ScheduleItem[]>([]);
  private readonly reportTypes = signal<ReportTypeConfig[]>([]);

  private readonly searchSubject = new Subject<string>();

  // ── Filter signals ───────────────────────────────────────────────────────

  readonly convFilter = signal<{
    statuses: SessionStatus[];
    visibilities: ConversationVisibility[];
    hasReport: boolean | null;
    tags: string[];
  }>({ statuses: [], visibilities: [], hasReport: null, tags: [] });

  readonly reportFilter = signal<{
    reportTypes: ReportType[];
    statuses: SessionStatus[];
  }>({ reportTypes: [], statuses: [] });

  readonly scheduleFilter = signal<{
    isActive: boolean | null;
    reportTypes: ReportType[];
    frequencyUnit: 'days' | 'weeks' | 'months' | null;
  }>({ isActive: null, reportTypes: [], frequencyUnit: null });

  readonly analyticalFilter = signal<{
    statuses: SessionStatus[];
    visibilities: ConversationVisibility[];
  }>({ statuses: [], visibilities: [] });

  // ── Filter options (static) ──────────────────────────────────────────────

  readonly statusOptions: { label: string; value: SessionStatus }[] = [
    { label: 'Active', value: 'active' },
    { label: 'Completed', value: 'completed' },
    { label: 'Expired', value: 'expired' },
    { label: 'Awaiting Data', value: 'awaiting_data' },
    { label: 'Building Query', value: 'building_query' },
  ];

  readonly visibilityOptions: {
    label: string;
    value: ConversationVisibility;
  }[] = [
    { label: 'Private', value: 'private' },
    { label: 'Public', value: 'shared' },
  ];

  readonly frequencyOptions: {
    label: string;
    value: 'days' | 'weeks' | 'months';
  }[] = [
    { label: 'Daily', value: 'days' },
    { label: 'Weekly', value: 'weeks' },
    { label: 'Monthly', value: 'months' },
  ];

  readonly activeOptions: { label: string; value: boolean }[] = [
    { label: 'Active', value: true },
    { label: 'Inactive', value: false },
  ];

  // ── Dynamic filter options derived from data ─────────────────────────────

  readonly tagOptions = computed(() =>
    [...new Set(this.conversations().flatMap((c) => c.tags ?? []))].map(
      (t) => ({
        label: t,
        value: t,
      }),
    ),
  );

  readonly reportTypeOptions = computed(() =>
    this.reportTypes().map((r) => ({
      label: r.display_name,
      value: r.report_type,
    })),
  );

  // ── Tabs ─────────────────────────────────────────────────────────────────

  readonly tabs = [
    { label: 'All', icon: 'pi-objects-column' },
    { label: 'Conversations', icon: 'pi-send' },
    { label: 'Reports', icon: 'pi-chart-bar' },
    { label: 'Scheduled Reports', icon: 'pi-clock' },
    { label: 'Analytical Reviews', icon: 'pi-microchip-ai' },
  ];

  readonly quickActions = [
    {
      label: 'New Conversation',
      icon: 'pi-send',
      action: () => this.navigateToNew(),
    },
    {
      label: 'New Report',
      icon: 'pi-file-plus',
      action: () => this.navigateToNew(),
    },
    {
      label: 'New Scheduled Report',
      icon: 'pi-calendar-plus',
      action: () => this.navigateToNew(),
    },
    {
      label: 'New Analytical Review',
      icon: 'pi-chart-line',
      action: () => this.navigateToNew(),
    },
  ];

  // ── Filtered results ─────────────────────────────────────────────────────

  readonly conversationResults = computed(() => {
    const query = this.searchQuery().toLowerCase();
    const filters = this.convFilter();
    let results = this.conversations();
    if (query)
      results = results.filter((conversation) =>
        conversation.title?.toLowerCase().includes(query),
      );
    if (filters.statuses.length)
      results = results.filter((conversation) =>
        filters.statuses.includes(conversation.status),
      );
    if (filters.visibilities.length)
      results = results.filter((conversation) =>
        filters.visibilities.includes(conversation.visibility),
      );
    if (filters.hasReport !== null)
      results = results.filter(
        (conversation) => conversation.has_report === filters.hasReport,
      );
    if (filters.tags.length)
      results = results.filter((conversation) =>
        filters.tags.every((tag) => conversation.tags?.includes(tag) === true),
      );
    return results;
  });

  readonly reportResults = computed(() => {
    const query = this.searchQuery().toLowerCase();
    const filters = this.reportFilter();
    const flat: ReportFileResult[] = [];
    for (const conversation of this.conversations()) {
      if (isNullOrUndefined(conversation.report_files?.length)) continue;
      for (const file of conversation.report_files) {
        if (
          query &&
          !file.filename?.toLowerCase().includes(query) &&
          !conversation.title?.toLowerCase().includes(query)
        )
          continue;
        if (
          filters.reportTypes.length &&
          isDefined(file.report_type) &&
          !filters.reportTypes.includes(file.report_type as ReportType)
        )
          continue;
        if (
          filters.statuses.length &&
          !filters.statuses.includes(conversation.status)
        )
          continue;
        flat.push({
          conversationId: conversation.id,
          conversationTitle: conversation.title,
          file,
        });
      }
    }
    return flat;
  });

  readonly scheduleResults = computed(() => {
    const query = this.searchQuery().toLowerCase();
    const filters = this.scheduleFilter();
    let results = this.schedules();
    if (query)
      results = results.filter((schedule) =>
        getReportTypeLabel(
          schedule.report_config?.report_type,
          this.reportTypes(),
        )
          .toLowerCase()
          .includes(query),
      );
    if (filters.isActive !== null)
      results = results.filter(
        (schedule) => schedule.is_active === filters.isActive,
      );
    if (filters.reportTypes.length)
      results = results.filter((schedule) =>
        filters.reportTypes.includes(schedule.report_config?.report_type),
      );
    if (filters.frequencyUnit)
      results = results.filter(
        (schedule) =>
          schedule.schedule?.relative_date_range?.unit ===
          filters.frequencyUnit,
      );
    return results;
  });

  readonly analyticalResults = computed(() => {
    const query = this.searchQuery().toLowerCase();
    const filters = this.analyticalFilter();
    const flat: AnalyticsSnapshotResult[] = [];
    for (const conversation of this.conversations()) {
      if (isNullOrUndefined(conversation.analytics_snapshots?.length)) continue;
      if (
        filters.statuses.length &&
        !filters.statuses.includes(conversation.status)
      )
        continue;
      if (
        filters.visibilities.length &&
        !filters.visibilities.includes(conversation.visibility)
      )
        continue;
      for (const snapshot of conversation.analytics_snapshots) {
        if (
          query &&
          !snapshot.query?.toLowerCase().includes(query) &&
          !conversation.title?.toLowerCase().includes(query)
        )
          continue;
        flat.push({
          conversationId: conversation.id,
          conversationTitle: conversation.title,
          snapshot,
        });
      }
    }
    return flat;
  });

  readonly conversationGroups = computed(() =>
    groupByDate(
      this.conversationResults(),
      (conversation) => conversation.last_activity,
    ),
  );

  readonly reportGroups = computed(() =>
    groupByDate(this.reportResults(), (r) => r.file.created_at ?? ''),
  );

  readonly scheduleGroups = computed(() =>
    groupByDate(this.scheduleResults(), (schedule) => schedule.next_run),
  );

  readonly analyticalGroups = computed(() =>
    groupByDate(this.analyticalResults(), (r) => r.snapshot.created_at ?? ''),
  );

  // ── Active filter chips (unified strip) ──────────────────────────────────

  readonly activeConvChips = computed<ActiveFilterChip[]>(() => {
    const filters = this.convFilter();
    const chips: ActiveFilterChip[] = [];
    for (const status of filters.statuses) {
      const label =
        this.statusOptions.find((option) => option.value === status)?.label ??
        status;
      chips.push({
        group: 'Status',
        label,
        clear: () =>
          this.convFilter.update((current) => ({
            ...current,
            statuses: current.statuses.filter(
              (existing) => existing !== status,
            ),
          })),
      });
    }
    for (const visibility of filters.visibilities) {
      const label =
        this.visibilityOptions.find((option) => option.value === visibility)
          ?.label ?? visibility;
      chips.push({
        group: 'Visibility',
        label,
        clear: () =>
          this.convFilter.update((current) => ({
            ...current,
            visibilities: current.visibilities.filter(
              (existing) => existing !== visibility,
            ),
          })),
      });
    }
    if (filters.hasReport !== null) {
      chips.push({
        group: 'Has Report',
        label: filters.hasReport ? 'Yes' : 'No',
        clear: () =>
          this.convFilter.update((current) => ({
            ...current,
            hasReport: null,
          })),
      });
    }
    for (const tag of filters.tags) {
      chips.push({
        group: 'Tag',
        label: tag,
        clear: () =>
          this.convFilter.update((current) => ({
            ...current,
            tags: current.tags.filter((existing) => existing !== tag),
          })),
      });
    }
    return chips;
  });

  readonly activeReportChips = computed<ActiveFilterChip[]>(() => {
    const filters = this.reportFilter();
    const chips: ActiveFilterChip[] = [];
    for (const reportType of filters.reportTypes) {
      const label =
        this.reportTypeOptions().find((option) => option.value === reportType)
          ?.label ?? reportType;
      chips.push({
        group: 'Type',
        label,
        clear: () =>
          this.reportFilter.update((current) => ({
            ...current,
            reportTypes: current.reportTypes.filter(
              (existing) => existing !== reportType,
            ),
          })),
      });
    }
    for (const status of filters.statuses) {
      const label =
        this.statusOptions.find((option) => option.value === status)?.label ??
        status;
      chips.push({
        group: 'Status',
        label,
        clear: () =>
          this.reportFilter.update((current) => ({
            ...current,
            statuses: current.statuses.filter(
              (existing) => existing !== status,
            ),
          })),
      });
    }
    return chips;
  });

  readonly activeScheduleChips = computed<ActiveFilterChip[]>(() => {
    const filters = this.scheduleFilter();
    const chips: ActiveFilterChip[] = [];
    if (filters.isActive !== null) {
      chips.push({
        group: 'State',
        label: filters.isActive ? 'Active' : 'Inactive',
        clear: () =>
          this.scheduleFilter.update((current) => ({
            ...current,
            isActive: null,
          })),
      });
    }
    for (const reportType of filters.reportTypes) {
      const label =
        this.reportTypeOptions().find((option) => option.value === reportType)
          ?.label ?? reportType;
      chips.push({
        group: 'Type',
        label,
        clear: () =>
          this.scheduleFilter.update((current) => ({
            ...current,
            reportTypes: current.reportTypes.filter(
              (existing) => existing !== reportType,
            ),
          })),
      });
    }
    if (filters.frequencyUnit) {
      const label =
        this.frequencyOptions.find(
          (option) => option.value === filters.frequencyUnit,
        )?.label ?? filters.frequencyUnit;
      chips.push({
        group: 'Frequency',
        label,
        clear: () =>
          this.scheduleFilter.update((current) => ({
            ...current,
            frequencyUnit: null,
          })),
      });
    }
    return chips;
  });

  readonly activeAnalyticalChips = computed<ActiveFilterChip[]>(() => {
    const filters = this.analyticalFilter();
    const chips: ActiveFilterChip[] = [];
    for (const status of filters.statuses) {
      const label =
        this.statusOptions.find((option) => option.value === status)?.label ??
        status;
      chips.push({
        group: 'Status',
        label,
        clear: () =>
          this.analyticalFilter.update((current) => ({
            ...current,
            statuses: current.statuses.filter(
              (existing) => existing !== status,
            ),
          })),
      });
    }
    for (const visibility of filters.visibilities) {
      const label =
        this.visibilityOptions.find((option) => option.value === visibility)
          ?.label ?? visibility;
      chips.push({
        group: 'Visibility',
        label,
        clear: () =>
          this.analyticalFilter.update((current) => ({
            ...current,
            visibilities: current.visibilities.filter(
              (existing) => existing !== visibility,
            ),
          })),
      });
    }
    return chips;
  });

  // ── Helpers ──────────────────────────────────────────────────────────────

  clearConvFilters(): void {
    this.convFilter.set({
      statuses: [],
      visibilities: [],
      hasReport: null,
      tags: [],
    });
  }

  clearReportFilters(): void {
    this.reportFilter.set({ reportTypes: [], statuses: [] });
  }

  clearScheduleFilters(): void {
    this.scheduleFilter.set({
      isActive: null,
      reportTypes: [],
      frequencyUnit: null,
    });
  }

  clearAnalyticalFilters(): void {
    this.analyticalFilter.set({ statuses: [], visibilities: [] });
  }

  constructor() {
    this.searchSubject
      .pipe(debounceTime(300), takeUntilDestroyed(this.destroyRef))
      .subscribe((query) => this.searchQuery.set(query));

    effect(() => {
      if (this.visible()) {
        this.onOpen();
      }
    });
  }

  private onOpen(): void {
    this.searchQuery.set('');
    this.activeTabIndex.set(0);
    this.isLoading.set(true);
    this.hasError.set(false);
    this.reportTypes.set(this.reportGenerationService.getReportTypes());
    this.clearConvFilters();
    this.clearReportFilters();
    this.clearScheduleFilters();
    this.clearAnalyticalFilters();

    setTimeout(() => {
      this.searchInput?.nativeElement.focus();
    }, 50);

    Promise.all([
      this.conversationHistoryService.loadConversations(),
      this.reportGenerationService.listSchedules(),
    ])
      .then(([convs, scheds]) => {
        this.conversations.set(convs);
        this.schedules.set(scheds);
      })
      .catch(() => {
        this.hasError.set(true);
      })
      .finally(() => {
        this.isLoading.set(false);
      });
  }

  setActiveTab(tabIndex: number): void {
    this.activeTabIndex.set(tabIndex);
  }

  onSearch(event: Event): void {
    this.searchSubject.next((event.target as HTMLInputElement).value);
  }

  openConversation(conversationId: string, scrollTargetId?: string): void {
    this.conversationOpened.emit({ conversationId, scrollTargetId });
    this.visible.set(false);
  }

  getScheduleLabel(s: ScheduleItem): string {
    return getReportTypeLabel(s.report_config?.report_type, this.reportTypes());
  }

  getScheduleFrequency(s: ScheduleItem): string {
    return cronToHuman(s.schedule);
  }

  closeDialog(): void {
    this.visible.set(false);
  }

  private navigateToNew(): void {
    this.visible.set(false);
  }
}
