import { Injectable, computed, signal } from '@angular/core';

import {
  ChatMessage,
  ChatSession,
  DataCollectionStatus,
} from '../chat/models/chat.interface';

export type ConversationPhase =
  | 'greeting'
  | 'date_and_vehicle_selection'
  | 'date_selection'
  | 'vehicle_selection'
  | 'data_type_selection'
  | 'query_building'
  | 'ready';

@Injectable()
export class ChatSessionStore {
  // ============================================================================
  // Private state
  // ============================================================================

  private readonly _session = signal<ChatSession | null>(null);
  private readonly _messages = signal<ChatMessage[]>([]);
  private readonly _isConnecting = signal(false);
  private readonly _isTyping = signal(false);
  private readonly _error = signal<string | null>(null);
  private readonly _lastFailedOperation = signal<(() => Promise<void>) | null>(
    null,
  );
  private readonly _conversationPhase = signal<ConversationPhase>('greeting');
  private readonly _dataCollectionStatus = signal<DataCollectionStatus>({
    isCollecting: false,
    progress: 0,
    dataTypes: [],
    collectedData: null,
  });
  private readonly _finalQuery = signal<string | null>(null);

  // ============================================================================
  // Public readonly signals
  // ============================================================================

  readonly session = this._session.asReadonly();
  readonly messages = this._messages.asReadonly();
  readonly isConnecting = this._isConnecting.asReadonly();
  readonly isTyping = this._isTyping.asReadonly();
  readonly error = this._error.asReadonly();
  readonly lastFailedOperation = this._lastFailedOperation.asReadonly();
  readonly conversationPhase = this._conversationPhase.asReadonly();
  readonly dataCollectionStatus = this._dataCollectionStatus.asReadonly();
  readonly finalQuery = this._finalQuery.asReadonly();

  // ============================================================================
  // Computed signals
  // ============================================================================

  readonly isSessionActive = computed(() => {
    const status = this._session()?.status;
    return (
      status === 'active' ||
      status === 'awaiting_data' ||
      status === 'building_query'
    );
  });

  readonly hasSession = computed(() => this._session() !== null);
  readonly hasMessages = computed(() => this._messages().length > 0);

  // ============================================================================
  // Setters
  // ============================================================================

  setSession(session: ChatSession | null): void {
    this._session.set(session);
  }

  updateSession(updater: (s: ChatSession | null) => ChatSession | null): void {
    this._session.update(updater);
  }

  setMessages(messages: ChatMessage[]): void {
    this._messages.set(messages);
  }

  updateMessages(updater: (msgs: ChatMessage[]) => ChatMessage[]): void {
    this._messages.update(updater);
  }

  setIsConnecting(value: boolean): void {
    this._isConnecting.set(value);
  }

  setIsTyping(value: boolean): void {
    this._isTyping.set(value);
  }

  setError(error: string | null): void {
    this._error.set(error);
  }

  setLastFailedOperation(op: (() => Promise<void>) | null): void {
    this._lastFailedOperation.set(op);
  }

  setConversationPhase(phase: ConversationPhase): void {
    this._conversationPhase.set(phase);
  }

  setDataCollectionStatus(status: DataCollectionStatus): void {
    this._dataCollectionStatus.set(status);
  }

  updateDataCollectionStatus(
    updater: (s: DataCollectionStatus) => DataCollectionStatus,
  ): void {
    this._dataCollectionStatus.update(updater);
  }

  setFinalQuery(query: string | null): void {
    this._finalQuery.set(query);
  }

  // ============================================================================
  // Reset
  // ============================================================================

  reset(): void {
    this._session.set(null);
    this._messages.set([]);
    this._isConnecting.set(false);
    this._isTyping.set(false);
    this._error.set(null);
    this._lastFailedOperation.set(null);
    this._conversationPhase.set('greeting');
    this._dataCollectionStatus.set({
      isCollecting: false,
      progress: 0,
      dataTypes: [],
      collectedData: null,
    });
    this._finalQuery.set(null);
  }
}
