import { Component, effect, output, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';

import { TranslatePipe } from '@ngx-translate/core';

import {
  StopType,
  StoppingFilterSelection,
} from '../../../../../../../core/interfaces/report-generation.interface';

/**
 * Filter for the Stopping report. Two parts:
 *  - Stop type: which kind of stop to include (Ignition Off / Speed). The stop
 *    type follows from the device's `active_input` config, so a vehicle is one
 *    or the other — this is a single choice (defaults to Ignition Off) and is
 *    emitted as a one-element `stop_types` whitelist.
 *  - Duration (minutes): optional strictly greater-than threshold; a blank
 *    input emits `null`, which the backend treats as "show all".
 */
@Component({
  selector: 'app-inline-stopping-filter',
  imports: [CommonModule, FormsModule, TranslatePipe],
  templateUrl: './inline-stopping-filter.component.html',
})
export class InlineStoppingFilterComponent {
  filterChanged = output<StoppingFilterSelection>();

  readonly stopType = signal<StopType>('ignition_off');
  readonly minDurationMinutes = signal<number | null>(null);

  constructor() {
    effect(
      () => {
        this.filterChanged.emit({
          stop_types: [this.stopType()],
          min_duration_minutes: this.minDurationMinutes(),
        });
      },
      { allowSignalWrites: true },
    );
  }

  setDuration(value: string): void {
    this.minDurationMinutes.set(value === '' ? null : Number(value));
  }
}
