  // ============================================================================

  private readonly _isGenerating = signal(false);
  private readonly _generationProgress = signal('');
  private readonly _error = signal<string | null>(null);

  readonly isGenerating = this._isGenerating.asReadonly();
  readonly generationProgress = this._generationProgress.asReadonly();
  readonly error = this._error.asReadonly();

  // ============================================================================
  // Report Generation
  // ============================================================================

  async generateReport(
    request: ReportGenerationRequest,
  ): Promise<ReportGenerationResponse | null> {
    this._isGenerating.set(true);
    this._error.set(null);
    this._generationProgress.set('Generating report...');

    try {
      const userTimeZone =
        this.userSessionService.currentUserSession()?.timeZoneId ?? '';
      const response = await firstValueFrom(
        this.http.post<ReportGenerationResponse>(
          `${this.chatApiBaseUrl()}/generate-report`,
          {
            ...request,
            // Backend only resolves IANA zone names (e.g. Africa/Johannesburg).
            // When the user profile stores a GMT±N value, fall back to the
            // browser's IANA zone — the same zone the preset window is computed
            // in (resolveDatePreset) — so dates don't render in UTC.
            timezone:
              request.timezone ??
              (userTimeZone.includes('/')
                ? userTimeZone
                : Intl.DateTimeFormat().resolvedOptions().timeZone),
            key_auth_token: this.authTokenManagerService.getAccessToken() ?? '',
            key_base_url: this.apiUrlService.getCurrentApiUrl(),
          },
        ),
      );
      return response;
    } catch (err) {
      this._error.set(
        err instanceof Error ? err.message : 'Report generation failed',
      );
      return null;
    } finally {
      this._isGenerating.set(false);
      this._generationProgress.set('');
    }
  }

  // ============================================================================
  // File Download
  // ============================================================================

  downloadReportFile(response: ReportGenerationResponse): void {
    const { data, filename, content_type } = response.report_file;
    const binary = atob(data);
    const bytes = new Uint8Array(binary.length);
    for (let i = 0; i < binary.length; i++) {
      bytes[i] = binary.charCodeAt(i);
    }
    const blob = new Blob([bytes], { type: content_type });
    const url = URL.createObjectURL(blob);
    const anchor = document.createElement('a');
    anchor.href = url;
    anchor.download = filename;
    anchor.click();
    URL.revokeObjectURL(url);
  }

