  async createSchedule(
    conversationId: string,
    reportConfig: ReportGenerationRequest,
    schedule: ScheduleConfig,
    recipients: string[],
  ): Promise<void> {
    this._error.set(null);
    try {
      await firstValueFrom(
        this.http.post<void>(`${this.chatApiBaseUrl()}/schedule-report`, {
          conversation_id: conversationId,
          report_config: reportConfig,
          schedule,
          recipients,
          auth_token: this.authTokenManagerService.getAccessToken() ?? '',
          base_url: this.apiUrlService.getCurrentApiUrl(),
        }),
      );
    } catch (err) {
      this._error.set(
        err instanceof Error ? err.message : 'Failed to create schedule',
      );
    }
  }

  async listSchedules(): Promise<ScheduleItem[]> {
    try {
      const response = await firstValueFrom(
        this.http.get<{ schedules: ScheduleItem[]; count: number }>(
          `${this.chatApiBaseUrl()}/scheduled-reports`,
          {
            headers: {
              'x-access-token':
                this.authTokenManagerService.getAccessToken() ?? '',
              'x-base-url': this.apiUrlService.getCurrentApiUrl(),
            },
          },
        ),
      );
      return response.schedules ?? [];
    } catch (err) {
      this._error.set(
        err instanceof Error ? err.message : 'Failed to load schedules',
      );
      return [];
    }
  }

  async deleteSchedule(scheduleId: string): Promise<void> {
    try {
      await firstValueFrom(
        this.http.delete<void>(
          `${this.chatApiBaseUrl()}/scheduled-reports/${scheduleId}`,
          {
            headers: {
              'x-access-token':
                this.authTokenManagerService.getAccessToken() ?? '',
              'x-base-url': this.apiUrlService.getCurrentApiUrl(),
            },
          },
        ),
      );
    } catch (err) {
      this._error.set(
        err instanceof Error ? err.message : 'Failed to delete schedule',
      );
    }
  }

  /**
   * Resolves selected recipients to a deduped list of email addresses (max 20).
   * Users contribute their own email; roles are expanded to the email addresses
   * of their member users. The reporting backend only accepts email strings.
   */
  async resolveRecipientEmails(
    ownerId: string,
    recipients: ScheduleRecipient[],
  ): Promise<string[]> {
    const emails: string[] = [];

    for (const recipient of recipients) {
      if (recipient.type === 'user') {
        if (recipient.email != null && recipient.email.length > 0) {
          emails.push(recipient.email);
        }
      } else if (ownerId.length > 0) {
        emails.push(...(await this.resolveRoleEmails(ownerId, recipient.id)));
      }
    }

    const deduped = [
      ...new Set(emails.map((e) => e.trim()).filter((e) => e.length > 0)),
    ];
    return deduped.slice(0, MAX_RECIPIENT_EMAILS);
  }

  /** Fetches the email addresses of all active users that belong to a role. */
  private async resolveRoleEmails(
    ownerId: string,
    roleId: string,
  ): Promise<string[]> {
    try {
      const response = await firstValueFrom(
        this.accountsService.listUsers(
          ownerId,
          0,
          500,
          'name',
          `roles.id=in=(${roleId})`,
        ),
      );
      return (response.items ?? [])
        .map((u) => u.emailAddress ?? '')
        .filter((e) => e.length > 0);
    } catch {
      return [];
    }
  }

