  getDefaultColumns(reportType: ReportType): string[] {
    const config = this.getReportTypes().find(
      (r) => r.report_type === reportType,
    );
    return config?.default_columns ?? [];
  }

  /**
   * Column keys surfaced in the "Add Additional Columns" picker's Standard group,
   * in display order. These are user-togglable in the picker (some default-on),
   * so both the picker and the request builder must agree on the set — the
   * request builder lets these keys be controlled by the picker selection while
   * every other default column stays always-on.
   */
  private readonly ADDITIONAL_STANDARD_KEYS: Partial<
    Record<ReportType, string[]>
  > = {
    trip_history_daily_summary: [
      'trip_count',
      'total_duration',
      'total_stopped_time',
      'total_parked_time',
      'avg_speed',
      'initial_odometer',
      'final_odometer',
    ],
  };

  /** The Standard-group columns for the "Add Additional Columns" picker. */
  getAdditionalStandardColumns(reportType: ReportType): ColumnDefinition[] {
    const keys = this.ADDITIONAL_STANDARD_KEYS[reportType] ?? [];
    const byKey = new Map(
      this.getAvailableColumns(reportType).map((c) => [c.key, c]),
    );
    return keys
      .map((k) => byKey.get(k))
      .filter((c): c is ColumnDefinition => c !== undefined);
  }
