import { Component, input, output, signal, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ButtonModule } from 'primeng/button';

export interface DataTypeOption {
  id: string;
  label: string;
  description: string;
  icon: string;
}

const DEFAULT_DATA_TYPES: DataTypeOption[] = [
  {
    id: 'trips',
    label: 'Trips',
    description: 'Journey data with start/end locations and times',
    icon: 'pi-map-marker',
  },
  {
    id: 'events',
    label: 'Events',
    description: 'Driver behavior events like harsh braking, speeding',
    icon: 'pi-exclamation-triangle',
  },
  {
    id: 'telemetry',
    label: 'Telemetry',
    description: 'Real-time sensor data: speed, fuel, engine status',
    icon: 'pi-chart-line',
  },
  {
    id: 'alerts',
    label: 'Alerts',
    description: 'System alerts and notifications',
    icon: 'pi-bell',
  },
];

@Component({
  selector: 'app-inline-data-type-selector',
  imports: [CommonModule, ButtonModule],
  templateUrl: './inline-data-type-selector.component.html',
  styleUrl: './inline-data-type-selector.component.scss',
})
export class InlineDataTypeSelectorComponent {
  // Inputs
  dataTypes = input<DataTypeOption[]>(DEFAULT_DATA_TYPES);
  initialSelection = input<string[]>([]);

  // Outputs
  dataTypesSelected = output<string[]>();

  // Local state
  selectedIds = signal<Set<string>>(new Set());

  // Computed
  readonly selectedCount = computed(() => this.selectedIds().size);

  readonly canConfirm = computed(() => this.selectedCount() > 0);

  readonly allSelected = computed(() => {
    const types = this.dataTypes();
    const selected = this.selectedIds();
    return types.length > 0 && types.every((t) => selected.has(t.id));
  });

  isSelected(id: string): boolean {
    return this.selectedIds().has(id);
  }

  toggleDataType(type: DataTypeOption): void {
    const current = new Set(this.selectedIds());

    if (current.has(type.id)) {
      current.delete(type.id);
    } else {
      current.add(type.id);
    }

    this.selectedIds.set(current);
  }

  selectAll(): void {
    this.selectedIds.set(new Set(this.dataTypes().map((t) => t.id)));
  }

  clearAll(): void {
    this.selectedIds.set(new Set());
  }

  onConfirm(): void {
    const selections = Array.from(this.selectedIds());
    if (selections.length > 0) {
      this.dataTypesSelected.emit(selections);
    }
  }
}
