import {
  DestroyRef,
  Injectable,
  computed,
  effect,
  inject,
  signal,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';

import { AssetsService } from '../../../../../api';
import { AssetGroupingService } from '../../../../../shared/services/asset-grouping.service';
import { ClientDataService } from '../../../../clients/services/client-data.service';
import { ConversationHistoryService } from '../../../../../core/services/conversation-history.service';
import { ReportGenerationService } from '../../../../../core/services/report-generation.service';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';

import { AnalyticalReviewService } from './analytical-review.service';
import { AnalyticalReportLoadingService } from './analytical-report-loading.service';
import { AnalyticalReportReportingService } from './analytical-report-reporting.service';

import { AnalyticalReportAssetsStore } from '../store/assets.store';
import { AnalyticalReportDateStore } from '../store/date.store';
import { AnalyticalReportQueryStore } from '../store/query.store';
import { AnalyticalReportUiStore } from '../store/ui.store';
import { AnalyticalReportSessionStore } from '../store/session.store';
import { ChatSessionStore } from '../store/chat-session.store';

import { ChatSessionService } from '../chat/services/chat-session.service';
import { ReportEditingService } from '../dashboard/services/report-editing.service';
import { DropdownOption } from '../models/analytical-report.types';
import { ClientInfo } from '../chat/models/chat.interface';
import { AnalyticsSnapshotMeta } from '../../../../../core/interfaces/conversation.interface';
import { ReportConfigDrawerResult } from '../chat/components/report-config-drawer/report-config-drawer.component';
import { ReportConfigSelection } from '../chat/components/inline-report-config/inline-report-config.component';
import { SavedParams } from '../chat/components/chat-summary-header/chat-summary-header.component';

@Injectable()
export class AnalyticalReportFacadeService {
  // ── Stores (private — sealed boundary) ────────────────────────────────────
  private readonly assetsStore = inject(AnalyticalReportAssetsStore);
  private readonly dateStore = inject(AnalyticalReportDateStore);
  private readonly queryStore = inject(AnalyticalReportQueryStore);
  private readonly uiStore = inject(AnalyticalReportUiStore);
  private readonly sessionStore = inject(AnalyticalReportSessionStore);
  private readonly chatSessionStore = inject(ChatSessionStore);

  // ── Services (private) ────────────────────────────────────────────────────
  private readonly chatSessionService = inject(ChatSessionService);
  private readonly reportEditing = inject(ReportEditingService);
  private readonly analyticalReviewService = inject(AnalyticalReviewService);
  private readonly assetsService = inject(AssetsService);
  private readonly assetGroupingService = inject(AssetGroupingService);
  private readonly clientDataService = inject(ClientDataService);
  private readonly conversationHistoryService = inject(
    ConversationHistoryService,
  );
  private readonly reportGenerationService = inject(ReportGenerationService);
  private readonly destroyRef = inject(DestroyRef);
  private readonly analyticalReportLoadingService = inject(
    AnalyticalReportLoadingService,
  );
  private readonly analyticalReportReportingService = inject(
    AnalyticalReportReportingService,
  );

  // ── Client signal ─────────────────────────────────────────────────────────
  readonly selectedClientSignal =
    this.clientDataService.getSelectedClientSignal();

  // ── Delegation: loading ───────────────────────────────────────────────────
  readonly loadingMessage = this.analyticalReportLoadingService.loadingMessage;

  // ── Delegation: conversation history ─────────────────────────────────────
  readonly groupedConversations =
    this.conversationHistoryService.groupedConversations;
  readonly conversationsLoading = this.conversationHistoryService.isLoading;
  readonly selectedConversationId =
    this.conversationHistoryService.selectedConversationId;

  // ── Delegation: UI store ──────────────────────────────────────────────────
  readonly viewerMode = this.uiStore.viewerMode;
  readonly viewerCollapsed = this.uiStore.viewerCollapsed;
  readonly sidebarCollapsed = this.uiStore.sidebarCollapsed;
  readonly isGeneratingFile = this.uiStore.isGeneratingFile;
  readonly isTestingApi = this.uiStore.isTestingApi;
  readonly pendingReportConfig = this.uiStore.pendingReportConfig;
  readonly configDrawerInitialDeliveryMode =
    this.uiStore.configDrawerInitialDeliveryMode;
  readonly configDrawerVisibleWritable =
    this.uiStore.configDrawerVisibleWritable;
  readonly errorMessage = this.uiStore.errorMessage;
  readonly successMessage = this.uiStore.successMessage;
  readonly generatedReport = this.uiStore.generatedReport;
  readonly pendingMessage = this.uiStore.pendingMessage;
  readonly pendingSnapshot = this.uiStore.pendingSnapshot;
  readonly generatingReportsCount = this.uiStore.generatingReportsCount;
  readonly dashboardResponse = this.uiStore.dashboardResponse;
  readonly reportSummary = this.uiStore.reportSummary;
  readonly pendingScrollTarget = this.uiStore.pendingScrollTarget;

  // ── Delegation: query store ───────────────────────────────────────────────
  readonly lastReportQuery = this.queryStore.lastReportQuery;

  // ── Delegation: assets store ──────────────────────────────────────────────
  readonly chatSelectedVehicles = this.assetsStore.chatSelectedVehicles;

  // ── Delegation: date store ────────────────────────────────────────────────
  readonly chatDateRange = this.dateStore.chatDateRange;

  // ── Delegation: session store ─────────────────────────────────────────────
  readonly selectedConversationForReports =
    this.sessionStore.selectedConversationForReports;

  // ── Delegation: chat session ──────────────────────────────────────────────
  readonly session = this.chatSessionStore.session;

  // ── Computed signals ──────────────────────────────────────────────────────
  readonly chatClientInfo = computed((): ClientInfo | null => {
    const client = this.selectedClientSignal();
    if (isNullOrUndefined(client?.id) || isNullOrUndefined(client?.name))
      return null;
    return { id: client.id, name: client.name };
  });

  readonly selectedConversationHasReports = computed(() => {
    const id = this.selectedConversationId();
    if (isNullOrUndefined(id)) return false;
    return (
      this.conversationHistoryService.conversations().find((c) => c.id === id)
        ?.has_report ?? false
    );
  });

  /** Most recent analytics snapshot in the conversation (the last generated report). */
  readonly latestAnalyticsSnapshot = computed<AnalyticsSnapshotMeta | null>(
    () => {
      const messages = this.chatSessionStore.messages();
      for (let i = messages.length - 1; i >= 0; i--) {
        const snap = messages[i].metadata?.analyticsSnapshot;
        if (isDefined(snap)) return snap;
      }
      return null;
    },
  );

  readonly selectedConversationHasAnalyticalReport = computed(
    () => this.latestAnalyticsSnapshot() !== null,
  );

  /** True while an analytical report is being loaded for display. */
  private readonly _isOpeningReport = signal(false);
  readonly isOpeningReport = this._isOpeningReport.asReadonly();

  readonly selectedConversationTitle = computed<string | null>(() => {
    const id = this.selectedConversationId();
    if (isNullOrUndefined(id)) return null;
    return (
      this.conversationHistoryService.conversations().find((c) => c.id === id)
        ?.title ?? null
    );
  });

  readonly isReadyForTesting = computed(() => {
    return !!(
      isDefined(this.selectedClientSignal()?.id) &&
      this.assetsStore.selectedAssetIds().length > 0 &&
      isDefined(this.dateStore.startDate()) &&
      isDefined(this.dateStore.endDate())
    );
  });

  constructor() {
    let previousClientId: string | null = null;
    effect(() => {
      const selectedClient = this.selectedClientSignal();

      if (isDefined(selectedClient?.id)) {
        if (
          previousClientId !== null &&
          previousClientId !== selectedClient.id
        ) {
          this.resetAll();
        }
        previousClientId = selectedClient.id;
        this.loadInitialAssets(selectedClient.id);
        this.conversationHistoryService.refreshList();
        this.uiStore.setErrorMessage(null);
      } else {
        previousClientId = null;
        this.assetsStore.setAssets([]);
        this.assetsStore.setFilteredAssets([]);
      }
    });
  }

  // ── Initialization ────────────────────────────────────────────────────────

  loadInitialAssets(clientId: string): void {
    this.assetsStore.setLoadingAssets(true);
    this.uiStore.setErrorMessage(null);

    this.assetsService
      .listAssets(clientId, 0, 1000, undefined, 'state=active')
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response) => {
          const assetOptions: DropdownOption[] =
            response.items?.map((asset) => ({
              label: asset.name || `Asset ${asset.id}`,
              value: asset.id,
              assetData: asset,
            })) ?? [];

          this.assetsStore.setAssets(assetOptions);
          this.assetsStore.setFilteredAssets(assetOptions);
          this.assetsStore.setLoadingAssets(false);

          void this.loadGroupingData(clientId, assetOptions);
        },
        error: () => {
          this.uiStore.setErrorMessage(
            'Failed to load assets. Please try again.',
          );
          this.assetsStore.setLoadingAssets(false);
        },
      });
  }

  private async loadGroupingData(
    clientId: string,
    assetOptions: DropdownOption[],
  ): Promise<void> {
    const [costCentreItems, assetGroupItems] = await Promise.all([
      this.assetGroupingService.getCostCentres(clientId),
      this.assetGroupingService.getAssetGroups(clientId),
    ]);

    const costCenters = costCentreItems
      .map((cc) => ({
        id: cc.id,
        name: cc.name,
        type: 'cost_center' as const,
        assetIds: assetOptions
          .filter((a) => a.assetData?.costCentre?.id === cc.id)
          .map((a) => a.value),
      }))
      .filter((cc) => cc.assetIds.length > 0);

    const assetGroups = assetGroupItems
      .map((ag) => ({
        id: ag.id,
        name: ag.name,
        type: 'asset_group' as const,
        assetIds: assetOptions
          .filter(
            (a) => a.assetData?.groups?.some((g) => g.id === ag.id) ?? false,
          )
          .map((a) => a.value),
      }))
      .filter((ag) => ag.assetIds.length > 0);

    this.assetsStore.setAvailableCostCenters(costCenters);
    this.assetsStore.setAvailableAssetGroups(assetGroups);
  }

  // ── State management ──────────────────────────────────────────────────────

  resetAll(): void {
    this.analyticalReviewService.clearResponse();
    this.uiStore.reset();
    this.queryStore.reset();
    this.sessionStore.reset();
    this.assetsStore.reset();
    this.dateStore.reset();
    this.chatSessionService.reset();
    // Drop the previous report's edited blocks too. Otherwise a new chat
    // inherits them and sends them as `current_report`, leaking one session's
    // report into another and re-triggering report-edit mode. See CHV-2720.
    this.reportEditing.clear();
  }

  async selectConversation(id: string): Promise<void> {
    this.conversationHistoryService.selectConversation(id);
    this.uiStore.setViewerMode(null);
    this.uiStore.setGeneratedReport(null);
    this.sessionStore.setViewingExistingSession(true);

    const cachedSummary = this.conversationHistoryService
      .conversations()
      .find((c) => c.id === id);
    if (isDefined(cachedSummary?.query_confidence)) {
      this.queryStore.setCurrentConfidence(cachedSummary.query_confidence);
    }
    if (isDefined(cachedSummary?.current_query)) {
      this.queryStore.setCurrentQuery(cachedSummary.current_query);
    }

    try {
      const detail = await this.chatSessionService.loadExistingSession(id);

      if (!isDefined(detail)) return;

      if (
        isDefined(detail.context?.dateRange?.startDate) &&
        isDefined(detail.context?.dateRange?.endDate)
      ) {
        const start = new Date(detail.context.dateRange.startDate);
        const end = new Date(detail.context.dateRange.endDate);
        this.dateStore.setDateRange(start, end);
      }

      if (isDefined(detail.context?.vehicleIds?.length)) {
        this.assetsStore.setSelectedAssetIds(detail.context.vehicleIds);
        this.assetsStore.setContextVehicleNames(
          detail.context.vehicleNames ?? {},
        );
      }

      if (isDefined(detail.context?.dataTypes?.length)) {
        const dataTypes = detail.context.dataTypes as string[];
        this.queryStore.setSelectedDataTypesList(dataTypes);
        this.queryStore.updateDataTypeOptions((options) =>
          options.map((opt) => ({
            ...opt,
            selected: dataTypes.includes(opt.value),
          })),
        );
      }
    } catch {
      this.uiStore.setErrorMessage('Failed to load conversation');
    }
  }

  // ── UI write delegation ───────────────────────────────────────────────────

  setPendingMessage(msg: string | null): void {
    this.uiStore.setPendingMessage(msg);
  }

  setPendingScrollTarget(id: string | null): void {
    this.uiStore.setPendingScrollTarget(id);
  }

  setGeneratingReportsCount(n: number): void {
    this.uiStore.setGeneratingReportsCount(n);
  }

  openConfigDrawer(mode: 'now' | 'schedule'): void {
    this.uiStore.setConfigDrawerVisible(true, mode);
  }

  setViewerCollapsed(collapsed: boolean): void {
    this.uiStore.setViewerCollapsed(collapsed);
  }

  setSidebarCollapsed(collapsed: boolean): void {
    this.uiStore.setSidebarCollapsed(collapsed);
  }

  startNewConversation(): void {
    this.conversationHistoryService.selectConversation('');
    this.uiStore.setViewerMode(null);
    this.resetAll();
  }

  // ── Event handlers ────────────────────────────────────────────────────────

  async handleChatGenerateReport(query: string): Promise<void> {
    await this.generateReportFile(query);
  }

  /** Open the most recent analytical report (with the user's edits applied). */
  async showLatestAnalyticalReport(): Promise<void> {
    const snap = this.latestAnalyticsSnapshot();
    if (isDefined(snap)) {
      await this.handleViewAnalyticsSnapshot(snap);
    }
  }

  async handleViewAnalyticsSnapshot(
    snap: AnalyticsSnapshotMeta,
  ): Promise<void> {
    const conversationId = this.selectedConversationId();
    if (isNullOrUndefined(conversationId)) {
      this.uiStore.setPendingSnapshot(null);
      return;
    }
    this._isOpeningReport.set(true);
    this.uiStore.setPendingSnapshot(snap);
    try {
      const [analytics, persisted] = await Promise.all([
        this.conversationHistoryService.loadFullSnapshot(
          conversationId,
          snap.snapshot_id,
        ),
        this.conversationHistoryService.getEditedReport(conversationId),
      ]);
      if (isDefined(analytics)) {
        // Stash the persisted edit so the dashboard hydrates it over the
        // baseline snapshot when this response renders.
        this.reportEditing.setPendingPersisted(persisted);
        this.analyticalReviewService.setApiResponse({
          success: true,
          data: analytics,
        });
        this.analyticalReviewService.setLastReportQuery(snap.query);
        this.uiStore.setViewerMode('dashboard');
      }
    } finally {
      // Reset the snapshot signal so QueryChatComponent can reset its own loading state
      this.uiStore.setPendingSnapshot(null);
      this._isOpeningReport.set(false);
    }
  }

  handleFooterMessageSent(message: string): void {
    this.uiStore.setPendingMessage(message);
  }

  handleHeaderParamsSaved(params: SavedParams): void {
    const parts: string[] = [];

    if (params.dateRange != null) {
      const oldStart = params.previousDateRange?.start;
      const oldEnd = params.previousDateRange?.end;
      if (isDefined(oldStart))
        parts.push(`Start date: From ${oldStart} to ${params.dateRange.start}`);
      if (isDefined(oldEnd))
        parts.push(`End date: From ${oldEnd} to ${params.dateRange.end}`);
    }

    if (params.vehicleIds) {
      const oldIds = params.previousVehicleIds ?? [];
      parts.push(
        `Vehicles: From [${oldIds.join(', ')}] to [${params.vehicleIds.join(', ')}]`,
      );
    }

    if (params.dataTypeIds) {
      const oldTypes = params.previousDataTypeIds ?? [];
      parts.push(
        `Data types: From [${oldTypes.join(', ')}] to [${params.dataTypeIds.join(', ')}]`,
      );
    }

    if (parts.length === 0) return;
    if (!this.chatSessionService.isSessionActive()) return;

    const message = `I've updated the report parameters: ${parts.join('\n ')}. Please take these into account.`;
    this.uiStore.setPendingMessage(message);
  }

  async handleDrawerGenerateNow(
    result: ReportConfigDrawerResult,
  ): Promise<void> {
    this.uiStore.setErrorMessage(null);
    const { report, error } =
      await this.analyticalReportReportingService.generateFromDrawer(result);

    if (report) {
      this.uiStore.setGeneratedReport(report);
      this.uiStore.setSuccessMessage(
        'Report generated! Click "Download Report" to save it.',
      );
      setTimeout(() => this.uiStore.setSuccessMessage(null), 5000);
    } else {
      this.uiStore.setErrorMessage(error);
    }
  }

  async handleFooterGenerateAnalyticalReview(): Promise<void> {
    const query = this.queryStore.currentQuery();
    if (!query) {
      this.uiStore.setErrorMessage('Please build a query first by chatting.');
      return;
    }

    this.uiStore.setErrorMessage(null);
    this.uiStore.setSuccessMessage(null);
    const { errorMessage, successMessage } =
      await this.analyticalReviewService.runAnalyticalReview(query);
    this.uiStore.setErrorMessage(errorMessage);
    this.uiStore.setSuccessMessage(successMessage);
  }

  handleShowReports(): void {
    const id = this.selectedConversationId();
    if (isNullOrUndefined(id)) return;
    const conversation =
      this.conversationHistoryService
        .conversations()
        .find((c) => c.id === id) ?? null;
    this.sessionStore.setSelectedConversationForReports(conversation);
    this.uiStore.setViewerMode('reports');
  }

  handleToggleVisibility(): void {
    const id = this.selectedConversationId();
    if (isNullOrUndefined(id)) return;
    const conversation = this.conversationHistoryService
      .conversations()
      .find((c) => c.id === id);
    if (!conversation || isNullOrUndefined(id)) return;
    const newVisibility =
      conversation.visibility === 'private' ? 'shared' : 'private';
    void this.conversationHistoryService.updateConversation(id, {
      visibility: newVisibility,
    });
  }

  handleReportConfigSelected(config: ReportConfigSelection): void {
    this.uiStore.setPendingReportConfig(config);
  }

  handleRecalculate(): void {
    this.analyticalReviewService.clearResponse();
    this.uiStore.setErrorMessage(null);
    this.uiStore.setSuccessMessage(null);
    const query = this.queryStore.currentQuery();
    if (query) {
      void this.analyticalReviewService
        .runAnalyticalReview(query)
        .then(({ errorMessage, successMessage }) => {
          this.uiStore.setErrorMessage(errorMessage);
          this.uiStore.setSuccessMessage(successMessage);
        });
    }
  }

  handleDownloadReport(): void {
    const report = this.uiStore.generatedReport();
    if (report) {
      this.reportGenerationService.downloadReportFile(report);
    }
  }

  handleClearResponse(): void {
    this.analyticalReviewService.clearResponse();
    this.uiStore.setErrorMessage(null);
    this.uiStore.setSuccessMessage(null);
  }

  private async generateReportFile(queryOverride?: string): Promise<void> {
    if (this.assetsStore.selectedAssetIds().length === 0) {
      this.uiStore.setErrorMessage('Please select at least one vehicle.');
      return;
    }

    if (isDefined(queryOverride)) {
      this.queryStore.setCurrentQuery(queryOverride);
    }

    this.uiStore.setErrorMessage(null);
    const { report, error } =
      await this.analyticalReportReportingService.generateReportFile();

    if (report) {
      this.uiStore.setGeneratedReport(report);
      this.uiStore.setSuccessMessage(
        'Report generated! Click "Download Report" to save it.',
      );
      setTimeout(() => this.uiStore.setSuccessMessage(null), 5000);
    } else {
      this.uiStore.setErrorMessage(error);
    }
  }

  stop(): void {
    this.analyticalReportLoadingService.stop();
  }
}
