import { Injectable, computed, signal } from '@angular/core';
import { isNullOrUndefined } from '../../../../../shared/utils';

@Injectable()
export class AnalyticalReportDateStore {
  private readonly _startDate = signal<Date | null>(null);
  private readonly _endDate = signal<Date | null>(null);
  private readonly _activeDatePreset = signal<string | null>(null);

  readonly startDate = this._startDate.asReadonly();
  readonly endDate = this._endDate.asReadonly();
  readonly activeDatePreset = this._activeDatePreset.asReadonly();

  readonly chatDateRange = computed((): { start: Date; end: Date } | null => {
    const start = this._startDate();
    const end = this._endDate();
    if (start && end) {
      return { start, end };
    }
    return null;
  });

  readonly isDateRangeGreaterThan2Days = computed((): boolean => {
    const startDate = this._startDate();
    const endDate = this._endDate();

    if (isNullOrUndefined(startDate) || isNullOrUndefined(endDate)) {
      return false;
    }

    const diffInMs = endDate.getTime() - startDate.getTime();
    const diffInDays = diffInMs / (1000 * 60 * 60 * 24);
    return diffInDays > 2;
  });

  readonly formatDateRange = computed((): string => {
    const startDate = this._startDate();
    const endDate = this._endDate();

    if (isNullOrUndefined(startDate) || isNullOrUndefined(endDate)) {
      return 'Date range not selected';
    }

    try {
      const formatDate = (date: Date) => {
        if (isNullOrUndefined(date)) return 'Invalid Date';
        return new Date(date).toLocaleDateString('en-US', {
          month: 'short',
          day: 'numeric',
          year: 'numeric',
          hour: 'numeric',
          minute: '2-digit',
          hour12: true,
        });
      };

      return `${formatDate(startDate)} - ${formatDate(endDate)}`;
    } catch {
      return 'Invalid date range';
    }
  });

  readonly canAnalyzePerDay = computed(() =>
    this.isDateRangeGreaterThan2Days(),
  );

  setDateRange(start: Date | null, end: Date | null): void {
    this._startDate.set(start);
    this._endDate.set(end);
  }

  setActiveDatePreset(preset: string | null): void {
    this._activeDatePreset.set(preset);
  }

  reset(): void {
    this._startDate.set(null);
    this._endDate.set(null);
    this._activeDatePreset.set(null);
  }
}
