import { Component, effect, output, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';

import { SelectModule } from 'primeng/select';
import { TranslatePipe } from '@ngx-translate/core';

import {
  UtilisationFilterSelection,
  UtilizationMode,
} from '../../../../../../../core/interfaces/report-generation.interface';

interface ModeOption {
  label: string;
  value: UtilizationMode;
}

/**
 * Settings for the Daily Utilisation report. A period-basis mode (12h / 24h /
 * the asset's configured working-hours schedule) plus an optional daily distance
 * target (km). A blank target emits `null`, which the backend treats as "no
 * target" — it then omits the Target and Distance Utilization % columns.
 */
@Component({
  selector: 'app-inline-utilisation-filter',
  imports: [CommonModule, FormsModule, SelectModule, TranslatePipe],
  templateUrl: './inline-utilisation-filter.component.html',
})
export class InlineUtilisationFilterComponent {
  filterChanged = output<UtilisationFilterSelection>();

  readonly mode = signal<UtilizationMode>('24_hours');
  readonly targetKm = signal<number | null>(null);

  readonly modeOptions: ModeOption[] = [
    { label: '12 Hours', value: '12_hours' },
    { label: '24 Hours', value: '24_hours' },
    { label: 'Working Hours', value: 'working_hours' },
  ];

  constructor() {
    effect(
      () => {
        this.filterChanged.emit({
          utilization_mode: this.mode(),
          daily_target_distance_km: this.targetKm(),
        });
      },
      { allowSignalWrites: true },
    );
  }

  setTarget(value: string): void {
    this.targetKm.set(value === '' ? null : Number(value));
  }
}
