/**
 * Report Generation Interfaces
 * CHV-2285
 */

// ============================================================================
// Union Types
// ============================================================================

export type ReportType =
  | 'trip_history_listing'
  | 'trip_history_daily_summary'
  | 'trip_history_detailed'
  | 'speeding'
  | 'geofence'
  | 'daily_utilisation'
  | 'idling'
  | 'events'
  | 'alerts'
  | 'stopping';

export type ColumnCategory =
  | 'standard'
  | 'custom_fields'
  | 'average'
  | 'initial'
  | 'final'
  | 'min'
  | 'max'
  | 'total'
  | 'rate'
  | 'event_count';

// ============================================================================
// Report Generation Request / Response
// ============================================================================

export interface ReportGenerationRequest {
  conversation_id: string;
  company_id: string;
  report_type: ReportType;
  vehicle_ids: string[];
  vehicle_names: Record<string, string>;
  start_date: string;
  end_date: string;
  columns: string[];
  column_categories: ColumnCategory[];
  output_format: 'csv' | 'xlsx';
  include_ai_analysis: boolean;
  /** IANA timezone (e.g. Africa/Johannesburg) used to render report datetimes. */
  timezone?: string;
  /**
   * Geofence-report filters. Only consulted when `report_type === 'geofence'`.
   * Each list is treated as a whitelist; omitting a field (or sending []) means
   * "no restriction on that dimension" — i.e. Select All.
   */
  geofence_ids?: string[];
  geofence_type_ids?: string[];
  geofence_group_ids?: string[];
  /**
   * Events-report filter. Only consulted when `report_type === 'events'`.
   * List of event-class keys (e.g. 'ZONEEVENT', 'TRIGGEREDEVENT') to include;
   * omitting/empty means "Select all event types".
   */
  event_categories?: string[];
  /**
   * Alerts-report filter. Only consulted when `report_type === 'alerts'`.
   * List of alert-class keys (e.g. 'TRIGGEREDEVENT') to include;
   * omitting/empty means "Select all alerts".
   */
  alert_categories?: string[];
  /**
   * Incident thresholds. `min_distance_km` is only consulted when
   * `report_type === 'speeding'`; `min_duration_minutes` serves the
   * 'speeding', 'idling' and 'stopping' reports. Each is a strictly-greater-than
   * filter on an incident; omitting (or null) means "no restriction" — show all.
   */
  min_distance_km?: number;
  min_duration_minutes?: number;
  /**
   * Stopping-report filter. Only consulted when `report_type === 'stopping'`.
   * Whitelist of stop types to include; omitting/empty means "all types".
   */
  stop_types?: StopType[];
  /**
   * Daily Utilisation report settings. Only consulted when
   * `report_type === 'daily_utilisation'`. `utilization_mode` selects the period
   * basis (12h / 24h / the asset's configured working-hours schedule);
   * `daily_target_distance_km` is optional — when omitted the backend drops the
   * Target and Distance Utilization % columns.
   */
  utilization_mode?: UtilizationMode;
  daily_target_distance_km?: number;
  /**
   * Asset custom-field columns to append, sourced from Client's `customFields`
   * definitions. `key` is the custom-field id (matches the asset's `fields[key]`);
   * `title` is the column header. Only consulted for `trip_history_daily_summary`.
   */
  custom_columns?: CustomFieldColumn[];
  /**
   * IoType columns whose value is taken from the first trip of each day.
   * `key` = IoType id, `title` = column header. Only consulted for
   * `trip_history_daily_summary`. Backend value-resolution is a follow-up.
   */
  initial_columns?: CustomFieldColumn[];
  /**
   * IoType columns whose value is taken from the last trip of each day.
   * `key` = IoType id, `title` = column header. Only consulted for
   * `trip_history_daily_summary`. Backend value-resolution is a follow-up.
   */
  final_columns?: CustomFieldColumn[];
}

/**
 * A single asset custom-field column selected in the "Add Additional Column" picker.
 * `key` = the Client-doc `customFields[...].id` (also the asset's `fields` key);
 * `title` = the field's display title used as the column header.
 * `unit` = optional IoType unit (e.g. "Km", "%") appended to Initial/Final IO
 * values by the backend ("122 355 Km"). Absent for custom fields.
 */
export interface CustomFieldColumn {
  key: string;
  title: string;
  unit?: string | null;
}

/**
 * Selection emitted by the event-type filter picker. An empty `event_categories`
 * array means "All event types" (the backend treats it as a wildcard).
 */
export interface EventTypeFilterSelection {
  event_categories: string[];
}

/**
 * Selection emitted by the alert-type filter picker. An empty `alert_categories`
 * array means "All alerts" (the backend treats it as a wildcard).
 */
export interface AlertTypeFilterSelection {
  alert_categories: string[];
}

/**
 * Selection emitted by the geofence filter picker. The picker translates each
 * mode into one of these arrays before they're appended to the report request.
 * An "All" choice on a dimension produces an empty array, which the backend
 * treats as a wildcard.
 */
export interface GeofenceFilterSelection {
  geofence_ids: string[];
  geofence_type_ids: string[];
  geofence_group_ids: string[];
}

/** Default "no filter chosen" value — all dimensions wildcarded. */
export const EMPTY_GEOFENCE_FILTER: GeofenceFilterSelection = {
  geofence_ids: [],
  geofence_type_ids: [],
  geofence_group_ids: [],
};

/**
 * Selection emitted by the speeding filter picker. Each value is a
 * strictly-greater-than threshold; `null` means "no restriction" (show all).
 */
export interface SpeedingFilterSelection {
  min_distance_km: number | null;
  min_duration_minutes: number | null;
}

/** Default "no filter chosen" value — both thresholds disabled. */
export const EMPTY_SPEEDING_FILTER: SpeedingFilterSelection = {
  min_distance_km: null,
  min_duration_minutes: null,
};

/**
 * Selection emitted by the idling filter picker. A strictly-greater-than
 * duration threshold; `null` means "no restriction" (show all).
 */
export interface IdlingFilterSelection {
  min_duration_minutes: number | null;
}

/** Default "no filter chosen" value — threshold disabled. */
export const EMPTY_IDLING_FILTER: IdlingFilterSelection = {
  min_duration_minutes: null,
};

/**
 * Stop type for the Stopping report. Follows from the device's `active_input`
 * config: 'speed' (emulate — stop when speed hits 0) or 'ignition_off' (an IO
 * field — stop when the ignition signal drops).
 */
export type StopType = 'ignition_off' | 'speed';

/**
 * Selection emitted by the Stopping filter picker. `stop_types` is a whitelist
 * of stop types to include — an empty array means "all types". The optional
 * `min_duration_minutes` is a strictly-greater-than threshold; `null` = show all.
 */
export interface StoppingFilterSelection {
  stop_types: StopType[];
  min_duration_minutes: number | null;
}

/**
 * Default value — Ignition Off (the picker is single-choice; a vehicle is
 * configured as one type or the other), no duration threshold.
 */
export const EMPTY_STOPPING_FILTER: StoppingFilterSelection = {
  stop_types: ['ignition_off'],
  min_duration_minutes: null,
};

/** Period basis for the Daily Utilisation report. */
export type UtilizationMode = '12_hours' | '24_hours' | 'working_hours';

/**
 * Selection emitted by the Daily Utilisation filter picker. `utilization_mode`
 * is always set; `daily_target_distance_km` is `null` when no target is chosen
 * (the backend then omits the Target / Distance Utilization % columns).
 */
export interface UtilisationFilterSelection {
  utilization_mode: UtilizationMode;
  daily_target_distance_km: number | null;
}

/** Default value — 24-hour period basis, no distance target. */
export const EMPTY_UTILISATION_FILTER: UtilisationFilterSelection = {
  utilization_mode: '24_hours',
  daily_target_distance_km: null,
};

export interface ReportMetadata {
  report_type: ReportType;
  vehicles_count: number;
  rows_count: number;
  processing_time_ms: number;
  data_fetch_time_ms: number;
  report_generation_time_ms: number;
  ai_analysis_time_ms: number;
}

export interface ReportGenerationResponse {
  report_file: {
    data: string;
    filename: string;
    content_type: string;
    size_bytes: number;
    blob_url: string | null;
  };
  ai_analysis?: string | null;
  metadata: ReportMetadata;
}

// ============================================================================
// Column / Report Type Configuration
// ============================================================================

export interface ColumnDefinition {
  key: string;
  label: string;
  category: ColumnCategory;
  default: boolean;
}

export interface ReportTypeConfig {
  report_type: ReportType;
  display_name: string;
  description: string;
  default_columns: string[];
  available_categories: ColumnCategory[];
  icon: string;
}

// ============================================================================
// Scheduling
// ============================================================================

export interface ScheduleConfig {
  cron: string;
  timezone: string;
  relative_date_range: {
    unit: 'days' | 'weeks' | 'months';
    value: number;
  };
}

export interface ScheduleItem {
  id: string;
  conversation_id: string;
  report_config: ReportGenerationRequest;
  schedule: ScheduleConfig;
  created_at: string;
  next_run: string;
  is_active: boolean;
}

/**
 * A recipient selected for a scheduled report. Either a single user or a user
 * role (which expands to its member users). Resolved to email addresses before
 * the schedule is sent to the backend.
 */
export interface ScheduleRecipient {
  id: string;
  name: string;
  type: 'user' | 'role';
  /** Populated for `type: 'user'` at selection time. */
  email?: string;
}
