import { Component, computed, effect, output, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';

import { SelectModule } from 'primeng/select';
import { MultiSelectModule } from 'primeng/multiselect';

import { eventCategoryMapping } from '../../../../../../../shared/models/event-types.model';
import { EventTypeFilterSelection } from '../../../../../../../core/interfaces/report-generation.interface';

export type EventTypeFilterMode = 'all' | 'specific';

interface ModeOption {
  label: string;
  value: EventTypeFilterMode;
}

interface CategoryOption {
  label: string;
  value: string;
}

// Event categories the user can pick from, built from the shared event-type
// model. `value` is the eventClass key the backend filters on.
const CATEGORY_OPTIONS: CategoryOption[] = Object.entries(eventCategoryMapping)
  .map(([value, label]) => ({ label, value }))
  .sort((a, b) => a.label.localeCompare(b.label));

/**
 * Event-Type filter for the Events report. Mirrors the geofence filter: an
 * "All event types" / "Specific event types" mode plus a category multi-select.
 * Emits an empty array for "All" (the backend treats it as a wildcard).
 */
@Component({
  selector: 'app-inline-event-type-filter',
  imports: [CommonModule, FormsModule, SelectModule, MultiSelectModule],
  templateUrl: './inline-event-type-filter.component.html',
})
export class InlineEventTypeFilterComponent {
  filterChanged = output<EventTypeFilterSelection>();

  readonly mode = signal<EventTypeFilterMode>('all');
  readonly selectedCategories = signal<string[]>([]);

  readonly categoryOptions = CATEGORY_OPTIONS;
  readonly modeOptions: ModeOption[] = [
    { label: 'All Event Types', value: 'all' },
    { label: 'Specific Event Types', value: 'specific' },
  ];

  readonly showCategoryMulti = computed(() => this.mode() === 'specific');

  constructor() {
    effect(
      () => {
        this.filterChanged.emit(this.buildSelection());
      },
      { allowSignalWrites: true },
    );
  }

  private buildSelection(): EventTypeFilterSelection {
    if (this.mode() === 'specific') {
      return { event_categories: [...this.selectedCategories()] };
    }
    return { event_categories: [] };
  }
}
